AWG_SUBNET_V6:       str  = "fd66:66:66::/64"
AWG_CLIENT_IPv6:     str  = "fd66:66:66::2/128"
AWG_SERVER_IPv6:     str  = "fd66:66:66::1/128"
AWG_MTU:             int  = 1280
AWG_INSTALLED:       bool = False
# Ключи — заполняются в awg_generate_keys()
