        _box_row(f"  {CYAN}noSSEHeader:{NC}     {XHTTP_NO_SSE_HEADER}")
        _box_row(f"  {CYAN}noGRPCHeader:{NC}    {XHTTP_NO_GRPC_HEADER}")
