# =============================================================================
#  ШАГ 10: NGINX ВРЕМЕННЫЙ КОНФИГ
# =============================================================================
def setup_nginx_temp() -> None:
    global STAGE_NGINX_DONE
    info("Настройка Nginx для certbot (временный конфиг)...")

    # Гарантируем что nginx установлен перед настройкой
    _nginx_bin = find_nginx_bin()
    if not _nginx_bin:
        info("  nginx не найден — устанавливаю...")
        _run(["apt-get", "install", "-y", "-q", "nginx"],
             env={"DEBIAN_FRONTEND": "noninteractive"},
             check=False, quiet=True)
        _nginx_bin = find_nginx_bin() or "/usr/sbin/nginx"

    # Чиним битый симлинк если есть
    nginx_lbin = Path("/usr/local/bin/nginx")
    if nginx_lbin.is_symlink() and not nginx_lbin.exists():
        nginx_lbin.unlink()
    if _nginx_bin and not nginx_lbin.exists():
        try:
            nginx_lbin.symlink_to(_nginx_bin)
        except Exception:
            pass
    web_root = Path(f"/var/www/{PARAM_DOMAIN}")
    web_root.mkdir(parents=True, exist_ok=True)
    NGINX_CONF_DIR.mkdir(parents=True, exist_ok=True)
    NGINX_ENABLED_DIR.mkdir(parents=True, exist_ok=True)

    cfg = NGINX_CONF_DIR / PARAM_DOMAIN
    cfg.write_text(textwrap.dedent(f"""\
        server {{
            listen 80;
            listen [::]:80;
            server_name {PARAM_DOMAIN};
            root {web_root};
            index index.html;
            location /.well-known/acme-challenge/ {{ root {web_root}; }}
            location / {{ return 301 https://$host$request_uri; }}
        }}
    """))

    link = NGINX_ENABLED_DIR / PARAM_DOMAIN
    link.unlink(missing_ok=True)
    link.symlink_to(cfg)
    (NGINX_ENABLED_DIR / "default").unlink(missing_ok=True)

    r = _run([_nginx_bin, "-t"], capture=True, check=False)
    if "successful" in r.stderr:
        _run(["systemctl", "reload", "nginx"], check=False, quiet=True)
        STAGE_NGINX_DONE = True
        success("Nginx запущен для certbot")
    else:
        log_to_file("WARN", r.stderr)
        _run(["systemctl", "restart", "nginx"], check=False, quiet=True)
        STAGE_NGINX_DONE = True
        info("Nginx перезапущен (certbot)")

# =============================================================================
#  ШАГ 11: SSL СЕРТИФИКАТ
# =============================================================================
def obtain_ssl_cert() -> None:
    info(f"Получение SSL-сертификата для {PARAM_DOMAIN}...")
    # === Проверка DNS перед получением сертификата ===
    ipv4 = get_server_ip("4")
    if ipv4:
        resolved = _run(["dig", "+short", PARAM_DOMAIN], capture=True, check=False).stdout.strip().split()
        if ipv4 not in resolved and PARAM_DOMAIN not in resolved:
            warn(f"Домен {PARAM_DOMAIN} НЕ резолвится в IP сервера ({ipv4})!")
            warn("Это может привести к ошибке certbot.")
            if input(f"{YELLOW}Продолжить всё равно? [y/N]:{NC} ").strip().lower() != 'y':
                die("DNS не настроен корректно. Исправьте A-запись и запустите заново.")

    cert_path = Path(f"/etc/letsencrypt/live/{PARAM_DOMAIN}/fullchain.pem")
    key_path  = Path(f"/etc/letsencrypt/live/{PARAM_DOMAIN}/privkey.pem")
    web_root  = Path(f"/var/www/{PARAM_DOMAIN}")
    request_new = True

    if cert_path.exists() and key_path.exists():
        try:
            r = _run(["openssl", "x509", "-enddate", "-noout", "-in", str(cert_path)],
                     capture=True, check=False)
            expiry = r.stdout.strip().split("=", 1)[1]
            r2 = _run(["date", "-d", expiry, "+%s"], capture=True, check=False)
            expiry_epoch = int(r2.stdout.strip())
            days_left = (expiry_epoch - int(time.time())) // 86400
        except Exception:
            expiry    = "unknown"
            days_left = 0

        print()
        _box_top("Найден существующий сертификат")
        _box_row()
        _box_row(f"  Истекает: {CYAN}{expiry}{NC}")
        color = GREEN if days_left > 0 else RED
        label = f"{days_left} дней" if days_left > 0 else "ИСТЁК"
        _box_row(f"  Осталось: {color}{label}{NC}")
        _box_row()
        _box_item("U", f"Использовать имеющийся")
        _box_item("R", f"Перевыпустить новый")
        _box_sep()
        _box_bottom()
        while True:
            choice = input("  Выбор [U/R]: ").strip().lower() or "u"
            if choice == "u":
                request_new = False
                success("Используется существующий сертификат")
                break
            elif choice == "r":
                request_new = True
                info("Будет выпущен новый сертификат")
                break
            warn("Введите U или R")

    if request_new:
        info("Выпуск сертификата Let's Encrypt...")
        web_root.mkdir(parents=True, exist_ok=True)
        (web_root / "index.html").write_text("<h1>ACME Verification</h1>")

        le_ok = False
        r = _run([
            "certbot", "certonly", "--webroot",
            "--webroot-path", str(web_root),
            "--non-interactive", "--agree-tos",
            "--email", PARAM_EMAIL,
            "--force-renewal",
            "-d", PARAM_DOMAIN,
        ], capture=True, check=False)
        if r.returncode == 0:
            success("Сертификат Let's Encrypt успешно выпущен")
            le_ok = True

        if not le_ok:
            warn("Не удалось получить сертификат LE — генерируем самоподписанный")
            generate_self_signed_cert(PARAM_DOMAIN)

        if not cert_path.exists():
            warn(f"Сертификат не найден по пути {cert_path} — проверьте DNS и порт 80.")
            warn("Установка продолжается, но HTTPS может не работать.")
            warn(f"Для перевыпуска: certbot certonly --webroot -w {web_root} -d {PARAM_DOMAIN}")
        else:
            success(f"Сертификат на месте: {cert_path}")

    # xHTTP TLS: Xray читает сертификаты напрямую — выставляем права
    if PROTOCOL_MODE == "xhttp" and cert_path.exists():
        fix_letsencrypt_permissions(PARAM_DOMAIN)

def fix_letsencrypt_permissions(domain: str) -> None:
    """Выставляет права на сертификаты так, чтобы пользователь xray мог их читать."""
    import os, grp
    archive_dir     = Path(f"/etc/letsencrypt/archive/{domain}")
    live_domain_dir = Path(f"/etc/letsencrypt/live/{domain}")

    if not archive_dir.exists():
        warn(f"fix_letsencrypt_permissions: {archive_dir} не найден — пропускаем")
        return

    # Гарантируем права на проход по директориям (execute bit).
    # live/<domain> НЕ создаём через mkdir — эта директория принадлежит certbot.
    for d in (Path("/etc/letsencrypt/live"), live_domain_dir,
              Path("/etc/letsencrypt/archive"), archive_dir):
        try:
            if d.exists():
                d.chmod(0o755)
        except Exception as e:
            warn(f"Ошибка установки прав на {d}: {e}")

    # Получаем GID группы xray один раз
    try:
        xray_gid = grp.getgrnam('xray').gr_gid
        has_xray = True
    except KeyError:
        has_xray = False

    # privkey*.pem → 640 root:xray (только xray может читать приватный ключ)
    for f_path in archive_dir.glob("privkey*.pem"):
        try:
            if has_xray:
                os.chown(str(f_path), 0, xray_gid)
            os.chmod(str(f_path), 0o640)
        except Exception as e:
            warn(f"Не удалось исправить права для {f_path}: {e}")

    # fullchain/chain/cert → 644 root:root (публичные — читает nginx, xray и все)
    for pattern in ("fullchain*.pem", "chain*.pem", "cert*.pem"):
        for f_path in archive_dir.glob(pattern):
            try:
                os.chmod(str(f_path), 0o644)
            except Exception as e:
                warn(f"Не удалось исправить права для {f_path}: {e}")

    success(f"Права на сертификаты для {domain} обновлены "
            f"({'root:xray 640/644' if has_xray else '644 для всех'})")

def setup_nginx_final() -> None:
    info("Настройка финального конфига Nginx...")
    web_root = Path(f"/var/www/{PARAM_DOMAIN}")

    create_website()
    NGINX_CONF_DIR.mkdir(parents=True, exist_ok=True)
    NGINX_ENABLED_DIR.mkdir(parents=True, exist_ok=True)

    # === xHTTP TLS: Xray сам принимает :443, Nginx только :80 → 301 ===
    if PROTOCOL_MODE == "xhttp":
        info(f"xHTTP TLS: Nginx настраивается только как HTTP→HTTPS редирект (TLS на Xray :{SERVER_PORT})")
        cfg = NGINX_CONF_DIR / PARAM_DOMAIN
        cfg.write_text(textwrap.dedent(f"""\
            # HTTP → HTTPS redirect (xHTTP TLS — Xray слушает :{SERVER_PORT} напрямую)
            server {{
                listen 80;
                listen [::]:80;
                server_name {PARAM_DOMAIN};
                root {web_root};
                index index.html;
                location /.well-known/acme-challenge/ {{ root {web_root}; }}
                location / {{ return 301 https://$host$request_uri; }}
            }}
        """))
        link = NGINX_ENABLED_DIR / PARAM_DOMAIN
        link.unlink(missing_ok=True)
        link.symlink_to(cfg)
        _xhttp_nginx_bin = find_nginx_bin() or "/usr/sbin/nginx"
        r = _run([_xhttp_nginx_bin, "-t"], capture=True, check=False)
        if r.returncode == 0:
            _run(["systemctl", "reload", "nginx"], check=False, quiet=True)
            success(f"Nginx настроен (только HTTP→HTTPS редирект, Xray владеет :{SERVER_PORT})")
        else:
            _run(["systemctl", "restart", "nginx"], check=False, quiet=True)
            success("Nginx перезапущен (xHTTP TLS режим)")
        return

    # === AWG 2.0 + REALITY: Xray слушает на PORT напрямую, Nginx только HTTP→HTTPS ===
    if AWG_EXIT_ENABLED:
        info(f"AWG 2.0: Xray слушает на :{SERVER_PORT} напрямую, Nginx — только HTTP→HTTPS редирект")
        web_root = Path(f"/var/www/{PARAM_DOMAIN}")
        cfg = NGINX_CONF_DIR / PARAM_DOMAIN
        cfg.write_text(textwrap.dedent(f"""\
            # HTTP → HTTPS redirect (AWG 2.0 — Xray слушает :{SERVER_PORT} напрямую)
            server {{
                listen 80;
                listen [::]:80;
                server_name {PARAM_DOMAIN};
                root {web_root};
                index index.html;
                location /.well-known/acme-challenge/ {{ root {web_root}; }}
                location / {{ return 301 https://$host$request_uri; }}
            }}
        """))
        link = NGINX_ENABLED_DIR / PARAM_DOMAIN
        link.unlink(missing_ok=True)
        link.symlink_to(cfg)
        _nginx_bin = find_nginx_bin() or "/usr/sbin/nginx"
        r = _run([_nginx_bin, "-t"], capture=True, check=False)
        if r.returncode == 0:
            _run(["systemctl", "reload", "nginx"], check=False, quiet=True)
        else:
            _run(["systemctl", "restart", "nginx"], check=False, quiet=True)
        success(f"Nginx настроен (только HTTP→HTTPS редирект для AWG, Xray владеет :{SERVER_PORT})")
        return

    # === REALITY: стандартный конфиг через Unix-сокет ===
    _nginx_bin = find_nginx_bin() or "/usr/sbin/nginx"
    try:
        r = _run([_nginx_bin, "-v"], capture=True, check=False)
        m = re.search(r'(\d+)\.(\d+)\.(\d+)', r.stderr)
        nginx_major = int(m.group(1)) if m else 1
        nginx_minor = int(m.group(2)) if m else 18
        nginx_ver   = f"{nginx_major}.{nginx_minor}.{m.group(3) if m else 0}"
    except Exception:
        nginx_major, nginx_minor, nginx_ver = 1, 18, "1.18.0"

    # === FIX ROOT: xver=1 в классическом REALITY → Xray посылает Proxy Protocol header.
    # Nginx должен иметь proxy_protocol в listen — это согласовано с xver=1.
    # В AWG-режиме xver=0 и Nginx вообще не проксирует на socket (только HTTP→HTTPS),
    # поэтому этот блок выполняется только для классического режима. ===
    if nginx_major > 1 or (nginx_major == 1 and nginx_minor >= 25):
        listen_main    = f"listen unix:{PARAM_SOCKET_PATH} ssl proxy_protocol;"
        listen_default = f"listen unix:{PARAM_SOCKET_PATH} ssl proxy_protocol default_server;"
        http2_line     = "    http2 on;"
        info(f"Nginx {nginx_ver}: директива 'http2 on' (proxy_protocol согласован с xver=1)")
    else:
        listen_main    = f"listen unix:{PARAM_SOCKET_PATH} ssl http2 proxy_protocol;"
        listen_default = f"listen unix:{PARAM_SOCKET_PATH} ssl http2 proxy_protocol default_server;"
        http2_line     = ""
        info(f"Nginx {nginx_ver}: http2 в строке listen (proxy_protocol согласован с xver=1)")
    # === END FIX ROOT ===

    rate_limit = ""
    if NGINX_RATE_LIMIT_CONF.exists():
        rate_limit = ("    limit_req zone=general burst=20 nodelay;\n"
                      "    limit_conn conn_limit 10;")

    cfg = NGINX_CONF_DIR / PARAM_DOMAIN
    cfg.write_text(textwrap.dedent(f"""\
        # HTTP → HTTPS redirect
        server {{
            listen 80;
            listen [::]:80;
            server_name {PARAM_DOMAIN};
            return 301 https://$host$request_uri;
        }}

        # Main server: VLESS fallback via Unix socket
        server {{
            server_name {PARAM_DOMAIN};

            {listen_main}
        {http2_line}

            ssl_certificate     /etc/letsencrypt/live/{PARAM_DOMAIN}/fullchain.pem;
            ssl_certificate_key /etc/letsencrypt/live/{PARAM_DOMAIN}/privkey.pem;
            ssl_protocols TLSv1.2 TLSv1.3;
            ssl_ciphers ECDHE-ECDSA-AES128-GCM-SHA256:ECDHE-RSA-AES128-GCM-SHA256:ECDHE-ECDSA-AES256-GCM-SHA384:ECDHE-RSA-AES256-GCM-SHA384:ECDHE-ECDSA-CHACHA20-POLY1305:ECDHE-RSA-CHACHA20-POLY1305;
            ssl_prefer_server_ciphers on;

            real_ip_header proxy_protocol;
            set_real_ip_from unix:;

            root {web_root};
            index index.html;

            add_header X-Robots-Tag "noindex, nofollow" always;
        {rate_limit}

            location / {{
                try_files $uri $uri/ =404;
            }}
        }}

        # Default server: reject all other SNI
        server {{
            {listen_default}
            server_name _;
            ssl_reject_handshake on;
            return 444;
        }}
    """))

    # Создаём временный unix-сокет если нет
    sock_path = Path(PARAM_SOCKET_PATH)
    sock_parent = sock_path.parent
    sock_parent.mkdir(parents=True, exist_ok=True)
    if not sock_path.exists():
        try:
            s = socket.socket(socket.AF_UNIX, socket.SOCK_STREAM)
            s.bind(str(sock_path))
            s.close()
            info("Создан временный unix-сокет для nginx -t")
        except Exception:
            pass

    link = NGINX_ENABLED_DIR / PARAM_DOMAIN
    link.unlink(missing_ok=True)
    link.symlink_to(cfg)

    r = _run([_nginx_bin, "-t"], capture=True, check=False)
    log_to_file("INFO", r.stderr)

    if r.returncode == 0:
        r_active = _run(["systemctl", "is-active", "nginx"], capture=True, check=False)
        if r_active.stdout.strip() == "active":
            _run(["systemctl", "reload", "nginx"], check=False, quiet=True)
        success(f"Nginx финально настроен (Nginx {nginx_ver})")
    else:
        warn("nginx -t: проверка с временным сокетом (предупреждение ожидаемо):")
        for line in r.stderr.splitlines()[-5:]:
            warn(f"  {line}")
        info("Nginx будет запущен до Xray (финальный шаг установки)")

    # Удаляем временный сокет; финальный старт nginx — до xray
    sock_path.unlink(missing_ok=True)
    _run(["systemctl", "stop", "nginx"], check=False, quiet=True)

# =============================================================================
#  ШАГ 12.1: NGINX SYSTEMD OVERRIDE
# =============================================================================
def setup_nginx_systemd_override() -> None:
    info("Настройка зависимости Nginx → Xray в systemd...")
    override_dir = Path("/etc/systemd/system/nginx.service.d")
    override_dir.mkdir(parents=True, exist_ok=True)

    # При xHTTP Nginx не зависит от сокета Xray — можно запускать независимо
    if PROTOCOL_MODE == "xhttp":
        content = textwrap.dedent("""\
            [Unit]
            After=network.target
        """)
        msg = "Nginx: независимый запуск (xHTTP TLS — сокет не нужен)"
    elif PARAM_USE_DNSCRYPT:
        # REALITY: xray создаёт сокет, nginx к нему подключается.
        # Nginx стартует ПОСЛЕ xray и dnscrypt.
        content = textwrap.dedent("""\
            [Unit]
            After=xray.service dnscrypt-proxy.service
            Wants=xray.service dnscrypt-proxy.service
        """)
        msg = "Nginx будет запускаться после Xray и DNSCrypt-proxy (systemd override)"
    else:
        # REALITY: xray создаёт unix-сокет, nginx к нему подключается.
        content = textwrap.dedent("""\
            [Unit]
            After=xray.service
            Wants=xray.service
        """)
        msg = "Nginx будет запускаться после Xray (systemd override)"

    (override_dir / "after-xray.conf").write_text(content)
    _run(["systemctl", "daemon-reload"], check=False, quiet=True)
    success(msg)

# =============================================================================
#  ШАГ 13: АВТООБНОВЛЕНИЕ СЕРТИФИКАТА
# =============================================================================

def ensure_cert_fix_script(domain: str) -> Path:
    """Создает внешний скрипт для исправления прав, вызываемый systemd перед стартом Xray."""
    script_path = Path("/usr/local/bin/fix-xray-certs.sh")
    script_content = f"""#!/bin/bash
# Автоматический фикс прав для Xray xHTTP TLS (Created by install.py)
DOMAIN="{domain}"
ARCHIVE_DIR="/etc/letsencrypt/archive/$DOMAIN"
LIVE_DIR="/etc/letsencrypt/live/$DOMAIN"

[[ ! -d "$ARCHIVE_DIR" ]] && exit 0

# Гарантируем права на проход по директориям
chmod 755 /etc/letsencrypt/live 2>/dev/null || true
chmod 755 "$LIVE_DIR" 2>/dev/null || true
chmod 755 /etc/letsencrypt/archive 2>/dev/null || true
chmod 755 "$ARCHIVE_DIR" 2>/dev/null || true

# privkey → 640 root:xray (только xray читает приватный ключ)
chown root:xray "$ARCHIVE_DIR"/privkey*.pem 2>/dev/null || true
chmod 640 "$ARCHIVE_DIR"/privkey*.pem 2>/dev/null || true

# Публичные сертификаты → 644 (читают все: xray, nginx, etc.)
chmod 644 "$ARCHIVE_DIR"/fullchain*.pem 2>/dev/null || true
chmod 644 "$ARCHIVE_DIR"/chain*.pem 2>/dev/null || true
chmod 644 "$ARCHIVE_DIR"/cert*.pem 2>/dev/null || true
"""
    script_path.write_text(script_content)
    script_path.chmod(0o750)
    return script_path

def setup_cert_renewal() -> None:
    deploy_dir = Path("/etc/letsencrypt/renewal-hooks/deploy")
    deploy_dir.mkdir(parents=True, exist_ok=True)
    hook = deploy_dir / "nginx-reload.sh"

    if PROTOCOL_MODE == "xhttp":
        # Хук восстанавливает права после certbot renew и перезапускает сервисы.
        # privkey → 640 root:xray, публичные сертификаты → 644 (для xray и nginx).
        hook.write_text(textwrap.dedent(f"""\
#!/bin/bash
# Автоматически создаётся установщиком VLESS xHTTP TLS
DOMAIN="{PARAM_DOMAIN}"
ARCHIVE_DIR="/etc/letsencrypt/archive/$DOMAIN"

[[ ! -d "$ARCHIVE_DIR" ]] && exit 0

chmod 755 /etc/letsencrypt/live 2>/dev/null || true
chmod 755 /etc/letsencrypt/live/$DOMAIN 2>/dev/null || true
chmod 755 /etc/letsencrypt/archive 2>/dev/null || true
chmod 755 "$ARCHIVE_DIR" 2>/dev/null || true

chown root:xray "$ARCHIVE_DIR"/privkey*.pem 2>/dev/null || true
chmod 640 "$ARCHIVE_DIR"/privkey*.pem 2>/dev/null || true

chmod 644 "$ARCHIVE_DIR"/fullchain*.pem 2>/dev/null || true
chmod 644 "$ARCHIVE_DIR"/chain*.pem 2>/dev/null || true
chmod 644 "$ARCHIVE_DIR"/cert*.pem 2>/dev/null || true

systemctl restart xray 2>/dev/null || true
systemctl reload nginx 2>/dev/null || true
"""))
    else:
        hook.write_text("#!/bin/bash\nsystemctl reload nginx 2>/dev/null || true")

    hook.chmod(0o755)

    # crontab
    r = _run(["crontab", "-l"], capture=True, check=False)
    existing = r.stdout if r.returncode == 0 else ""
    if "certbot" not in existing:
        new_crontab = existing.rstrip('\n') + "\n0 3 * * * certbot renew --quiet\n"
        _run(["crontab", "-"], input_text=new_crontab, check=False, quiet=True)
    success("Автообновление сертификата настроено")


def _xray_get_release_info(prerelease: bool = False) -> "dict | None":
    """
    Возвращает dict с полями tag_name, prerelease из GitHub API.
    prerelease=False → /releases/latest
    prerelease=True  → /releases (первый, включая prerelease)
    """
    url = (
        "https://api.github.com/repos/XTLS/Xray-core/releases?per_page=5"
        if prerelease else
        "https://api.github.com/repos/XTLS/Xray-core/releases/latest"
    )
    for attempt in range(1, 4):
        try:
            r = _run(["curl", "-fsSL", "--connect-timeout", "10", url],
                     capture=True, check=False)
            data = json.loads(r.stdout)
            if prerelease:
                if isinstance(data, list) and data:
                    return data[0]
            else:
                if data.get("tag_name"):
                    return data
        except Exception:
            pass
        if attempt < 3:
            warn(f"Попытка {attempt}: не удалось получить данные GitHub, повтор...")
            time.sleep(2)
    return None


def _xray_version_norm(ver: str) -> str:
    ver = ver.lstrip("v")
    parts = (ver.split(".")[:3] + ["0", "0", "0"])[:3]
    try:
        return "".join(f"{int(p):05d}" for p in parts)
    except ValueError:
        return "000000000000000"


def _xray_current_version() -> str:
    xray_bin = shutil.which("xray") or "/usr/local/bin/xray"
    try:
        r = _run([xray_bin, "version"], capture=True, check=False)
        match = re.search(r'[0-9]+\.[0-9]+\.[0-9]+', r.stdout)
        if match:
            return "v" + match.group(0)
    except Exception:
        pass
    return "v0.0.0"


def _xray_geo_is_runetfreedom() -> bool:
    """
    Проверяет что geosite.dat содержит категорию ru-available-only-inside.
    Делает это через быстрый grep по бинарному содержимому файла.
    Это единственный надёжный способ — размер файла ненадёжен.
    """
    # Xray ищет geo-файлы в нескольких местах в таком порядке:
    # 1. $XRAY_LOCATION_ASSET  2. /etc/xray/  3. /usr/local/share/xray/
    # Проверяем все возможные пути.
    candidates = [
        Path("/etc/xray/geosite.dat"),
        Path("/usr/local/share/xray/geosite.dat"),
        Path("/usr/local/etc/xray/geosite.dat"),
    ]
    # Путь рядом с бинарником
    xray_bin = shutil.which("xray") or "/usr/local/bin/xray"
    candidates.append(Path(xray_bin).parent / "geosite.dat")

    for p in candidates:
        if not p.exists():
            continue
        try:
            import subprocess as _sp
            r = _sp.run(
                ["grep", "-qaF", "ru-available-only-inside", str(p)],
                capture_output=True,
            )
            if r.returncode == 0:
                return True
        except Exception:
            pass
    return False


