def _xray_update_geo_runetfreedom() -> bool:
    """
    Скачивает runetfreedom geosite.dat + geoip.dat и раскладывает
    во ВСЕ директории где Xray ищет geo-файлы.
    При неудаче — предлагает ручное размещение файлов.
    Возвращает True если geosite.dat скачан и установлен успешно.
    """
    # Все известные зеркала — jsDelivr идёт первым (лучше доступен с РФ)
    GEOSITE_URLS = [
        "https://cdn.jsdelivr.net/gh/runetfreedom/russia-v2ray-rules-dat@release/geosite.dat",
        GEOSITE_URL,  # raw.githubusercontent.com
        "https://github.com/runetfreedom/russia-v2ray-rules-dat/releases/latest/download/geosite.dat",
        "https://ghproxy.net/https://github.com/runetfreedom/russia-v2ray-rules-dat/releases/latest/download/geosite.dat",
        "https://ghproxy.com/https://github.com/runetfreedom/russia-v2ray-rules-dat/releases/latest/download/geosite.dat",
        "https://mirror.ghproxy.com/https://github.com/runetfreedom/russia-v2ray-rules-dat/releases/latest/download/geosite.dat",
        "https://gh.con.sh/https://github.com/runetfreedom/russia-v2ray-rules-dat/releases/latest/download/geosite.dat",
        "https://hub.gitmirror.com/https://github.com/runetfreedom/russia-v2ray-rules-dat/releases/latest/download/geosite.dat",
        "https://github.moeyy.xyz/https://github.com/runetfreedom/russia-v2ray-rules-dat/releases/latest/download/geosite.dat",
    ]
    GEOIP_URLS = [
        "https://cdn.jsdelivr.net/gh/runetfreedom/russia-v2ray-rules-dat@release/geoip.dat",
        GEOIP_URL,    # raw.githubusercontent.com
        "https://github.com/runetfreedom/russia-v2ray-rules-dat/releases/latest/download/geoip.dat",
        "https://ghproxy.net/https://github.com/runetfreedom/russia-v2ray-rules-dat/releases/latest/download/geoip.dat",
        "https://ghproxy.com/https://github.com/runetfreedom/russia-v2ray-rules-dat/releases/latest/download/geoip.dat",
        "https://mirror.ghproxy.com/https://github.com/runetfreedom/russia-v2ray-rules-dat/releases/latest/download/geoip.dat",
        "https://gh.con.sh/https://github.com/runetfreedom/russia-v2ray-rules-dat/releases/latest/download/geoip.dat",
        "https://hub.gitmirror.com/https://github.com/runetfreedom/russia-v2ray-rules-dat/releases/latest/download/geoip.dat",
        "https://github.moeyy.xyz/https://github.com/runetfreedom/russia-v2ray-rules-dat/releases/latest/download/geoip.dat",
    ]

    # Выводим ссылки в терминал
    print()
    info("  Ссылки для скачивания geo-файлов:")
    print(f"  {DIM}geosite.dat:{NC}")
    for url in GEOSITE_URLS[:4]:
        print(f"    {DIM}{url}{NC}")
    print(f"  {DIM}geoip.dat:{NC}")
    for url in GEOIP_URLS[:4]:
        print(f"    {DIM}{url}{NC}")
    print()

    # Все директории где Xray ищет geo-файлы
    xray_bin = shutil.which("xray") or "/usr/local/bin/xray"
    dest_dirs_raw = [
        Path("/usr/local/share/xray"),
        Path("/etc/xray"),
        Path("/usr/local/etc/xray"),
        Path(xray_bin).parent,
    ]
    seen: set = set()
    geo_dirs = []
    for d in dest_dirs_raw:
        if d not in seen:
            seen.add(d)
            try:
                d.mkdir(parents=True, exist_ok=True)
                geo_dirs.append(d)
            except Exception:
                if d.exists():
                    geo_dirs.append(d)

    # Пути ручного размещения — /root/ проверяем тоже
    _MANUAL_ROOTS = [Path("/root")]

    geosite_ok = False
    failed_files: list[str] = []

    for urls, fname, min_size in (
        (GEOSITE_URLS, "geosite.dat", 3_000_000),
        (GEOIP_URLS,   "geoip.dat",   10_000),
    ):
        tmp = Path(f"/tmp/runet_{fname}")
        downloaded = False

        # Проверяем файлы уже размещённые пользователем вручную
        for manual_dir in _MANUAL_ROOTS + geo_dirs:
            candidate = manual_dir / fname
            if candidate.exists() and candidate.stat().st_size >= min_size:
                info(f"  Найден локальный файл: {candidate} ({candidate.stat().st_size // 1024} КБ)")
                tmp = candidate
                downloaded = True
                break

        if not downloaded:
            for url in urls:
                tmp_dl = Path(f"/tmp/runet_{fname}")
                tmp_dl.unlink(missing_ok=True)
                info(f"  Загрузка {fname}: {url.split('/')[2]} ...")
                r = _run([
                    "curl", "-fL", "--connect-timeout", "15",
                    "-m", "120", "--retry", "2",
                    "-o", str(tmp_dl), url,
                ], capture=True, check=False, quiet=True)
                sz = tmp_dl.stat().st_size if tmp_dl.exists() else 0
                if r.returncode == 0 and sz >= min_size:
                    info(f"  Скачан {fname} ({sz // 1024} КБ)")
                    tmp = tmp_dl
                    downloaded = True
                    break
                warn(f"  {url.split('/')[2]}: код {r.returncode}, размер {sz} Б — следующий источник...")
                tmp_dl.unlink(missing_ok=True)

        if not downloaded:
            # Fallback: wget
            info(f"  Пробую wget для {fname} ...")
            tmp_dl = Path(f"/tmp/runet_{fname}")
            tmp_dl.unlink(missing_ok=True)
            r2 = _run([
                "wget", "-q", "--timeout=60", "--tries=2",
                "-O", str(tmp_dl), urls[0],
            ], capture=True, check=False, quiet=True)
            sz = tmp_dl.stat().st_size if tmp_dl.exists() else 0
            if r2.returncode == 0 and sz >= min_size:
                info(f"  Скачан {fname} через wget ({sz // 1024} КБ)")
                tmp = tmp_dl
                downloaded = True

        if downloaded:
            for dest_dir in geo_dirs:
                dest = dest_dir / fname
                try:
                    shutil.copy2(tmp, dest)
                    dest.chmod(0o644)
                except Exception:
                    pass
            # Не удаляем если это был файл пользователя из /root/
            if str(tmp).startswith("/tmp/"):
                tmp.unlink(missing_ok=True)
            if fname == "geosite.dat":
                geosite_ok = True
                info(f"  geosite.dat → {', '.join(str(d) for d in geo_dirs)}")
        else:
            warn(f"  Не удалось скачать {fname} из всех источников — split tunneling будет частично отключён")
            failed_files.append(fname)

    # Если что-то не скачалось — предлагаем ручное размещение
    if failed_files:
        warn(f"  Не удалось загрузить гео-файлы — проверьте интернет-соединение")
        _geo_print_manual_download_hint()
        try:
            ans = input(f"{CYAN}  Разместили файлы вручную? Повторить проверку? [Y/n]:{NC} ").strip().lower()
        except (EOFError, KeyboardInterrupt):
            ans = "n"
        if ans != "n":
            # Повторная проверка наличия файлов вручную
            for fname, min_size in (("geosite.dat", 3_000_000), ("geoip.dat", 10_000)):
                if fname not in failed_files:
                    continue
                for manual_dir in _MANUAL_ROOTS + geo_dirs:
                    candidate = manual_dir / fname
                    if candidate.exists() and candidate.stat().st_size >= min_size:
                        info(f"  Найден: {candidate} ({candidate.stat().st_size // 1024} КБ)")
                        for dest_dir in geo_dirs:
                            dest = dest_dir / fname
                            try:
                                shutil.copy2(candidate, dest)
                                dest.chmod(0o644)
                            except Exception:
                                pass
                        if fname == "geosite.dat":
                            geosite_ok = True
                        failed_files.remove(fname)
                        info(f"  {fname} → {', '.join(str(d) for d in geo_dirs)}")
                        break

    return geosite_ok


def _xray_do_upgrade(tag: str, is_prerelease: bool = False) -> bool:
    """
    Скачивает, верифицирует и устанавливает Xray версии tag.

    Порядок действий:
      1. Скачать zip + проверить SHA256.
      2. Распаковать новый бинарник во временную папку.
      3. Если geo-файлы не runetfreedom — обновить их сейчас
         (без этого тест конфига упадёт на geosite:ru-available-only-inside).
      4. Тест конфига новым бинарником.
      5. При ошибке теста — сообщить причину, ничего не трогать.
      6. При успехе — бэкап старого бинарника, установка нового.
      7. .dat из zip НЕ перезатирают runetfreedom-версии.
    """
    xray_bin_path = shutil.which("xray") or "/usr/local/bin/xray"
    xray_bin = Path(xray_bin_path)
    current_ver = _xray_current_version()

    arch_map = {"x86_64": "64", "aarch64": "arm64-v8a", "armv7l": "arm32-v7a"}
    machine = subprocess.check_output(["uname", "-m"]).decode().strip()
    xray_arch = arch_map.get(machine)
    if not xray_arch:
        warn(f"Архитектура {machine} не поддерживается")
        return False

    zip_name = f"Xray-linux-{xray_arch}.zip"
    zip_url  = f"https://github.com/XTLS/Xray-core/releases/download/{tag}/{zip_name}"
    chk_url  = f"https://github.com/XTLS/Xray-core/releases/download/{tag}/checksums.txt"

    label = f"{YELLOW}[PRERELEASE]{NC}" if is_prerelease else f"{GREEN}[LATEST]{NC}"
    info(f"Скачиваю Xray {label} {tag} ...")

    zip_tmp = Path("/tmp/xray_manual_update.zip")
    r = _run([
        "curl", "-fsSL", "--connect-timeout", "30", "--retry", "3",
        zip_url, "-o", str(zip_tmp),
    ], check=False, quiet=True)
    if r.returncode != 0:
        warn(f"Ошибка загрузки: {zip_url}")
        return False

    if not _verify_sha256(zip_tmp, chk_url, zip_name):
        zip_tmp.unlink(missing_ok=True)
        warn("SHA256 верификация провалилась. Установка отменена.")
        return False
    info("SHA256 верификация: ОК")

    with tempfile.TemporaryDirectory(prefix="xray_upd.") as ext_dir:
        _run(["unzip", "-o", str(zip_tmp), "-d", ext_dir], check=False, quiet=True)
        zip_tmp.unlink(missing_ok=True)
        new_bin = Path(ext_dir) / "xray"
        if not new_bin.exists():
            warn("Бинарник xray не найден в архиве")
            return False

        # ── Шаг 3: убеждаемся что geo-файлы — runetfreedom-версия ──────
        # Проверяем наличие категории ru-available-only-inside в geosite.dat.
        # Если уже есть — не скачиваем повторно (файл ~65 MB, долго).
        print()
        if _xray_geo_is_runetfreedom():
            info("Geo-файлы runetfreedom уже установлены — пропускаем загрузку")
            geo_ok = True
        else:
            info("Обновляю geosite.dat / geoip.dat (runetfreedom)...")
            geo_ok = _xray_update_geo_runetfreedom()
            if not geo_ok:
                warn("Не удалось скачать geo-файлы runetfreedom.")
                warn("Обновите вручную и повторите:")
                warn("  curl -fsSL https://github.com/runetfreedom/russia-v2ray-rules-dat"
                     "/releases/latest/download/geosite.dat -o /usr/local/share/xray/geosite.dat")
                warn("  cp /usr/local/share/xray/geosite.dat /etc/xray/geosite.dat")
                return False
            success("Geo-файлы runetfreedom установлены")
        print()

        # ── Шаг 4: тест конфига новым бинарником ─────────────────────────
        # Xray ищет geosite.dat/geoip.dat сначала рядом с бинарником
        # (os.Executable()), потом в системных путях.
        # new_bin во временной папке — копируем runetfreedom .dat туда,
        # ПЕРЕЗАПИСЫВАЯ стандартные файлы из zip которые уже там лежат.
        for dat_name in ("geosite.dat", "geoip.dat"):
            dst = Path(ext_dir) / dat_name
            # Ищем runetfreedom-версию по всем системным путям
            for src_dir in (Path("/etc/xray"), Path("/usr/local/share/xray"),
                            Path("/usr/local/etc/xray")):
                src = src_dir / dat_name
                if src.exists() and src.stat().st_size > 3_000_000:
                    try:
                        shutil.copy2(src, dst)
                        info(f"  {dat_name} → {ext_dir} ({src.stat().st_size // 1024} КБ)")
                    except Exception:
                        pass
                    break

        cfg_path = None
        for cp in (Path("/etc/xray/config.json"),
                   Path("/usr/local/etc/xray/config.json")):
            if cp.exists():
                cfg_path = cp
                break

        if cfg_path:
            info("Тест конфига новым бинарником...")
            rt = _run(
                [str(new_bin), "run", "-test", "-config", str(cfg_path)],
                capture=True, check=False,
            )
            if rt.returncode != 0:
                err_out = (rt.stderr.strip() or rt.stdout.strip())
                print()
                print(f"{RED}{'═'*64}{NC}")
                print(f"{RED}  ✗ ТЕСТ КОНФИГА НЕ ПРОШЁЛ{NC}")
                print(f"{RED}{'═'*64}{NC}")
                print(f"{DIM}{err_out}{NC}")
                print(f"{RED}{'═'*64}{NC}")
                warn("Установка отменена. Бинарник не заменён.")
                return False
            info("Тест конфига: ОК")

        # ── Шаг 5: бэкап старого бинарника ───────────────────────────────
        backup_dir = Path("/var/backups/xray/binaries")
        backup_dir.mkdir(parents=True, exist_ok=True)
        backup_path = backup_dir / f"xray_{current_ver}_{datetime.now().strftime('%Y%m%d%H%M%S')}"
        try:
            shutil.copy2(xray_bin, backup_path)
            backup_path.chmod(0o755)
            info(f"Бэкап бинарника: {backup_path}")
            for old_b in sorted(backup_dir.glob("xray_*"))[:-5]:
                old_b.unlink(missing_ok=True)
        except Exception as e:
            warn(f"Не удалось создать бэкап: {e}")

        # ── Шаг 6: установка нового бинарника ────────────────────────────
        # Нельзя перезаписать запущенный бинарник (ETXTBSY).
        # Решение: удалить старый файл, затем скопировать новый.
        # unlink не мешает уже запущенному процессу — он держит inode,
        # а новый файл получит новый inode.
        try:
            xray_bin.unlink()
        except Exception as e:
            warn(f"Не удалось удалить старый бинарник: {e}")
        shutil.copy2(new_bin, xray_bin)
        xray_bin.chmod(0o755)

        # ── Шаг 7: .dat из zip — НЕ перезатираем runetfreedom ────────────
        _geo_thresholds = {
            "geosite.dat": 10 * 1024 * 1024,
            "geoip.dat":   15 * 1024 * 1024,
        }
        share_dir = Path("/usr/local/share/xray")
        for dat in Path(ext_dir).glob("*.dat"):
            dest = share_dir / dat.name
            thr = _geo_thresholds.get(dat.name, 0)
            if thr and dest.exists() and dest.stat().st_size >= thr:
                info(f"  Сохранён runetfreedom {dat.name} — zip пропущен")
            else:
                try:
                    shutil.copy2(dat, dest)
                except Exception:
                    pass

    return True


def _xray_restart_all_services() -> bool:
    """Перезапускает xray и nginx. Ждёт до 15 сек. Возвращает True если xray активен."""
    info("Перезапуск Xray...")
    _run(["systemctl", "restart", "xray"], check=False, quiet=True)
    for i in range(1, 6):
        time.sleep(3)
        rs = _run(["systemctl", "is-active", "xray"], capture=True, check=False)
        if rs.stdout.strip() == "active":
            success("Xray запущен успешно")
            rn = _run(["systemctl", "is-active", "nginx"], capture=True, check=False)
            if rn.stdout.strip() == "active":
                _run(["systemctl", "restart", "nginx"], check=False, quiet=True)
                info("Nginx перезапущен")
            return True
        info(f"Ожидание запуска Xray... ({i*3}/15 сек)")
    return False


def _nginx_restart_if_reality() -> None:
    """
    Перезапускает nginx после restart xray при режиме REALITY+Unix-сокет.

    АРХИТЕКТУРА: при REALITY-режиме nginx слушает на unix:PARAM_SOCKET_PATH
    (listen unix:/dev/shm/XXXX.socket ssl proxy_protocol). Xray при старте
    выполняет ExecStartPre: rm -f PARAM_SOCKET_PATH — удаляет файл сокета.
    Сокет создаётся NGINX-ом при его (пере)запуске, не Xray-ом.

    BUGFIX: предыдущая логика ждала появления сокета ДО перезапуска nginx —
    deadlock, потому что сокет появляется только ПОСЛЕ запуска nginx.
    Исправление: сначала перезапускаем nginx (он создаёт сокет), затем ждём
    подтверждения что сокет появился.
    """
    if PROTOCOL_MODE != "reality" or not PARAM_SOCKET_PATH:
        return
    # AWG-режим: Xray слушает напрямую на TCP-порту, unix-сокет не используется
    if AWG_EXIT_ENABLED:
        return
    rn = _run(["systemctl", "is-active", "nginx"], capture=True, check=False)
    if rn.stdout.strip() != "active":
        return
    # Перезапускаем nginx ПЕРВЫМ — он создаст bind на unix-сокет
    _run(["systemctl", "restart", "nginx"], check=False, quiet=True)
    # Ждём подтверждения что сокет появился (nginx создаёт его при старте)
    for _i in range(20):
        if Path(PARAM_SOCKET_PATH).is_socket():
            break
        time.sleep(1)
    else:
        warn(f"Сокет {PARAM_SOCKET_PATH} не появился за 20 сек после restart nginx — проверьте: journalctl -u nginx -n 20")
        return
    time.sleep(1)
    info("nginx перезапущен, Unix-сокет готов")


def _xray_find_config() -> Path | None:
    """Возвращает актуальный путь к config.json (проверяет обе стандартные локации)."""
    for p in (Path("/etc/xray/config.json"),
              Path("/usr/local/etc/xray/config.json")):
        if p.exists():
            return p
    return None


def _xray_config_rollback(backup_cfg: Path, cfg: Path) -> None:
    """
    Откатывает config.json из резервной копии и перезапускает Xray.
    Вызывается когда xray не запустился после применения нового конфига.
    """
    warn("Откат конфигурации из резервной копии...")
    try:
        shutil.copy2(backup_cfg, cfg)
        _set_config_owner(cfg)
        log_to_file("WARN", f"Конфиг откатан из {backup_cfg} → {cfg}")
    except Exception as e:
        warn(f"Не удалось откатить конфиг: {e}")
        log_to_file("ERROR", f"Откат конфига провалился: {e}")
        return
    _run(["systemctl", "restart", "xray"], check=False, quiet=True)
    time.sleep(2)
    r = _run(["systemctl", "is-active", "xray"], capture=True, check=False)
    if r.stdout.strip() == "active":
        success("Xray запущен на откатанном конфиге")
    else:
        warn("Xray не запустился даже после отката! Проверьте: journalctl -u xray -n 50")


def _xray_safe_apply_config(cfg: Path | None = None,
                             *,
                             service_restart: bool = True) -> bool:
    """
    Безопасное применение конфига Xray:
      1. Находит cfg (если не передан явно).
      2. Создаёт временный бэкап текущего конфига.
      3. Запускает ``xray run -test`` — при ошибке останавливается (xray НЕ перезапускается).
      4. Синхронизирует вторую копию конфига (если есть).
      5. Делает ``systemctl restart xray`` и ждёт до 15 сек.
      6. Если xray не поднялся — автоматически откатывает конфиг из бэкапа.

    Возвращает True при успехе, False при любой ошибке.

    Используется вместо прямого ``systemctl restart xray`` везде, где конфиг мог измениться.
    """
    # ── 1. Найти конфиг ───────────────────────────────────────────────────────
    if cfg is None:
        cfg = _xray_find_config()
    if cfg is None:
        warn("_xray_safe_apply_config: конфиг Xray не найден")
        return False

    # ── 2. Бэкап текущего конфига ─────────────────────────────────────────────
    backup_cfg = cfg.with_suffix(".json.pre-apply")
    try:
        shutil.copy2(cfg, backup_cfg)
    except Exception as e:
        warn(f"Не удалось создать бэкап конфига: {e}. Применение отменено.")
        return False

    # ── 3. Валидация ──────────────────────────────────────────────────────────
    xray_bin = shutil.which("xray") or "/usr/local/bin/xray"
    r = _run([xray_bin, "run", "-test", "-config", str(cfg)],
             capture=True, check=False)
    if r.returncode != 0:
        err_out = (r.stdout + r.stderr).strip()
        warn(f"xray -test: конфиг содержит ошибки — перезапуск отменён")
        if err_out:
            dim(f"  {err_out[:600]}")
        log_to_file("ERROR", f"xray -test провалился для {cfg}: {err_out[:400]}")
        try:
            backup_cfg.unlink(missing_ok=True)
        except Exception:
            pass
        return False

    # ── 4. Синхронизация второй копии конфига ─────────────────────────────────
    all_cfgs = [Path("/etc/xray/config.json"),
                Path("/usr/local/etc/xray/config.json")]
    for other in all_cfgs:
        if other != cfg and other.exists() and not other.is_symlink():
            try:
                shutil.copy2(cfg, other)
                _set_config_owner(other)
            except Exception as e:
                warn(f"Не удалось синхронизировать {other}: {e}")

    # ── 5. Перезапуск ─────────────────────────────────────────────────────────
    if not service_restart:
        backup_cfg.unlink(missing_ok=True)
        return True

    _run(["systemctl", "restart", "xray"], check=False, quiet=True)
    _nginx_restart_if_reality()

    for i in range(1, 6):
        time.sleep(3)
        r2 = _run(["systemctl", "is-active", "xray"], capture=True, check=False)
        if r2.stdout.strip() == "active":
            success("Xray перезапущен успешно (конфиг прошёл проверку)")
            log_to_file("SUCCESS", f"xray перезапущен после применения {cfg}")
            backup_cfg.unlink(missing_ok=True)
            return True
        info(f"Ожидание запуска Xray... ({i*3}/15 сек)")

    # ── 6. Xray не поднялся — откат ───────────────────────────────────────────
    warn("Xray не запустился после применения конфига — запускаю откат")
    log_to_file("ERROR", "xray не запустился — откат конфига")
    _xray_config_rollback(backup_cfg, cfg)
    try:
        backup_cfg.unlink(missing_ok=True)
    except Exception:
        pass
    return False


def _xray_rollback(backup_path: Path) -> bool:
    """Откатывает бинарник из backup_path и перезапускает сервисы."""
    xray_bin = Path(shutil.which("xray") or "/usr/local/bin/xray")
    try:
        shutil.copy2(backup_path, xray_bin)
        xray_bin.chmod(0o755)
        info(f"Бинарник откатан из: {backup_path}")
    except Exception as e:
        warn(f"Ошибка отката бинарника: {e}")
        return False
    return _xray_restart_all_services()


def do_xray_update_interactive() -> None:
    """
    Интерактивное обновление Xray из меню.
    Проверяет ветку latest И prerelease.
    Cron-задача использует только latest (xray-autoupdate.sh).
    """
    os.system("clear")
    print()
    _box_top("🔧  ОБНОВЛЕНИЕ XRAY-CORE")
    _box_row()
    current_ver = _xray_current_version()
    _box_row(f"  Текущая версия: {CYAN}{current_ver}{NC}")
    _box_sep()
    _box_row(f"  {DIM}Получение информации о релизах...{NC}")
    _box_bottom()
    print()

    info("Получение latest release...")
    latest_info = _xray_get_release_info(prerelease=False)
    latest_tag  = latest_info.get("tag_name", "") if latest_info else ""

    info("Получение prerelease info...")
    pre_info = _xray_get_release_info(prerelease=True)
    pre_tag  = pre_info.get("tag_name", "") if pre_info else ""
    is_pre   = pre_info.get("prerelease", False) if pre_info else False

    cur_norm    = _xray_version_norm(current_ver)
    latest_norm = _xray_version_norm(latest_tag) if latest_tag else cur_norm
    pre_norm    = _xray_version_norm(pre_tag) if pre_tag else cur_norm

    has_latest_update = bool(latest_tag and latest_norm > cur_norm)
    has_pre_update    = bool(pre_tag and is_pre and pre_norm > cur_norm and pre_tag != latest_tag)

    print()
    print(f"{CYAN}{'═'*64}{NC}")
    print(f"{CYAN}  ИНФОРМАЦИЯ О ВЕРСИЯХ{NC}")
    print(f"{CYAN}{'═'*64}{NC}")
    print(f"  Установлена:       {BOLD}{current_ver}{NC}")
    if latest_tag:
        marker = f"  {GREEN}← доступно{NC}" if has_latest_update else f"  {DIM}(актуально){NC}"
        print(f"  Stable (latest):   {GREEN}{latest_tag}{NC}{marker}")
    else:
        print(f"  Stable (latest):   {RED}не удалось получить{NC}")
    if pre_tag and is_pre:
        marker = f"  {YELLOW}← доступна prerelease{NC}" if has_pre_update else f"  {DIM}(не новее){NC}"
        print(f"  Prerelease:        {YELLOW}{pre_tag}{NC}{marker}")
    elif pre_tag:
        print(f"  Prerelease:        {DIM}отдельного prerelease нет{NC}")
    print(f"{CYAN}{'═'*64}{NC}")
    print()

    if not has_latest_update and not has_pre_update:
        success("Xray актуален. Обновлений нет.")
        return

    choices = []
    if has_latest_update:
        choices.append(("1", f"Обновить до {GREEN}stable{NC} {latest_tag}", latest_tag, False))
    if has_pre_update:
        choices.append(("2" if has_latest_update else "1",
                        f"Обновить до {YELLOW}prerelease{NC} {pre_tag}", pre_tag, True))

    for key, label, _t, _p in choices:
        print(f"  [{key}] {label}")
    print(f"  [Q] Отмена")
    print()

    target_tag    = None
    target_is_pre = False
    while True:
        try:
            ch = input(f"{CYAN}Выбор:{NC} ").strip().upper()
        except (KeyboardInterrupt, EOFError):
            ch = "Q"
        if ch in ("Q", ""):
            info("Обновление отменено.")
            return
        for key, label, _t, _p in choices:
            if ch == key:
                target_tag, target_is_pre = _t, _p
                break
        if target_tag:
            break
        warn("Неверный выбор.")

    if target_is_pre:
        print()
        print(f"{YELLOW}{'═'*64}{NC}")
        print(f"{YELLOW}  ⚠  ВНИМАНИЕ: PRERELEASE ВЕРСИЯ{NC}")
        print(f"{YELLOW}{'═'*64}{NC}")
        print(f"  Версия {BOLD}{target_tag}{NC} является НЕСТАБИЛЬНОЙ (prerelease).")
        print(f"  Возможны: ошибки, изменение поведения, несовместимость.")
        print(f"  Автообновление по cron будет использовать только stable.")
        print(f"{YELLOW}{'═'*64}{NC}")
        print()
        try:
            confirm = input(
                f"{YELLOW}  Вы уверены? [y/N]:{NC} "
            ).strip().lower()
        except (KeyboardInterrupt, EOFError):
            confirm = "n"
        if confirm not in ("y", "yes"):
            info("Установка prerelease отменена.")
            return

    backup_dir = Path("/var/backups/xray/binaries")
    existing_backups_before = set(backup_dir.glob("xray_*")) if backup_dir.exists() else set()

    print()
    info(f"Начинаю обновление: {current_ver} → {target_tag} ...")
    ok = _xray_do_upgrade(target_tag, is_prerelease=target_is_pre)
    if not ok:
        warn("Обновление завершилось с ошибкой. Бинарник не заменён.")
        return

    xray_started = _xray_restart_all_services()
    new_ver = _xray_current_version()

    if xray_started:
        print()
        success(f"Xray успешно обновлён: {current_ver} → {new_ver}")
        if target_is_pre:
            warn("Установлена PRERELEASE версия. Следите за стабильностью.")
        dim("  Лог: /var/log/xray-autoupdate.log")
        return

    # Xray не запустился после установки
    print()
    print(f"{RED}{'═'*64}{NC}")
    print(f"{RED}  ✗ XRAY НЕ ЗАПУСТИЛСЯ ПОСЛЕ ОБНОВЛЕНИЯ{NC}")
    print(f"{RED}{'═'*64}{NC}")
    print()
    print(f"  Команда для просмотра причины:")
    print(f"  {BOLD}{CYAN}journalctl -u xray -n 50 --no-pager{NC}")
    print(f"{RED}{'═'*64}{NC}")
    print()

    all_backups  = sorted(backup_dir.glob("xray_*")) if backup_dir.exists() else []
    new_backups  = [b for b in all_backups if b not in existing_backups_before]
    rollback_src = new_backups[-1] if new_backups else (all_backups[-1] if all_backups else None)

    if rollback_src:
        rollback_ver = rollback_src.name.split("_")[1] if "_" in rollback_src.name else "предыдущая"
        print(f"  Доступен откат на: {GREEN}{rollback_ver}{NC}  ({DIM}{rollback_src}{NC})")
        print()
        try:
            ans = input(f"{CYAN}  Откатиться? [Y/n]:{NC} ").strip().lower()
        except (KeyboardInterrupt, EOFError):
            ans = "n"
        if ans in ("y", "yes", ""):
            info(f"Откат на {rollback_ver}...")
            if _xray_rollback(rollback_src):
                print()
                success(f"Откат выполнен. Xray работает на версии: {_xray_current_version()}")
                success("Все сервисы запущены. Система готова к использованию.")
            else:
                print()
                print(f"{RED}✗ Xray не запустился и после отката!{NC}")
                print(f"  {BOLD}{CYAN}journalctl -u xray -n 50 --no-pager{NC}")
                print(f"  {BOLD}{CYAN}xray run -test -config /etc/xray/config.json{NC}")
        else:
            warn("Откат отменён. Xray остаётся в нерабочем состоянии.")
    else:
        warn("Бэкап не найден — автоматический откат невозможен.")
        warn("Переустановите Xray через пункт меню [1].")


def setup_xray_autoupdate() -> None:
    print()  # перевод строки после прогресс-бара (он оставляет курсор без \n)
    _box_top(f"Автообновление Xray-core")
    _box_row()
    _box_row()
    _box_item("Y", f"Включить автообновление (systemd timer, ежедневно 03:30)")
    _box_item("N", f"Отключить — обновлять вручную")
    _box_sep()
    _box_bottom()

    while True:
        choice = input(
            f"{CYAN}Включить автообновление Xray? [Y/n]:{NC} "
        ).strip().lower()
        if choice in ('y', 'yes', ''):
            _install_autoupdate_service()
            break
        elif choice in ('n', 'no'):
            break
        warn("Введите Y или N")


def _install_autoupdate_service() -> None:
    info("Установка сервиса автообновления Xray...")
    agent = Path("/usr/local/bin/xray-autoupdate.sh")

    agent.write_text(textwrap.dedent(r"""
        #!/usr/bin/env bash
        set -euo pipefail
        LOG="/var/log/xray-autoupdate.log"
        BACKUP_DIR="/var/backups/xray/binaries"

        # Ротация лога выполняется logrotate (/etc/logrotate.d/xray-aux).
        touch "$LOG" 2>/dev/null || true
        chmod 600 "$LOG" 2>/dev/null || true
        log() { echo "[$(date '+%Y-%m-%d %H:%M:%S')] $*" >> "$LOG" 2>/dev/null || true; }

        log "=== Проверка обновлений Xray-core ==="
        XRAY_BIN=$(command -v xray 2>/dev/null || echo /usr/local/bin/xray)
        [[ ! -x "$XRAY_BIN" ]] && log "ERROR: Xray не найден" && exit 1

        CURRENT_RAW=$("$XRAY_BIN" version 2>&1 | head -1 | grep -oE '[0-9]+\.[0-9]+\.[0-9]+' | head -1 || true)
        CURRENT="v${CURRENT_RAW:-0.0.0}"
        log "Установлена: $CURRENT"

        LATEST=$(curl -fsSL --connect-timeout 15 \
            "https://api.github.com/repos/XTLS/Xray-core/releases/latest" \
            2>/dev/null | python3 -c "import json,sys; d=json.load(sys.stdin); print(d.get('tag_name',''))" 2>/dev/null || true)
        [[ -z "$LATEST" ]] && log "WARN: Не удалось получить latest" && exit 0
        log "Последняя: $LATEST"

        _norm() { echo "$1" | sed 's/^v//' | tr '.' ' ' | awk '{printf "%05d%05d%05d\n", $1, $2, $3}'; }
        [[ "$(_norm "$CURRENT")" == "$(_norm "$LATEST")" ]] && log "INFO: Версия актуальна" && exit 0

        log "INFO: Обновление $CURRENT → $LATEST"
        ARCH=$(uname -m)
        case "$ARCH" in
            x86_64)  XRAY_ARCH="64" ;;
            aarch64) XRAY_ARCH="arm64-v8a" ;;
            armv7*)  XRAY_ARCH="arm32-v7a" ;;
            *) log "ERROR: Архитектура $ARCH не поддерживается" && exit 1 ;;
        esac

        mkdir -p "$BACKUP_DIR"
        BACKUP="${BACKUP_DIR}/xray_${CURRENT}_$(date +%Y%m%d%H%M%S)"
        cp "$XRAY_BIN" "$BACKUP" && chmod 755 "$BACKUP" || true
        ls -t "${BACKUP_DIR}"/xray_* 2>/dev/null | tail -n +6 | xargs rm -f 2>/dev/null || true

        ZIP_NAME="Xray-linux-${XRAY_ARCH}.zip"
        ZIP_URL="https://github.com/XTLS/Xray-core/releases/download/${LATEST}/${ZIP_NAME}"
        ZIP_TMP=$(mktemp /tmp/xray_au.XXXXXX.zip)
        EXTRACT_DIR=$(mktemp -d /tmp/xray_au_ex.XXXXXX)
        trap 'rm -f "$ZIP_TMP" 2>/dev/null; rm -rf "$EXTRACT_DIR" 2>/dev/null' EXIT

        curl -fsSL --connect-timeout 30 --retry 3 "$ZIP_URL" -o "$ZIP_TMP" 2>/dev/null || \
            { log "ERROR: Ошибка загрузки"; exit 1; }

        CHKS_TMP=$(mktemp /tmp/xray_chk.XXXXXX.txt)
        CHKS_URL="https://github.com/XTLS/Xray-core/releases/download/${LATEST}/checksums.txt"
        if curl -fsSL --connect-timeout 10 "$CHKS_URL" -o "$CHKS_TMP" 2>/dev/null && [[ -s "$CHKS_TMP" ]]; then
            EXPECTED=$(grep -E "^[0-9a-f]{64}[[:space:]]+\*?${ZIP_NAME}$" "$CHKS_TMP" | awk '{print $1}' || true)
            rm -f "$CHKS_TMP"
            if [[ -n "$EXPECTED" ]]; then
                ACTUAL=$(sha256sum "$ZIP_TMP" | awk '{print $1}')
                if [[ "$ACTUAL" != "$EXPECTED" ]]; then
                    log "ERROR: SHA256 не совпал!"
                    exit 1
                fi
                log "INFO: SHA256 OK"
            fi
        else
            rm -f "$CHKS_TMP" 2>/dev/null || true
            log "WARN: checksums.txt недоступен — без верификации"
        fi

        unzip -o "$ZIP_TMP" -d "$EXTRACT_DIR" &>/dev/null || true
        NEW_BIN="${EXTRACT_DIR}/xray"
        [[ ! -x "$NEW_BIN" ]] && log "ERROR: Бинарник не найден в архиве" && exit 1

        CFG_PATH=""
        [[ -f /etc/xray/config.json ]] && CFG_PATH="/etc/xray/config.json"
        [[ -z "$CFG_PATH" && -f /usr/local/etc/xray/config.json ]] && CFG_PATH="/usr/local/etc/xray/config.json"
        if [[ -n "$CFG_PATH" ]]; then
            "$NEW_BIN" run -test -config "$CFG_PATH" &>/dev/null || \
                { log "ERROR: Тест конфига провален — откат"; exit 1; }
        fi

        cp "$NEW_BIN" "$XRAY_BIN" && chmod 755 "$XRAY_BIN"

        # Не перезатираем runetfreedom geo-файлы стандартными из zip XTLS.
        for DAT_FILE in "${EXTRACT_DIR}"/*.dat; do
            [[ -f "$DAT_FILE" ]] || continue
            DAT_NAME=$(basename "$DAT_FILE")
            DEST="/usr/local/share/xray/${DAT_NAME}"
            THRESHOLD=0
            [[ "$DAT_NAME" == "geosite.dat" ]] && THRESHOLD=$((10 * 1024 * 1024))
            [[ "$DAT_NAME" == "geoip.dat"   ]] && THRESHOLD=$((15 * 1024 * 1024))
            if [[ "$THRESHOLD" -gt 0 && -f "$DEST" ]]; then
                DEST_SIZE=$(stat -c%s "$DEST" 2>/dev/null || echo 0)
                if [[ "$DEST_SIZE" -ge "$THRESHOLD" ]]; then
                    log "INFO: Сохранён runetfreedom ${DAT_NAME} — zip пропущен"
                    continue
                fi
            fi
            cp "$DAT_FILE" "$DEST" 2>/dev/null || true
        done

        systemctl restart xray 2>/dev/null || true
        # Ждём запуска до 15 секунд (по 3 сек × 5 попыток)
        XRAY_OK=0
        for _i in 1 2 3 4 5; do
            sleep 3
            if systemctl is-active --quiet xray 2>/dev/null; then
                XRAY_OK=1
                break
            fi
        done

        if [[ "$XRAY_OK" -eq 0 ]]; then
            log "ERROR: Xray не запустился за 15 сек — откат к $CURRENT"
            cp "$BACKUP" "$XRAY_BIN" && chmod 755 "$XRAY_BIN" || true
            systemctl restart xray 2>/dev/null || true
            python3 "$(readlink -f "$0" 2>/dev/null || echo "$0")" --tg-event xray_down "🔴 Autoupdate ОШИБКА: Xray не запустился после $LATEST — откат к $CURRENT" 2>/dev/null || true
            exit 1
        fi

        NEW_VER=$("$XRAY_BIN" version 2>&1 | head -1 | grep -oE '[0-9]+\.[0-9]+\.[0-9]+' | head -1 || true)
        log "OK: Обновлён $CURRENT → v${NEW_VER:-?}. Бэкап: $BACKUP"
        INSTALLER=$(cat /var/lib/xray-installer/installer_path 2>/dev/null || echo "")
        [[ -n "$INSTALLER" ]] && python3 "$INSTALLER" --tg-event xray_up "✅ Autoupdate: Xray обновлён $CURRENT → v${NEW_VER:-?}" 2>/dev/null || true
    """).lstrip())
    agent.chmod(0o700)

    Path("/etc/systemd/system/xray-autoupdate.service").write_text(textwrap.dedent("""\
        [Unit]
        Description=Xray-core Auto-Update
        After=network-online.target
        Wants=network-online.target

        [Service]
        Type=oneshot
        ExecStart=/usr/local/bin/xray-autoupdate.sh
        StandardOutput=journal
        StandardError=journal
        TimeoutStartSec=300
        SuccessExitStatus=0 1
    """))

    Path("/etc/systemd/system/xray-autoupdate.timer").write_text(textwrap.dedent("""\
        [Unit]
        Description=Xray-core Auto-Update Timer

        [Timer]
        OnCalendar=*-*-* 03:30:00
        RandomizedDelaySec=1800
        Persistent=true

        [Install]
        WantedBy=timers.target
    """))

    _run(["systemctl", "daemon-reload"], check=False, quiet=True)
    _run(["systemctl", "enable", "xray-autoupdate.timer"], check=False, quiet=True)
    _run(["systemctl", "start",  "xray-autoupdate.timer"], check=False, quiet=True)

    # Сохраняем путь к инсталлятору для вызова --tg-event из bash-скриптов
    try:
        _installer_path = Path(sys.argv[0]).resolve()
        Path("/var/lib/xray-installer").mkdir(parents=True, exist_ok=True)
        Path("/var/lib/xray-installer/installer_path").write_text(str(_installer_path))
    except Exception:
        pass

    success("Автообновление Xray настроено (ежедневно 03:30)")
    dim("  Лог: /var/log/xray-autoupdate.log")
    dim("  Бэкапы: /var/backups/xray/binaries/ (5 последних)")

# =============================================================================
#  УПРАВЛЕНИЕ ПОЛЬЗОВАТЕЛЯМИ
# =============================================================================
def _users_get_config() -> Path:
    for p in (Path("/etc/xray/config.json"),
              Path("/usr/local/etc/xray/config.json")):
        if p.exists():
            return p
    die("Конфиг Xray не найден. Сначала выполните установку.")


def _users_apply_config(cfg: Path) -> None:
    """
    Применяет изменённый config.json к Xray.
    Делегирует в _xray_safe_apply_config (test → backup → restart → rollback).
    """
    _xray_safe_apply_config(cfg)


def _users_gen_link(cfg: Path, uuid_str: str, email: str) -> str:
    try:
        with cfg.open() as f:
            c = json.load(f)
        inb = c.get("inbounds", [{}])[0]
        ss  = inb.get("streamSettings", {})
        net = ss.get("network", "tcp")
        domain = ""
        port   = inb.get("port", 443)
        import urllib.parse
        _, _, _flag = get_server_country_cached()
        _flag_prefix = f"{_flag} " if _flag and _flag != "🌐" else ""
        label  = _flag_prefix + urllib.parse.quote(email)

        if net == "xhttp":
            tls_s  = ss.get("tlsSettings", {})
            xhttp_s = ss.get("xhttpSettings", {})
            domain = tls_s.get("serverName", "")
            path   = xhttp_s.get("path", "/")
            mode   = xhttp_s.get("mode", "streamup")
            path_enc = urllib.parse.quote(path, safe="/")
            return (f"vless://{uuid_str}@{domain}:{port}"
                    f"?type=xhttp&security=tls&sni={domain}"
                    f"&path={path_enc}&mode={mode}"
                    f"&fp=chrome#{label}")
        else:
            rs     = ss.get("realitySettings", {})
            sni    = (rs.get("serverNames") or [""])[0]
            pbk    = rs.get("publicKey", "")
            sids   = rs.get("shortIds", [""])
            sid    = sids[0] if sids else ""
            # host — реальный адрес сервера (PARAM_DOMAIN или IP), sni — домен маскировки
            host   = PARAM_DOMAIN or get_server_ip("4") or sni
            return (f"vless://{uuid_str}@{host}:{port}"
                    f"?type=tcp&security=reality&pbk={pbk}"
                    f"&fp=chrome&sni={sni}&sid={sid}"
                    f"&flow=xtls-rprx-vision#{label}")
    except Exception as e:
        log_to_file("WARN", str(e))
        return ""


def do_user_list() -> None:
    cfg = _users_get_config()
    _box_top("СПИСОК ПОЛЬЗОВАТЕЛЕЙ")
    try:
        with cfg.open() as f:
            c = json.load(f)
        clients = c.get("inbounds", [{}])[0].get("settings", {}).get("clients", [])
        if not clients:
            _box_row(f"  {DIM}Пользователи не найдены.{NC}")
        else:
            _box_row(f"  {'N':<4} {'Email/имя':<30} {'UUID':<38} {'Flow':<20}")
            _box_bottom()
            print("  " + "─" * 96)
            for i, cl in enumerate(clients, 1):
                print(f"  {i:<4} {cl.get('email','—'):<30} "
                      f"{cl.get('id','—'):<38} {cl.get('flow','—'):<20}")
    except Exception:
        warn("Не удалось прочитать конфиг")
    print()


def do_user_add() -> None:
    cfg = _users_get_config()
    print()
    print()
    _box_top(f"Добавление пользователя")
    _box_row()
    _box_row()

    # Email
    _box_bottom()
    while True:
        new_email = input(f"{CYAN}Email/имя пользователя:{NC} ").strip()
        if not new_email:
            warn("Имя не может быть пустым")
            continue
        if ' ' in new_email:
            warn("Имя не должно содержать пробелов")
            continue
        try:
            with cfg.open() as f:
                c = json.load(f)
            clients = (c.get("inbounds", [{}])[0]
                       .get("settings", {}).get("clients", []))
            if any(cl.get("email", "") == new_email for cl in clients):
                warn(f"Пользователь '{new_email}' уже существует")
                continue
        except Exception:
            pass
        break

    # UUID
    auto_uuid = gen_uuid()
    new_uuid_in = input(f"{CYAN}UUID [{auto_uuid}]:{NC} ").strip()
    new_uuid = new_uuid_in or auto_uuid
    if not re.match(r'^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$', new_uuid):
        warn("Неверный UUID, используем авто")
        new_uuid = auto_uuid

    try:
        with cfg.open() as f:
            c = json.load(f)
        # Определяем протокол из конфига: xHTTP не использует flow xtls-rprx-vision
        net = (c.get("inbounds", [{}])[0]
               .get("streamSettings", {}).get("network", "tcp"))
        new_client: dict = {"id": new_uuid, "email": new_email}
        if net != "xhttp" and XTLS_FLOW:
            new_client["flow"] = XTLS_FLOW
        c["inbounds"][0]["settings"]["clients"].append(new_client)
        with cfg.open('w') as f:
            json.dump(c, f, indent=2, ensure_ascii=False)
    except Exception as e:
        warn(f"Ошибка добавления пользователя: {e}")

    success(f"Пользователь '{new_email}' добавлен")

    link = _users_gen_link(cfg, new_uuid, new_email)
    if link:
        print(f"{BOLD}VLESS ссылка:{NC}")
        _box_link(link)
        _show_qr(link, new_email, f"/root/vless_qr_{new_email}.png")
        link_file = Path(f"/root/vless_link_{new_email}.txt")
        link_file.write_text(link)
        link_file.chmod(0o600)
        success(f"Ссылка сохранена: {link_file}")
    else:
        _box_bottom()
    _users_apply_config(cfg)


def do_user_delete() -> None:
    cfg = _users_get_config()
    do_user_list()
    target = input(f"{CYAN}Email или UUID для удаления:{NC} ").strip()
    if not target:
        warn("Отмена")
        return

    try:
        with cfg.open() as f:
            c = json.load(f)
        clients = c["inbounds"][0]["settings"]["clients"]
        before  = len(clients)
        removed = [cl for cl in clients
                   if cl.get("email", "") == target or cl.get("id", "") == target]
        new_clients = [cl for cl in clients
                       if cl.get("email", "") != target and cl.get("id", "") != target]
        after = len(new_clients)

        if before == after:
            warn(f"Пользователь '{target}' не найден")
            return
        if after == 0:
            warn("Нельзя удалить последнего пользователя")
            return

        c["inbounds"][0]["settings"]["clients"] = new_clients
        with cfg.open('w') as f:
            json.dump(c, f, indent=2, ensure_ascii=False)

        del_email = removed[0].get("email", "") if removed else target
        success(f"Пользователь '{del_email}' удалён")
        for p in (f"/root/vless_link_{del_email}.txt",
                  f"/root/vless_qr_{del_email}.png"):
            Path(p).unlink(missing_ok=True)
        _users_apply_config(cfg)
    except Exception as e:
        warn(f"Ошибка при удалении: {e}")


def do_user_show_link() -> None:
    cfg = _users_get_config()
    do_user_list()
    target = input(f"{CYAN}Email или UUID:{NC} ").strip()
    if not target:
        warn("Отмена")
        return

    try:
        with cfg.open() as f:
            c = json.load(f)
        clients = (c.get("inbounds", [{}])[0]
                   .get("settings", {}).get("clients", []))
        found = next((cl for cl in clients
                      if cl.get("email", "") == target or cl.get("id", "") == target), None)
    except Exception:
        found = None

    if not found:
        warn(f"Пользователь '{target}' не найден")
        return

    u_email = found.get("email", "")
    u_uuid  = found.get("id", "")
    link = _users_gen_link(cfg, u_uuid, u_email)
    if link:
        print(f"{BOLD}VLESS ссылка для '{u_email}':{NC}")
        _box_link(link)
        _show_qr(link, u_email, f"/root/vless_qr_{u_email}.png")


def do_user_menu() -> None:
    if not (Path("/etc/xray/config.json").exists()
            or Path("/usr/local/etc/xray/config.json").exists()):
        die("Xray не установлен.")
    while True:
        _box_top("УПРАВЛЕНИЕ ПОЛЬЗОВАТЕЛЯМИ")
        _box_item("L", f"Список пользователей")
        _box_item("A", f"Добавить пользователя")
        _box_item("D", f"Удалить пользователя")
        _box_item("S", f"Показать ссылку / QR-код")
        _box_item("Q", f"Назад")
        _box_bottom()
        choice = input(f"{CYAN}Выбор:{NC} ").strip().lower()
        if   choice == 'l': do_user_list()
        elif choice == 'a': do_user_add()
        elif choice == 'd': do_user_delete()
        elif choice == 's': do_user_show_link()
        elif choice in ('q', ''):
            return
        else:
            warn("Введите L, A, D, S или Q")

# =============================================================================
#  ГЕНЕРАЦИЯ ССЫЛОК + QR
# =============================================================================
def _show_qr(link: str, label: str, png_path: str) -> None:
    """Выводит QR-код внутри рамки бокса."""
    print()
    _box_top(f"QR-код [{label}]")
    _box_row(f"  {CYAN}Отсканируйте в v2rayNG / Hiddify / Nekobox:{NC}")
    _box_sep()

    qrencode = shutil.which("qrencode")
    if qrencode:
        # Выводим QR в терминал — каждая строка через _box_row
        import subprocess as _sp
        # ГОЛУБОЙ QR: используем ANSI256 foreground (цвет модулей) через
        # --foreground / --background если qrencode >= 4.1, иначе оборачиваем
        # строки вывода в ANSI-escape для голубого цвета.
        _QR_COLOR = "\033[96m"   # bright cyan (ANSI 96)
        _QR_RESET = "\033[0m"
        try:
            _qr_proc = _sp.run(
                [qrencode, "-t", "ANSIUTF8", "-m", "1",
                 "--foreground=00BFFF", "--background=000000",
                 "--strict-version", link],
                capture_output=True, text=True
            )
            _qr_lines = _qr_proc.stdout.splitlines()
        except Exception:
            _qr_lines = []
        if not _qr_lines:
            # fallback: пробуем без --foreground (старые версии qrencode)
            try:
                _qr_proc = _sp.run(
                    [qrencode, "-t", "ANSIUTF8", "-m", "1", link],
                    capture_output=True, text=True
                )
                _qr_lines = _qr_proc.stdout.splitlines()
            except Exception:
                _qr_lines = []
        for _ql in _qr_lines:
            # Вставляем QR-строку внутрь рамки с отступом.
            # Если qrencode не поддержал --foreground, оборачиваем в CYAN escape.
            if _QR_COLOR not in _ql and "\033[" not in _ql:
                _box_row(f"  {_QR_COLOR}{_ql}{_QR_RESET}")
            else:
                _box_row(f"  {_ql}")
        # Сохраняем PNG
        r = _run([qrencode, "-t", "PNG", "-o", png_path, "-s", "8", "-m", "4", link],
                 check=False, quiet=True)
        _box_sep()
        if r.returncode == 0:
            _box_ok(f"QR PNG сохранён: {png_path}")
        else:
            _box_warn(f"Не удалось сохранить QR PNG: {png_path}")
    else:
        # Fallback: python3-qrcode
        try:
            import qrcode  # type: ignore
            import io as _io
            qr = qrcode.QRCode(border=1)
            qr.add_data(link)
            qr.make(fit=True)
            # Захватываем ASCII-вывод
            _buf = _io.StringIO()
            import sys as _sys
            _old_stdout = _sys.stdout
            _sys.stdout = _buf
            qr.print_ascii(invert=True)
            _sys.stdout = _old_stdout
            _QR_COLOR = "\033[96m"
            _QR_RESET = "\033[0m"
            for _ql in _buf.getvalue().splitlines():
                _box_row(f"  {_QR_COLOR}{_ql}{_QR_RESET}")
            img = qr.make_image(fill_color='#00BFFF', back_color='black')
            img.save(png_path)
            _box_sep()
            _box_ok(f"QR PNG сохранён: {png_path}")
        except ImportError:
            _box_warn("python3-qrcode не установлен: pip3 install qrcode[pil]")
        except Exception as e:
            _box_warn(f"Ошибка QR: {e}")

    _box_bottom()


def _gen_vless_link(host: str, uuid_str: str, pbk: str,
                    sid: str, domain: str, fp: str = "chrome",
                    proto: str = "reality",
                    xhttp_path: str = "/", xhttp_mode: str = "streamup",
                    port: int = 443) -> str:
    """Генерирует VLESS-ссылку для REALITY или xHTTP TLS."""
    import urllib.parse
    _, _, _flag = get_server_country_cached()
    _flag_prefix = f"{_flag} " if _flag and _flag != "🌐" else ""
    label = _flag_prefix + urllib.parse.quote(domain)
    if proto == "xhttp":
        path_enc = urllib.parse.quote(xhttp_path, safe="/")
        return (f"vless://{uuid_str}@{host}:{port}"
                f"?type=xhttp&security=tls&sni={domain}"
                f"&path={path_enc}&mode={xhttp_mode}"
                f"&fp={fp}#{label}")
    else:
        return (f"vless://{uuid_str}@{host}:{port}"
                f"?type=tcp&security=reality&pbk={pbk}"
                f"&fp={fp}&sni={domain}&sid={sid}"
                f"&flow=xtls-rprx-vision#{label}")


def generate_client_links() -> None:
    global _BOX_W
    _BOX_W = _get_box_width()
    print()
    print()
    _box_top(f"Ссылки для подключения")
    _box_row()
    fp = "chrome"
    proto = PROTOCOL_MODE  # "reality" или "xhttp"
    # При AWG SNI = домен маскировки, при обычном REALITY SNI = собственный домен
    _sni = PARAM_REALITY_DEST if (AWG_EXIT_ENABLED and PARAM_REALITY_DEST) else PARAM_DOMAIN

    ipv4 = get_server_ip("4")
    if ipv4:
        link4 = _gen_vless_link(
            ipv4, PARAM_UUID, PARAM_PUBLIC_KEY, PARAM_SHORTID, _sni, fp,
            proto=proto, xhttp_path=XHTTP_PATH, xhttp_mode=XHTTP_MODE,
            port=SERVER_PORT,
        )
        print()
        print(f"{GREEN}📡 IPv4 ссылка:{NC}")
        _box_link(link4)
        link_file = Path("/root/vless_link.txt")
        link_file.write_text(link4)
        link_file.chmod(0o600)
        print()
        _show_qr(link4, "IPv4", "/root/vless_qr_ipv4.png")

    if IS_IPV6_AVAILABLE and IPV6_PREFLIGHT:
        link6 = _gen_vless_link(
            f"[{IPV6_PREFLIGHT}]", PARAM_UUID, PARAM_PUBLIC_KEY, PARAM_SHORTID, _sni, fp,
            proto=proto, xhttp_path=XHTTP_PATH, xhttp_mode=XHTTP_MODE,
            port=SERVER_PORT,
        )
        print()
        print(f"{CYAN}🌐 IPv6 ссылка:{NC}")
        _box_link(link6)
        link6_file = Path("/root/vless_link_ipv6.txt")
        link6_file.write_text(link6)
        link6_file.chmod(0o600)
        print()
        _show_qr(link6, "IPv6", "/root/vless_qr_ipv6.png")

    link_ds = _gen_vless_link(
        PARAM_DOMAIN, PARAM_UUID, PARAM_PUBLIC_KEY, PARAM_SHORTID, _sni, fp,
        proto=proto, xhttp_path=XHTTP_PATH, xhttp_mode=XHTTP_MODE,
        port=SERVER_PORT,
    )
    print()
    print(f"{MAGENTA}🔄 Domain (DualStack) ссылка:{NC}")
    _box_link(link_ds)
    print()
    _show_qr(link_ds, "Domain/DualStack", "/root/vless_qr.png")
    print()

    _box_row()
    proto_label = f"xHTTP TLS ({XHTTP_MODE})" if proto == "xhttp" else "VLESS+REALITY"
    _box_row(f"{BLUE}💡 Протокол: {proto_label}{NC}")
    _box_row(f"{BLUE}💡 Совет:{NC} Отсканируйте QR в v2rayNG, Hiddify, FoXray, Nekobox")
    _box_wrap_msg(f"   {DIM}Файлы QR:{NC} ", 12, "/root/vless_qr.png  /root/vless_qr_ipv4.png  /root/vless_qr_ipv6.png")
    _box_row()
    _box_bottom()

# =============================================================================
#  УДАЛЕНИЕ
# =============================================================================
def do_uninstall() -> None:
    _box_top("УДАЛЕНИЕ VLESS REALITY")
    _box_warn("Будет удалено: Xray, Nginx, сайт, правила UFW")
    _box_row()
    _box_bottom()
    uninst_domain = input(f"{YELLOW}Домен для подтверждения удаления:{NC} ").strip()
    if not uninst_domain:
        _box_top("УДАЛЕНИЕ VLESS REALITY")
        _box_warn("Домен не введён. Отмена.")
        _box_bottom()
        sys.exit(0)
    if not re.match(r'^[a-zA-Z0-9][a-zA-Z0-9._-]*\.[a-zA-Z]{2,}$', uninst_domain):
        die(f"Некорректный формат домена: '{uninst_domain}'")

    confirm = input(f"{RED}Удалить? [y/N]:{NC} ").strip().lower()
    if confirm != 'y':
        _box_top("УДАЛЕНИЕ VLESS REALITY")
        _box_info("Отменено.")
        _box_bottom()
        sys.exit(0)

    _box_top("УДАЛЕНИЕ VLESS REALITY")

    for svc in ("xray", "nginx", "dnscrypt-proxy"):
        _run(["systemctl", "stop",    svc], check=False, quiet=True)
    for svc in ("xray", "dnscrypt-proxy"):
        _run(["systemctl", "disable", svc], check=False, quiet=True)

    # Удаление Xray через официальный скрипт
    with tempfile.NamedTemporaryFile(suffix=".sh", delete=False) as tmp:
        tmp_path = Path(tmp.name)
    try:
        r = _run([
            "curl", "-fsSL", "--connect-timeout", "10",
            "https://github.com/XTLS/Xray-install/raw/main/install-release.sh",
            "-o", str(tmp_path),
        ], check=False, quiet=True)
        if r.returncode == 0 and tmp_path.stat().st_size > 0:
            _run(["bash", str(tmp_path), "remove"], check=False, quiet=True)
    finally:
        tmp_path.unlink(missing_ok=True)

    for p in (XRAY_BIN, XRAY_SERVICE):
        Path(p).unlink(missing_ok=True)
    # Зачищаем drop-in директорию xray (оставляемую официальным bash-установщиком)
    shutil.rmtree("/etc/systemd/system/xray.service.d", ignore_errors=True)
    for d in (Path("/usr/local/etc/xray"), CONFIG_DIR,
              Path("/var/log/xray"), Path("/var/lib/xray")):
        shutil.rmtree(d, ignore_errors=True)

    # Удаление DNSCrypt
    _box_info("Удаление DNSCrypt-proxy...")
    DNSCRYPT_BIN.unlink(missing_ok=True)
    DNSCRYPT_SERVICE.unlink(missing_ok=True)
    shutil.rmtree(DNSCRYPT_CONF_DIR, ignore_errors=True)
    for log_f in ("/var/log/dnscrypt-proxy.log",
                  "/var/log/dnscrypt-blocked.log",
                  "/var/log/dnscrypt-proxy-blocked.log"):
        Path(log_f).unlink(missing_ok=True)

    override = Path("/etc/systemd/system/nginx.service.d/after-xray.conf")
    override.unlink(missing_ok=True)
    try:
        override.parent.rmdir()
    except Exception:
        pass
    _run(["systemctl", "daemon-reload"], check=False, quiet=True)

    if PKG_MGR == "apt":
        _run(["apt-get", "remove", "--purge", "-y", "nginx", "nginx-common"],
             check=False, quiet=True)
        _run(["apt-get", "autoremove", "-y"], check=False, quiet=True)
    else:
        _run(["dnf", "remove", "-y", "nginx"], check=False, quiet=True)

    shutil.rmtree("/etc/nginx", ignore_errors=True)
    shutil.rmtree("/var/log/nginx", ignore_errors=True)
    if uninst_domain:
        shutil.rmtree(f"/var/www/{uninst_domain}", ignore_errors=True)
    _box_row()
    _box_bottom()


