TG_CONFIG_FILE = Path("/var/lib/xray-installer/telegram.json")

def _tg_load() -> dict:
    """Загружает Telegram-конфиг (token, chat_id, события)."""
    try:
        if TG_CONFIG_FILE.exists():
            return json.loads(TG_CONFIG_FILE.read_text())
    except Exception:
        pass
    return {}


def _tg_save(cfg: dict) -> None:
    TG_CONFIG_FILE.parent.mkdir(parents=True, exist_ok=True)
    TG_CONFIG_FILE.write_text(json.dumps(cfg, indent=2, ensure_ascii=False))
    TG_CONFIG_FILE.chmod(0o600)


def tg_send(msg: str, token: str = "", chat_id: str = "") -> bool:
    """
    Отправляет сообщение в Telegram.
    Если token/chat_id не переданы — берёт из TG_CONFIG_FILE.
    Возвращает True при успехе.
    """
    if not token or not chat_id:
        cfg = _tg_load()
        token   = cfg.get("token", "")
        chat_id = cfg.get("chat_id", "")
    if not token or not chat_id:
        return False
    try:
        r = _run([
            "curl", "-s", "-o", "/dev/null", "-w", "%{http_code}",
            "-m", "10",
            f"https://api.telegram.org/bot{token}/sendMessage",
            "-d", f"chat_id={chat_id}",
            "-d", f"text={msg}",
            "-d", "parse_mode=HTML",
        ], capture=True, check=False)
        return r.stdout.strip() == "200"
    except Exception:
        return False


def _tg_notify_event(event: str, detail: str = "") -> None:
    """Отправляет уведомление если соответствующее событие включено."""
    cfg = _tg_load()
    if not cfg.get("token") or not cfg.get("chat_id"):
        return
    events = cfg.get("events", {})
    if not events.get(event, True):
        return
    hostname = ""
    try:
        hostname = _run(["hostname", "-s"], capture=True, check=False).stdout.strip()
    except Exception:
        pass
    ts = datetime.now().strftime("%d.%m.%Y %H:%M")
    icons = {
        "xray_down":    "🔴",
        "xray_up":      "🟢",
        "cert_expire":  "🔒",
        "traffic_limit":"⚠️",
        "user_connect": "👤",
        "health_report":"📋",
        "node_down":    "📡",
    }
    icon = icons.get(event, "ℹ️")
    text = f"{icon} <b>[{hostname}]</b> {detail}\n<i>{ts}</i>"
    tg_send(text)
    log_to_file("INFO", f"TG notify: {event} — {detail}")


def do_manage_telegram() -> None:
    """Меню настройки Telegram-уведомлений."""
    while True:
        os.system("clear")
        cfg = _tg_load()
        token   = cfg.get("token", "")
        chat_id = cfg.get("chat_id", "")
        events  = cfg.get("events", {})
        configured = bool(token and chat_id)

        print()
        _box_top(f"Telegram-уведомления")
        _box_row(f"  Статус:  {''+GREEN+'НАСТРОЕН'+NC if configured else ''+YELLOW+'НЕ НАСТРОЕН'+NC}")
        if configured:
            _box_row(f"  Токен:   {DIM}{token[:10]}...{NC}")
            _box_row(f"  Chat ID: {CYAN}{chat_id}{NC}")
            _box_row(f"  {BOLD}Включённые события:{NC}")
            event_labels = {
                "xray_down":    "Xray упал / не отвечает",
                "xray_up":      "Xray восстановился",
                "cert_expire":  "Сертификат истекает (< 30 дней)",
                "traffic_limit":"Трафик пользователя превысил лимит",
                "health_report":"Ежедневный health-отчёт (08:00)",
                "node_down":    "Exit-нода недоступна",
            }
            for ev, label in event_labels.items():
                en = events.get(ev, True)
                col = GREEN if en else DIM
                _box_row(f"    {col}{'✓' if en else '✗'}{NC} {label}")
        _box_item("1", f"{'Изменить' if configured else 'Настроить'} бот-токен и Chat ID")
        _box_item("2", f"Тест — отправить тестовое сообщение")
        _box_item("3", f"Включить/выключить отдельные события")
        _box_item("4", f"Установить cron-агент мониторинга Xray")
        _box_item("5", f"{RED}Отключить Telegram{NC} (удалить конфиг)")
        _box_item("Q", f"Назад")
        _box_bottom()
        ch = input(f"{CYAN}Выбор:{NC} ").strip().lower()

        if ch == "1":
            print()
            new_token = input(f"  Bot Token (Enter = оставить текущий): ").strip()
            if new_token:
                cfg["token"] = new_token
            new_chat = input(f"  Chat ID (Enter = оставить текущий): ").strip()
            if new_chat:
                cfg["chat_id"] = new_chat
            if "events" not in cfg:
                cfg["events"] = {k: True for k in
                    ["xray_down","xray_up","cert_expire","traffic_limit","health_report","node_down"]}
            _tg_save(cfg)
            success("Конфиг сохранён")
            input(f"{BLUE}Нажмите Enter...{NC}")

        elif ch == "2":
            print()
            if not cfg.get("token") or not cfg.get("chat_id"):
                warn("Сначала настройте токен и Chat ID [1]")
            else:
                info("Отправка тестового сообщения...")
                ok = tg_send(
                    "✅ <b>VLESS Installer</b>: тестовое сообщение. Уведомления работают!",
                    cfg["token"], cfg["chat_id"]
                )
                if ok:
                    success("Сообщение отправлено!")
                else:
                    warn("Ошибка отправки — проверьте токен и chat_id")
            input(f"{BLUE}Нажмите Enter...{NC}")

        elif ch == "3":
            ev_keys = ["xray_down","xray_up","cert_expire","traffic_limit","health_report","node_down"]
            ev_labels = [
                "Xray упал", "Xray восстановился", "Сертификат истекает",
                "Лимит трафика", "Daily health-отчёт", "Exit-нода недоступна",
            ]
            events = cfg.get("events", {k: True for k in ev_keys})
            print()
            _box_top("Уведомления — вкл/выкл событий")
            for i, (k, lbl) in enumerate(zip(ev_keys, ev_labels), 1):
                en = events.get(k, True)
                _box_item(f"{i}", f"{''+GREEN+'[ВКЛ]'+NC if en else ''+DIM+'[ВЫКЛ]'+NC} {lbl}")
            _box_bottom()
            raw = input("  Номер для переключения (Enter = выход): ").strip()
            if raw.isdigit() and 1 <= int(raw) <= len(ev_keys):
                k = ev_keys[int(raw)-1]
                events[k] = not events.get(k, True)
                cfg["events"] = events
                _tg_save(cfg)
                success(f"{'Включено' if events[k] else 'Выключено'}: {ev_labels[int(raw)-1]}")
            input(f"{BLUE}Нажмите Enter...{NC}")

        elif ch == "4":
            _tg_install_monitor_cron()
            input(f"{BLUE}Нажмите Enter...{NC}")

        elif ch == "5":
            ans = input(f"  {RED}Удалить конфиг Telegram? [y/N]:{NC} ").strip().lower()
            if ans == "y":
                TG_CONFIG_FILE.unlink(missing_ok=True)
                Path("/etc/cron.d/xray-tg-monitor").unlink(missing_ok=True)
                Path("/usr/local/bin/xray-tg-monitor.sh").unlink(missing_ok=True)
                success("Telegram-конфиг удалён")
            input(f"{BLUE}Нажмите Enter...{NC}")

        elif ch in ("q", ""):
            break
        else:
            warn("Неверный выбор")
            time.sleep(1)


def _tg_install_monitor_cron() -> None:
    """Устанавливает cron-скрипт мониторинга: Xray, сертификат."""
    cfg = _tg_load()
    token   = cfg.get("token", "")
    chat_id = cfg.get("chat_id", "")
    if not token or not chat_id:
        warn("Telegram не настроен — сначала укажите токен и Chat ID")
        return

    domain = ""
    try:
        if STATE_FILE.exists():
            domain = json.loads(STATE_FILE.read_text()).get("domain", "")
    except Exception:
        pass

    script = textwrap.dedent(f"""\
        #!/bin/bash
        # Xray TG Monitor (VLESS Installer)
        TOKEN="{token}"
        CHAT="{chat_id}"
        DOMAIN="{domain}"
        LOG="/var/log/xray-tg-monitor.log"
        DATE=$(date '+%Y-%m-%d %H:%M:%S')
        HOST=$(hostname -s 2>/dev/null || echo "server")
        STATE_FILE="/var/lib/xray-installer/tg_monitor.state"
        mkdir -p "$(dirname $STATE_FILE)"

        send_tg() {{
            curl -s -o /dev/null -m 10 \\
                "https://api.telegram.org/bot$TOKEN/sendMessage" \\
                -d "chat_id=$CHAT" -d "text=$1" -d "parse_mode=HTML" || true
        }}

        get_state() {{ grep "^$1=" "$STATE_FILE" 2>/dev/null | cut -d= -f2; }}
        set_state() {{
            grep -v "^$1=" "$STATE_FILE" > /tmp/tg_state.tmp 2>/dev/null
            echo "$1=$2" >> /tmp/tg_state.tmp
            mv /tmp/tg_state.tmp "$STATE_FILE"
        }}

        IS_ACTIVE=$(systemctl is-active xray 2>/dev/null)
        PREV_ACTIVE=$(get_state xray_active)
        if [ "$IS_ACTIVE" != "active" ]; then
            if [ "$PREV_ACTIVE" != "down" ]; then
                send_tg "🔴 <b>[$HOST]</b> Xray сервис упал!&#10;<i>$DATE</i>"
                echo "[$DATE] Xray DOWN alert sent" >> "$LOG"
                set_state xray_active "down"
            fi
        else
            if [ "$PREV_ACTIVE" = "down" ]; then
                send_tg "🟢 <b>[$HOST]</b> Xray восстановился&#10;<i>$DATE</i>"
                echo "[$DATE] Xray UP recovery alert sent" >> "$LOG"
            fi
            set_state xray_active "active"
        fi

        if [ -n "$DOMAIN" ]; then
            CERT="/etc/letsencrypt/live/$DOMAIN/fullchain.pem"
            if [ -f "$CERT" ]; then
                EXPIRY=$(openssl x509 -in "$CERT" -noout -enddate 2>/dev/null | cut -d= -f2)
                EXPIRY_EPOCH=$(date -d "$EXPIRY" +%s 2>/dev/null || echo 0)
                NOW=$(date +%s)
                DAYS_LEFT=$(( (EXPIRY_EPOCH - NOW) / 86400 ))
                PREV_CERT=$(get_state cert_days)
                if [ "$DAYS_LEFT" -lt 30 ] && [ "$DAYS_LEFT" -gt 0 ]; then
                    if [ "$PREV_CERT" != "$DAYS_LEFT" ]; then
                        send_tg "🔒 <b>[$HOST]</b> Сертификат истекает через <b>$DAYS_LEFT дн.</b>&#10;Домен: $DOMAIN&#10;<i>$DATE</i>"
                        echo "[$DATE] Cert expire in $DAYS_LEFT days alert sent" >> "$LOG"
                        set_state cert_days "$DAYS_LEFT"
                    fi
                else
                    set_state cert_days ""
                fi
            fi
        fi
    """)
    script_path = Path("/usr/local/bin/xray-tg-monitor.sh")
    script_path.write_text(script)
    script_path.chmod(0o750)
    cron_path = Path("/etc/cron.d/xray-tg-monitor")
    cron_path.write_text(f"*/5 * * * * root {script_path} >> /var/log/xray-tg-monitor.log 2>&1\n")
    cron_path.chmod(0o644)
    success("Cron-агент мониторинга установлен (каждые 5 мин)")
    success("Лог: /var/log/xray-tg-monitor.log")


