import threading
import http.server
import urllib.parse


# =============================================================================
#  МОДУЛЬ 3: ВРЕМЕННЫЕ ПОЛЬЗОВАТЕЛИ (TTL)
#  Хранение: /var/lib/xray-installer/ttl_users.json
#  Формат записи:
#    {
#      "email": "guest@xray",
#      "expires_at": "2025-12-31T23:59:59+00:00",   # ISO-8601 UTC
#      "days": 7,                                     # исходный TTL
#      "notified_24h": false                          # флаг — алерт за 24ч отправлен
#    }
#  Cron-агент: /usr/local/bin/xray-ttl-check.sh
#  Cron-файл:  /etc/cron.d/xray-ttl-check  (каждые 30 мин)
# =============================================================================

TTL_FILE        = Path("/var/lib/xray-installer/ttl_users.json")
TTL_CRON_SCRIPT = Path("/usr/local/bin/xray-ttl-check.sh")
TTL_CRON_FILE   = Path("/etc/cron.d/xray-ttl-check")
TTL_LOG         = Path("/var/log/xray-ttl.log")


# ── helpers ──────────────────────────────────────────────────────────────────

def _ttl_load() -> dict:
    """Загружает TTL-базу. Ключ — email пользователя."""
    try:
        if TTL_FILE.exists():
            return json.loads(TTL_FILE.read_text())
    except Exception:
        pass
    return {}


def _ttl_save(data: dict) -> None:
    TTL_FILE.parent.mkdir(parents=True, exist_ok=True)
    TTL_FILE.write_text(json.dumps(data, indent=2, ensure_ascii=False))
    TTL_FILE.chmod(0o600)


def _ttl_expires_str(iso: str) -> str:
    """Возвращает строку вида '3д 14ч' до истечения или 'ИСТЁК'."""
    try:
        exp = datetime.fromisoformat(iso)
        now = datetime.now(timezone.utc)
        if exp.tzinfo is None:
            exp = exp.replace(tzinfo=timezone.utc)
        delta = exp - now
        total = int(delta.total_seconds())
        if total <= 0:
            return "ИСТЁК"
        days  = total // 86400
        hours = (total % 86400) // 3600
        mins  = (total % 3600)  // 60
        if days > 0:
            return f"{days}д {hours}ч"
        if hours > 0:
            return f"{hours}ч {mins}м"
        return f"{mins}м"
    except Exception:
        return "?"


def _ttl_is_expired(iso: str) -> bool:
    try:
        exp = datetime.fromisoformat(iso)
        if exp.tzinfo is None:
            exp = exp.replace(tzinfo=timezone.utc)
        return datetime.now(timezone.utc) >= exp
    except Exception:
        return False


def _ttl_expires_within_hours(iso: str, hours: int) -> bool:
    """True если пользователь истечёт в течение `hours` часов."""
    try:
        exp = datetime.fromisoformat(iso)
        if exp.tzinfo is None:
            exp = exp.replace(tzinfo=timezone.utc)
        now = datetime.now(timezone.utc)
        delta = (exp - now).total_seconds()
        return 0 < delta <= hours * 3600
    except Exception:
        return False


# ── добавление TTL к пользователю ────────────────────────────────────────────

def _ttl_set(email: str, days: int) -> None:
    """
    Устанавливает TTL для существующего пользователя.
    Если запись уже есть — перезаписывает (продление / сокращение).
    """
    data = _ttl_load()
    expires_at = (
        datetime.now(timezone.utc).replace(microsecond=0)
        + __import__("datetime").timedelta(days=days)
    ).isoformat()
    data[email] = {
        "email":        email,
        "expires_at":   expires_at,
        "days":         days,
        "notified_24h": False,
    }
    _ttl_save(data)
    log_to_file("INFO", f"TTL set: {email} expires {expires_at} ({days}d)")


def _ttl_remove(email: str) -> None:
    """Снимает TTL-ограничение с пользователя (делает постоянным)."""
    data = _ttl_load()
    if email in data:
        del data[email]
        _ttl_save(data)
        log_to_file("INFO", f"TTL removed: {email}")


# ── блокировка / разблокировка ───────────────────────────────────────────────

BLOCKED_FILE = Path("/var/lib/xray-installer/blocked_users.json")


def _blocked_load() -> dict:
    """Загружает базу заблокированных. Ключ — email, значение — запись."""
    try:
        if BLOCKED_FILE.exists():
            return json.loads(BLOCKED_FILE.read_text())
    except Exception:
        pass
    return {}


def _blocked_save(data: dict) -> None:
    BLOCKED_FILE.parent.mkdir(parents=True, exist_ok=True)
    BLOCKED_FILE.write_text(json.dumps(data, indent=2, ensure_ascii=False))
    BLOCKED_FILE.chmod(0o600)


def _ttl_block_user(email: str, reason: str = "ttl_expired") -> bool:
    """
    Блокирует пользователя: убирает его UUID из конфига Xray и перезапускает
    сервис, но сохраняет запись в users.json с флагом blocked=true.
    Это позволяет разблокировать / продлить срок без повторного добавления.

    Возвращает True если пользователь найден и заблокирован.
    """
    users = _users_load()
    target = next(
        (u for u in users if u.get("email") == email or u.get("uuid") == email),
        None,
    )
    if not target:
        log_to_file("WARN", f"_ttl_block_user: {email} not found in users.json")
        return False

    # Помечаем заблокированным в users.json
    target["blocked"]    = True
    target["blocked_at"] = datetime.now(timezone.utc).replace(microsecond=0).isoformat()
    target["block_reason"] = reason
    _users_save(users)

    # Сохраняем в отдельную базу заблокированных (для быстрого просмотра)
    blocked = _blocked_load()
    blocked[email] = {
        "email":       email,
        "uuid":        target.get("uuid", ""),
        "name":        target.get("name", ""),
        "blocked_at":  target["blocked_at"],
        "reason":      reason,
    }
    _blocked_save(blocked)

    # Применяем в Xray только НЕзаблокированных пользователей
    active_users = [u for u in users if not u.get("blocked")]
    _users_apply_to_config(active_users)

    log_to_file("INFO", f"User blocked: {email} (reason={reason})")
    return True


def _ttl_unblock_user(email: str) -> bool:
    """
    Снимает блокировку: возвращает UUID пользователя в конфиг Xray.
    Возвращает True если разблокировка прошла успешно.
    """
    users = _users_load()
    target = next(
        (u for u in users if u.get("email") == email or u.get("uuid") == email),
        None,
    )
    if not target:
        log_to_file("WARN", f"_ttl_unblock_user: {email} not found in users.json")
        return False

    # Снимаем флаги блокировки
    target.pop("blocked",      None)
    target.pop("blocked_at",   None)
    target.pop("block_reason", None)
    _users_save(users)

    # Убираем из базы заблокированных
    blocked = _blocked_load()
    if email in blocked:
        del blocked[email]
        _blocked_save(blocked)

    # Применяем всех незаблокированных (включая только что разблокированного)
    active_users = [u for u in users if not u.get("blocked")]
    _users_apply_to_config(active_users)

    log_to_file("INFO", f"User unblocked: {email}")
    return True


def _ttl_is_blocked(email: str) -> bool:
    """True если пользователь с данным email в настоящее время заблокирован."""
    users = _users_load()
    target = next(
        (u for u in users if u.get("email") == email or u.get("uuid") == email),
        None,
    )
    return bool(target and target.get("blocked"))


# ── проверка и блокировка истёкших ───────────────────────────────────────────

def _ttl_check_and_expire() -> int:
    """
    Проверяет все TTL-записи:
      • за 24 ч до истечения — отправляет TG-предупреждение
      • при истечении — БЛОКИРУЕТ пользователя (убирает из Xray, но не удаляет
        из users.json), помечает запись TTL как заблокированную.
        Это позволяет продлить срок и разблокировать без повторного добавления.

    Возвращает количество заблокированных пользователей.
    """
    data    = _ttl_load()
    blocked = 0
    changed = False

    for email, rec in list(data.items()):
        iso = rec.get("expires_at", "")

        # ── алерт за 24 часа ──
        if not rec.get("notified_24h") and _ttl_expires_within_hours(iso, 24):
            left = _ttl_expires_str(iso)
            _tg_notify_event(
                "ttl_expiring",
                f"⏳ Пользователь <b>{email}</b> истекает через <b>{left}</b>",
            )
            log_to_file("INFO", f"TTL 24h warning sent: {email}")
            rec["notified_24h"] = True
            changed = True

        # ── истёк: блокируем (не удаляем) ──
        if _ttl_is_expired(iso) and not rec.get("blocked"):
            ok = _ttl_block_user(email, reason="ttl_expired")
            if ok:
                rec["blocked"] = True
                _tg_notify_event(
                    "ttl_expired",
                    f"🔒 Пользователь <b>{email}</b> заблокирован — срок действия истёк",
                )
                log_to_file("INFO", f"TTL expired: {email} blocked in Xray")
                blocked += 1
            changed = True

    if changed:
        _ttl_save(data)

    return blocked


# ── cron-агент ───────────────────────────────────────────────────────────────

def _ttl_install_cron() -> None:
    """
    Устанавливает cron-агент, вызывающий этот скрипт с флагом --ttl-check.
    Запускается каждые 30 минут от root.
    """
    script = textwrap.dedent(f"""\
        #!/bin/bash
        # Xray TTL User Expiry Check (VLESS Installer)
        LOG="{TTL_LOG}"
        DATE=$(date '+%Y-%m-%d %H:%M:%S')
        echo "[$DATE] TTL check start" >> "$LOG"
        python3 {Path(__file__).resolve()} --ttl-check >> "$LOG" 2>&1
        echo "[$DATE] TTL check done" >> "$LOG"
    """)
    TTL_CRON_SCRIPT.write_text(script)
    TTL_CRON_SCRIPT.chmod(0o750)

    TTL_CRON_FILE.write_text(
        f"*/30 * * * * root {TTL_CRON_SCRIPT} >> {TTL_LOG} 2>&1\n"
    )
    TTL_CRON_FILE.chmod(0o644)
    success(f"Cron-агент TTL установлен (каждые 30 мин) → {TTL_CRON_SCRIPT}")
    success(f"Лог: {TTL_LOG}")


def _ttl_remove_cron() -> None:
    TTL_CRON_FILE.unlink(missing_ok=True)
    TTL_CRON_SCRIPT.unlink(missing_ok=True)
    success("Cron-агент TTL удалён")


def _ttl_cron_active() -> bool:
    return TTL_CRON_FILE.exists()


# ── меню управления ───────────────────────────────────────────────────────────

def do_manage_ttl_users() -> None:
    """
    Меню управления временными пользователями (TTL).
    Интегрируется в подменю пользователей.
    """
    while True:
        os.system("clear")
        print()
        data  = _ttl_load()
        users = _users_load()

        _box_top("⏱  ВРЕМЕННЫЕ ПОЛЬЗОВАТЕЛИ (TTL)")
        _box_row()

        # ── статус cron ──
        cron_ok = _ttl_cron_active()
        cron_str = f"{GREEN}ВКЛЮЧЁН (каждые 30 мин){NC}" if cron_ok \
                   else f"{YELLOW}ОТКЛЮЧЁН{NC}"
        _box_row(f"  Авто-проверка: {cron_str}")
        _box_sep()

        # ── список TTL-пользователей ──
        if not data:
            _box_row(f"  {DIM}Временных пользователей нет{NC}")
        else:
            _box_row(
                f"  {'#':<4} {'Email':<26} {'Истекает':<18} {'Осталось':<10} {'Статус'}"
            )
            _box_row(
                f"  {'─'*4} {'─'*26} {'─'*18} {'─'*10} {'─'*14}"
            )
            for i, (email, rec) in enumerate(data.items(), 1):
                iso      = rec.get("expires_at", "")
                left     = _ttl_expires_str(iso)
                expired  = _ttl_is_expired(iso)
                warn24   = _ttl_expires_within_hours(iso, 24) and not expired
                is_blocked_now = _ttl_is_blocked(email)

                # Форматируем дату без секунд
                try:
                    exp_dt   = datetime.fromisoformat(iso)
                    exp_show = exp_dt.strftime("%Y-%m-%d %H:%M")
                except Exception:
                    exp_show = iso[:16]

                if is_blocked_now:
                    status = f"{RED}ЗАБЛОКИРОВАН{NC}"
                    left_c = f"{RED}{left}{NC}"
                elif expired:
                    status = f"{RED}ИСТЁК{NC}"
                    left_c = f"{RED}{left}{NC}"
                elif warn24:
                    status = f"{YELLOW}скоро{NC}"
                    left_c = f"{YELLOW}{left}{NC}"
                else:
                    status = f"{GREEN}активен{NC}"
                    left_c = f"{GREEN}{left}{NC}"

                # Проверяем существует ли юзер в users.json
                in_users = any(
                    u.get("email") == email or u.get("uuid") == email
                    for u in users
                )
                if not in_users:
                    status = f"{DIM}нет в базе{NC}"

                _box_row(
                    f"  {i:<4} {email:<26} {exp_show:<18} {left_c:<10} {status}"
                )

        _box_sep()
        _box_row()
        _box_item("1", f"Назначить TTL пользователю")
        _box_item("2", f"Продлить / изменить срок  {DIM}(автоматически разблокирует){NC}")
        _box_item("3", f"Сделать пользователя постоянным (снять TTL)")
        _box_item("4", f"Проверить истёкших прямо сейчас")
        _box_item("5",
            f"{'Отключить' if cron_ok else 'Включить'} авто-проверку (cron 30 мин)"
        )
        _box_item("6", f"🔒 Заблокировать пользователя вручную")
        _box_item("7", f"🔓 Разблокировать пользователя")
        _box_row()
        _box_back()
        _box_bottom()

        try:
            ch = input(f"{CYAN}Выбор:{NC} ").strip().lower()
        except KeyboardInterrupt:
            break

        # ── 1: Назначить TTL ──────────────────────────────────────────────
        if ch == "1":
            print()
            if not users:
                warn("Нет пользователей. Сначала добавьте через менеджер пользователей.")
                input(f"{BLUE}Нажмите Enter...{NC}")
                continue

            # Показываем только тех, у кого нет TTL
            no_ttl = [u for u in users if u.get("email") not in data]
            if not no_ttl:
                warn("У всех пользователей уже есть TTL.")
                info("Используйте [2] для продления или [3] чтобы снять ограничение.")
                input(f"{BLUE}Нажмите Enter...{NC}")
                continue

            _box_top("Выбор пользователя")
            for i, u in enumerate(no_ttl, 1):
                _box_row(
                    f"  {DIM}[{NC}{BOLD}{i}{NC}{DIM}]{NC}"
                    f"  {u.get('name', u.get('email', '—')):<20}"
                    f"  {DIM}{u.get('email','')}{NC}"
                )
            _box_bottom()
            raw = input(f"  Номер: ").strip()
            if not (raw.isdigit() and 1 <= int(raw) <= len(no_ttl)):
                warn("Неверный номер")
                input(f"{BLUE}Нажмите Enter...{NC}")
                continue
            target = no_ttl[int(raw) - 1]
            email  = target.get("email", "")

            print()
            presets = {"1": 1, "2": 3, "3": 7, "4": 14, "5": 30, "6": 90}
            _box_top(f"Установить срок действия для: {email}")
            for k, v in presets.items():
                _box_item(k, f"{v} дней")
            _box_item("7", "Ввести своё количество дней")
            _box_bottom()
            raw2 = input(f"  Выбор: ").strip()

            if raw2 in presets:
                days = presets[raw2]
            elif raw2 == "7":
                d = input("  Количество дней (1–3650): ").strip()
                if not (d.isdigit() and 1 <= int(d) <= 3650):
                    warn("Неверное значение")
                    input(f"{BLUE}Нажмите Enter...{NC}")
                    continue
                days = int(d)
            else:
                warn("Отмена")
                input(f"{BLUE}Нажмите Enter...{NC}")
                continue

            _ttl_set(email, days)

            # Устанавливаем cron если не был
            if not cron_ok:
                info("Cron-агент ещё не установлен — устанавливаю автоматически...")
                _ttl_install_cron()

            exp = _ttl_expires_str(data.get(email, {}).get("expires_at", ""))
            # Перечитываем после _ttl_set
            data = _ttl_load()
            exp  = _ttl_expires_str(data.get(email, {}).get("expires_at", ""))
            success(
                f"TTL назначен: {email} → {days} дней (осталось: {exp})"
            )
            input(f"{BLUE}Нажмите Enter...{NC}")

        # ── 2: Продлить / изменить ────────────────────────────────────────
        elif ch == "2":
            print()
            if not data:
                warn("Нет TTL-пользователей")
                input(f"{BLUE}Нажмите Enter...{NC}")
                continue

            emails = list(data.keys())
            _box_top("Выбор пользователя")
            for i, e in enumerate(emails, 1):
                rec  = data[e]
                left = _ttl_expires_str(rec.get("expires_at", ""))
                _box_row(f"  {DIM}[{NC}{BOLD}{i}{NC}{DIM}]{NC}  {e:<30}  осталось: {left}")
            _box_row()
            _box_bottom()

            raw = input("  Номер пользователя: ").strip()
            if not (raw.isdigit() and 1 <= int(raw) <= len(emails)):
                warn("Неверный номер")
                input(f"{BLUE}Нажмите Enter...{NC}")
                continue
            email = emails[int(raw) - 1]

            print()
            presets = {"1": 1, "2": 3, "3": 7, "4": 14, "5": 30, "6": 90}
            _box_top(f"Новый срок от текущего момента: {email}")
            for k, v in presets.items():
                _box_item(k, f"{v} дней с сейчас")
            _box_item("7", "Ввести количество дней")
            _box_bottom()
            raw2 = input("  Выбор: ").strip()

            if raw2 in presets:
                days = presets[raw2]
            elif raw2 == "7":
                d = input("  Дней (1–3650): ").strip()
                if not (d.isdigit() and 1 <= int(d) <= 3650):
                    warn("Неверное значение")
                    input(f"{BLUE}Нажмите Enter...{NC}")
                    continue
                days = int(d)
            else:
                warn("Отмена")
                input(f"{BLUE}Нажмите Enter...{NC}")
                continue

            _ttl_set(email, days)
            # Если пользователь был заблокирован — снимаем блокировку
            if _ttl_is_blocked(email):
                _ttl_unblock_user(email)
                success(f"Блокировка снята, срок продлён: {email} → {days} дней")
            else:
                data = _ttl_load()
                exp  = _ttl_expires_str(data.get(email, {}).get("expires_at", ""))
                success(f"Срок обновлён: {email} → {days} дней (осталось: {exp})")
            input(f"{BLUE}Нажмите Enter...{NC}")

        # ── 3: Снять TTL ──────────────────────────────────────────────────
        elif ch == "3":
            print()
            if not data:
                warn("Нет TTL-пользователей")
                input(f"{BLUE}Нажмите Enter...{NC}")
                continue

            emails = list(data.keys())
            _box_top("Выбор пользователя")
            for i, e in enumerate(emails, 1):
                left = _ttl_expires_str(data[e].get("expires_at", ""))
                blk  = f"  {RED}[заблокирован]{NC}" if _ttl_is_blocked(e) else ""
                _box_row(f"  {DIM}[{NC}{BOLD}{i}{NC}{DIM}]{NC}  {e:<30}  осталось: {left}{blk}")
            _box_row()
            _box_bottom()

            raw = input("  Номер: ").strip()
            if not (raw.isdigit() and 1 <= int(raw) <= len(emails)):
                warn("Неверный номер")
                input(f"{BLUE}Нажмите Enter...{NC}")
                continue
            email = emails[int(raw) - 1]

            ans = input(
                f"  {YELLOW}Сделать '{email}' постоянным (TTL будет снят, блокировка снята)? [y/N]:{NC} "
            ).strip().lower()
            if ans == "y":
                # Снимаем блокировку если была
                if _ttl_is_blocked(email):
                    _ttl_unblock_user(email)
                _ttl_remove(email)
                success(f"TTL снят: {email} теперь постоянный пользователь")
            else:
                info("Отмена")
            input(f"{BLUE}Нажмите Enter...{NC}")

        # ── 4: Проверить прямо сейчас ─────────────────────────────────────
        elif ch == "4":
            print()
            info("Проверка истёкших TTL-пользователей...")
            n = _ttl_check_and_expire()
            if n:
                success(f"Заблокировано {n} пользователей с истёкшим сроком")
            else:
                info("Истёкших пользователей не найдено")
            input(f"{BLUE}Нажмите Enter...{NC}")

        # ── 5: Cron вкл/выкл ─────────────────────────────────────────────
        elif ch == "5":
            print()
            if cron_ok:
                ans = input(
                    f"  {YELLOW}Отключить авто-проверку TTL? [y/N]:{NC} "
                ).strip().lower()
                if ans == "y":
                    _ttl_remove_cron()
            else:
                _ttl_install_cron()
            input(f"{BLUE}Нажмите Enter...{NC}")

        # ── 6: Заблокировать вручную ──────────────────────────────────────
        elif ch == "6":
            print()
            # Показываем незаблокированных TTL-пользователей
            active_ttl = [
                e for e in data
                if not _ttl_is_blocked(e)
            ]
            if not active_ttl:
                warn("Нет активных TTL-пользователей для блокировки")
                input(f"{BLUE}Нажмите Enter...{NC}")
                continue

            _box_top("Заблокировать пользователя")
            for i, e in enumerate(active_ttl, 1):
                left = _ttl_expires_str(data[e].get("expires_at", ""))
                _box_row(f"  {DIM}[{NC}{BOLD}{i}{NC}{DIM}]{NC}  {e:<30}  осталось: {left}")
            _box_row()
            _box_bottom()

            raw = input("  Номер пользователя: ").strip()
            if not (raw.isdigit() and 1 <= int(raw) <= len(active_ttl)):
                warn("Неверный номер")
                input(f"{BLUE}Нажмите Enter...{NC}")
                continue
            email = active_ttl[int(raw) - 1]

            ans = input(
                f"  {YELLOW}Заблокировать '{email}'? Xray откажет ему в соединении. [y/N]:{NC} "
            ).strip().lower()
            if ans == "y":
                ok = _ttl_block_user(email, reason="manual")
                if ok:
                    success(f"Пользователь {email} заблокирован. Продлите TTL [2] чтобы разблокировать.")
                else:
                    warn(f"Не удалось заблокировать: {email} не найден в базе пользователей")
            else:
                info("Отмена")
            input(f"{BLUE}Нажмите Enter...{NC}")

        # ── 7: Разблокировать ─────────────────────────────────────────────
        elif ch == "7":
            print()
            blocked_ttl = [
                e for e in data
                if _ttl_is_blocked(e)
            ]
            if not blocked_ttl:
                info("Нет заблокированных пользователей")
                input(f"{BLUE}Нажмите Enter...{NC}")
                continue

            _box_top("Разблокировать пользователя")
            for i, e in enumerate(blocked_ttl, 1):
                rec  = data[e]
                iso  = rec.get("expires_at", "")
                exp_expired = _ttl_is_expired(iso)
                left = _ttl_expires_str(iso)
                left_c = f"{RED}{left}{NC}" if exp_expired else f"{YELLOW}{left}{NC}"
                note = f"  {RED}срок истёк — рекомендуется продлить [2]{NC}" if exp_expired else ""
                _box_row(f"  {DIM}[{NC}{BOLD}{i}{NC}{DIM}]{NC}  {e:<30}  {left_c}{note}")
            _box_row()
            _box_bottom()

            raw = input("  Номер пользователя: ").strip()
            if not (raw.isdigit() and 1 <= int(raw) <= len(blocked_ttl)):
                warn("Неверный номер")
                input(f"{BLUE}Нажмите Enter...{NC}")
                continue
            email = blocked_ttl[int(raw) - 1]

            # Предупреждаем если срок уже истёк
            rec = data.get(email, {})
            if _ttl_is_expired(rec.get("expires_at", "")):
                warn(f"Срок действия {email} уже истёк. После разблокировки он снова")
                warn("заблокируется при следующей проверке cron (каждые 30 мин).")
                warn("Рекомендуется продлить срок через [2] или снять TTL через [3].")
                ans = input(
                    f"  {YELLOW}Всё равно разблокировать временно? [y/N]:{NC} "
                ).strip().lower()
            else:
                ans = input(
                    f"  {YELLOW}Разблокировать '{email}'? [y/N]:{NC} "
                ).strip().lower()

            if ans == "y":
                # Сбрасываем флаг blocked в TTL-записи
                if email in data:
                    data[email].pop("blocked", None)
                    _ttl_save(data)
                ok = _ttl_unblock_user(email)
                if ok:
                    success(f"Пользователь {email} разблокирован")
                else:
                    warn(f"Не удалось разблокировать: {email} не найден в базе")
            else:
                info("Отмена")
            input(f"{BLUE}Нажмите Enter...{NC}")

        elif ch in ("q", ""):
            break
        else:
            warn("Неверный выбор")
            time.sleep(1)


def do_share_config_server() -> None:
    """
    Поднимает одноразовый HTTP-сервер на случайном порту с токеном.
    Пользователь заходит с телефона, получает QR и ссылки, сервер завершается.
    """
    print()
    print()
    _box_top(f"Разовая ссылка для передачи конфига")

    if not STATE_FILE.exists():
        _box_warn("state.json не найден — сначала выполните установку")
        return
    try:
        state = json.loads(STATE_FILE.read_text())
    except Exception as e:
        _box_warn(f"Не удалось прочитать state.json: {e}")
        return

    # Собираем VLESS-ссылки
    links: list[dict] = []
    try:
        users = _users_load()
        if users:
            for u in users[:5]:
                lnks = _unified_show_links(u, print_output=False)
                if lnks:
                    links.append({"name": u.get("name", "user"), "links": lnks})
        if not links:
            domain   = state.get("domain", "")
            vuuid    = state.get("uuid", "")
            pub_key  = state.get("public_key", "")
            short_id = state.get("short_id", "")
            fp       = state.get("fingerprint", "chrome")
            port     = state.get("server_port", 443)
            proto    = state.get("protocol_mode", "reality")
            # SNI: при Mode B + AWG — домен маскировки, иначе собственный домен.
            # Ключ "sni" не сохраняется в state.json, поэтому читаем reality_dest.
            _sc_install_mode = state.get("install_mode", "A")
            _sc_awg = state.get("awg_exit_enabled", False) and _sc_install_mode == "B"
            _sc_reality_dest = state.get("reality_dest", "")
            if proto == "reality" and _sc_awg and _sc_reality_dest:
                sni = _sc_reality_dest
            else:
                sni = domain
            if proto == "reality":
                link = (f"vless://{vuuid}@{domain}:{port}"
                        f"?encryption=none&flow=xtls-rprx-vision"
                        f"&security=reality&sni={sni}"
                        f"&fp={fp}&pbk={pub_key}&sid={short_id}"
                        f"&type=tcp#VLESS-Reality")
            else:
                xhttp_path = urllib.parse.quote(state.get("xhttp_path", "/"), safe="")
                link = (f"vless://{vuuid}@{domain}:{port}"
                        f"?encryption=none&security=tls&sni={domain}"
                        f"&fp={fp}&type=http&path={xhttp_path}#VLESS-xHTTP")
            links.append({"name": "default", "links": [link]})
    except Exception as e:
        _box_warn(f"Ошибка сборки ссылок: {e}")
        return

    if not links:
        _box_warn("Нет ссылок для передачи")
        return

    token      = ''.join(random.choices(string.ascii_lowercase + string.digits, k=16))
    share_port = random.randint(50000, 59999)
    server_ip  = get_server_ip("4") or "YOUR_SERVER_IP"

    def _make_html() -> str:
        rows = []
        for u_entry in links:
            for lnk in u_entry.get("links", []):
                encoded = urllib.parse.quote(lnk, safe="")
                qr_url  = f"https://api.qrserver.com/v1/create-qr-code/?size=220x220&data={encoded}"
                rows.append(f"""
                <div class="card">
                  <h3>{u_entry['name']}</h3>
                  <img src="{qr_url}" alt="QR" style="border-radius:8px;border:1px solid #ddd"/>
                  <p style="word-break:break-all;font-size:10px;color:#666;margin:8px 0">{lnk}</p>
                  <a href="{lnk}" style="display:inline-block;padding:8px 18px;background:#388e3c;
                     color:#fff;border-radius:6px;text-decoration:none;font-size:14px">
                     Открыть в приложении</a>
                </div>""")
        body = "".join(rows)
        return f"""<!DOCTYPE html>
<html><head><meta charset="utf-8">
<meta name="viewport" content="width=device-width,initial-scale=1">
<title>VLESS Config</title>
<style>
 body{{font-family:-apple-system,sans-serif;background:#f0f4f8;padding:16px;margin:0}}
 .card{{background:#fff;border-radius:14px;padding:20px;margin-bottom:16px;
        box-shadow:0 2px 10px rgba(0,0,0,.08);text-align:center}}
 h1{{font-size:20px;color:#333;margin-bottom:4px}}
 h3{{color:#555;margin:0 0 12px}}
 .warn{{color:#c62828;font-size:13px;margin-bottom:16px}}
</style></head>
<body>
<h1>🔐 VLESS Config</h1>
<p class="warn">⚠️ Одноразовая ссылка — страница недоступна после этого просмотра</p>
{body}
<p style="font-size:11px;color:#aaa;text-align:center;margin-top:20px">
 VLESS Ultimate Installer</p>
</body></html>"""

    html_content = _make_html()
    served_once  = [False]
    stop_event   = threading.Event()

    class _OneTimeHandler(http.server.BaseHTTPRequestHandler):
        def log_message(self, fmt, *args):
            pass

        def do_GET(self):
            parsed    = urllib.parse.urlparse(self.path)
            params    = urllib.parse.parse_qs(parsed.query)
            req_token = params.get("t", [""])[0]
            if req_token != token:
                self.send_response(403)
                self.end_headers()
                self.wfile.write(b"403 Forbidden")
                return
            self.send_response(200)
            self.send_header("Content-Type", "text/html; charset=utf-8")
            self.send_header("Cache-Control", "no-store")
            self.end_headers()
            self.wfile.write(html_content.encode())
            served_once[0] = True
            stop_event.set()

    server = http.server.HTTPServer(("0.0.0.0", share_port), _OneTimeHandler)
    server.timeout = 1
    share_url = f"http://{server_ip}:{share_port}/?t={token}"

    _box_row(f"  {GREEN}Сервер запущен на порту {share_port}{NC}")
    _box_row(f"  Ссылка (5 минут или 1 просмотр):")
    _box_row(f"  {CYAN}{BOLD}{share_url}{NC}")

    _run(["ufw", "allow", str(share_port), "comment", "xray-share-tmp"],
         check=False, quiet=True)
    _box_info("Ожидание подключения (5 минут)...")
    _box_row(f"  {DIM}(Ctrl+C для отмены){NC}")
    _box_bottom()

    deadline = time.time() + 300
    try:
        while not stop_event.is_set() and time.time() < deadline:
            server.handle_request()
    except KeyboardInterrupt:
        pass
    finally:
        server.server_close()
        _run(["ufw", "delete", "allow", str(share_port)], check=False, quiet=True)

    if served_once[0]:
        success("Конфиг передан. Сервер закрыт.")
    else:
        warn("Время истекло — сервер закрыт без отдачи страницы.")
    log_to_file("INFO", f"Share config: served={served_once[0]}, port={share_port}")


# =============================================================================
#  МОДУЛЬ 4: ЕЖЕДНЕВНЫЙ HEALTH-ОТЧЁТ (CRON 08:00)
# =============================================================================
def do_health_report(send_tg_flag: bool = True) -> str:
    """Собирает ежедневный health-отчёт, опционально шлёт в Telegram."""
    lines = []
    ts = datetime.now().strftime("%d.%m.%Y %H:%M")
    hostname = ""
    try:
        hostname = _run(["hostname", "-s"], capture=True, check=False).stdout.strip()
    except Exception:
        pass

    lines.append(f"📋 <b>Daily Health Report [{hostname}]</b>  {ts}")
    lines.append("")

    # Xray
    r = _run(["systemctl", "is-active", "xray"], capture=True, check=False)
    xray_ok = r.stdout.strip() == "active"
    lines.append(f"{'✅' if xray_ok else '❌'} Xray: {'активен' if xray_ok else 'НЕ АКТИВЕН'}")

    # Nginx
    r = _run(["systemctl", "is-active", "nginx"], capture=True, check=False)
    nginx_ok = r.stdout.strip() == "active"
    lines.append(f"{'✅' if nginx_ok else '❌'} Nginx: {'активен' if nginx_ok else 'НЕ АКТИВЕН'}")

    # SSL
    domain = ""
    try:
        if STATE_FILE.exists():
            domain = json.loads(STATE_FILE.read_text()).get("domain", "")
    except Exception:
        pass
    if domain:
        cert = Path(f"/etc/letsencrypt/live/{domain}/fullchain.pem")
        if cert.exists():
            try:
                r  = _run(["openssl", "x509", "-in", str(cert), "-noout", "-enddate"],
                          capture=True, check=False)
                expiry = r.stdout.strip().split("=", 1)[1]
                r2 = _run(["date", "-d", expiry, "+%s"], capture=True, check=False)
                cert_days = (int(r2.stdout.strip()) - int(time.time())) // 86400
                icon = "✅" if cert_days > 30 else "⚠️"
                lines.append(f"{icon} SSL ({domain}): {cert_days} дн. до истечения")
            except Exception:
                lines.append("⚠️ SSL: не удалось проверить")
        else:
            lines.append("❌ SSL: сертификат не найден")
    else:
        lines.append("ℹ️  SSL: домен не задан")

    # Диск
    try:
        r = _run(["df", "-h", "/"], capture=True, check=False)
        parts = r.stdout.splitlines()[-1].split()
        disk_pct = float(parts[4].replace("%", ""))
        icon = "✅" if disk_pct < 80 else "⚠️" if disk_pct < 90 else "❌"
        lines.append(f"{icon} Диск: {parts[2]}/{parts[1]} ({disk_pct:.0f}%)")
    except Exception:
        lines.append("⚠️ Диск: не удалось проверить")

    # RAM
    try:
        meminfo = {}
        for line in Path("/proc/meminfo").read_text().splitlines():
            k, v = line.split(":", 1)
            meminfo[k.strip()] = int(v.strip().split()[0])
        total_mb = meminfo.get("MemTotal", 0) // 1024
        avail_mb = meminfo.get("MemAvailable", 0) // 1024
        used_mb  = total_mb - avail_mb
        pct = used_mb * 100 // max(total_mb, 1)
        icon = "✅" if pct < 80 else "⚠️" if pct < 90 else "❌"
        lines.append(f"{icon} RAM: {used_mb}/{total_mb} МБ ({pct}%)")
    except Exception:
        lines.append("⚠️ RAM: не удалось проверить")

    # Geo-файлы
    for dat in (GEOSITE_DAT, GEOIP_DAT):
        if dat.exists():
            age = (time.time() - dat.stat().st_mtime) / 86400
            icon = "✅" if age < 14 else "⚠️"
            lines.append(f"{icon} {dat.name}: возраст {age:.0f} дн.")
        else:
            lines.append(f"❌ {dat.name}: не найден")

    text = "\n".join(lines)
    log_to_file("INFO", f"Health report generated")

    if send_tg_flag:
        cfg = _tg_load()
        if (cfg.get("token") and cfg.get("chat_id")
                and cfg.get("events", {}).get("health_report", True)):
            tg_send(text, cfg["token"], cfg["chat_id"])

    return text


def _health_report_install_cron() -> None:
    """Устанавливает cron на 08:00 для ежедневного health-отчёта."""
    sh = Path("/usr/local/bin/xray-health-report.sh")
    sh.write_text(textwrap.dedent(f"""\
        #!/bin/bash
        python3 -c "
import json, re, subprocess, sys, time
from pathlib import Path
from datetime import datetime
STATE_FILE = Path('/var/lib/xray-installer/state.json')
TG_CONFIG_FILE = Path('/var/lib/xray-installer/telegram.json')
GEOSITE_DAT = Path('/etc/xray/geosite.dat')
GEOIP_DAT   = Path('/etc/xray/geoip.dat')

def _run(args):
    return subprocess.run(args, capture_output=True, text=True)

def tg_send(msg, token, chat_id):
    subprocess.run(['curl','-s','-o','/dev/null','-m','10',
        f'https://api.telegram.org/bot{{token}}/sendMessage',
        '-d',f'chat_id={{chat_id}}','-d',f'text={{msg}}','-d','parse_mode=HTML'],
        capture_output=True)

cfg = {{}}
try:
    if TG_CONFIG_FILE.exists():
        cfg = json.loads(TG_CONFIG_FILE.read_text())
except: pass
token   = cfg.get('token','')
chat_id = cfg.get('chat_id','')
if not (token and chat_id and cfg.get('events',{{}}).get('health_report',True)):
    sys.exit(0)

hostname = _run(['hostname','-s']).stdout.strip()
ts = datetime.now().strftime('%d.%m.%Y %H:%M')
lines = [f'Daily Health Report [{{hostname}}]  {{ts}}', '']
for svc in ('xray','nginx'):
    ok = _run(['systemctl','is-active',svc]).stdout.strip() == 'active'
    lines.append(f'{{chr(9989) if ok else chr(10060)}} {{svc}}: {{\"активен\" if ok else \"НЕ АКТИВЕН\"}}')
domain = ''
try:
    if STATE_FILE.exists():
        domain = json.loads(STATE_FILE.read_text()).get('domain','')
except: pass
if domain:
    cert = Path(f'/etc/letsencrypt/live/{{domain}}/fullchain.pem')
    if cert.exists():
        try:
            r = _run(['openssl','x509','-in',str(cert),'-noout','-enddate'])
            exp = r.stdout.strip().split('=',1)[1]
            epoch = int(_run(['date','-d',exp,'+%s']).stdout.strip())
            days = (epoch - int(time.time())) // 86400
            lines.append(f'{{chr(9989) if days>30 else chr(9888)}} SSL: {{days}} дн. до истечения')
        except: lines.append('SSL: ошибка проверки')
try:
    r = _run(['df','-h','/'])
    p = r.stdout.splitlines()[-1].split()
    pct = float(p[4].replace('%',''))
    lines.append(f'{{chr(9989) if pct<80 else chr(9888)}} Диск: {{p[2]}}/{{p[1]}} ({{pct:.0f}}%)')
except: pass
for dat_name in ('geosite.dat','geoip.dat'):
    dat = Path(f'/etc/xray/{{dat_name}}')
    if dat.exists():
        age = (time.time() - dat.stat().st_mtime) / 86400
        lines.append(f'{{chr(9989) if age<14 else chr(9888)}} {{dat_name}}: возраст {{age:.0f}} дн.')
    else:
        lines.append(f'{{chr(10060)}} {{dat_name}}: не найден')
tg_send(chr(10).join(lines), token, chat_id)
" 2>>/var/log/xray-health-report.log
    """))
    sh.chmod(0o750)
    cron_p = Path("/etc/cron.d/xray-health-report")
    cron_p.write_text(f"0 8 * * * root {sh} >> /var/log/xray-health-report.log 2>&1\n")
    cron_p.chmod(0o644)
    success("Health-отчёт cron установлен (ежедневно 08:00)")


def do_manage_health_report() -> None:
    """Меню управления ежедневным health-отчётом."""
    while True:
        os.system("clear")
        cron_active = Path("/etc/cron.d/xray-health-report").exists()
        print()
        _box_top(f"Ежедневный Health-отчёт")
        _box_row(f"  Cron (08:00): {''+GREEN+'ВКЛЮЧЁН'+NC if cron_active else ''+YELLOW+'ОТКЛЮЧЁН'+NC}")
        _box_item("1", f"{'Отключить' if cron_active else 'Включить'} ежедневный отчёт (cron 08:00)")
        _box_item("2", f"Запустить отчёт прямо сейчас")
        _box_item("3", f"Показать лог отчётов")
        _box_item("Q", f"Назад")
        _box_bottom()
        ch = input(f"{CYAN}Выбор:{NC} ").strip().lower()

        if ch == "1":
            if cron_active:
                Path("/etc/cron.d/xray-health-report").unlink(missing_ok=True)
                Path("/usr/local/bin/xray-health-report.sh").unlink(missing_ok=True)
                success("Health-отчёт cron отключён")
            else:
                _health_report_install_cron()
            input(f"{BLUE}Нажмите Enter...{NC}")

        elif ch == "2":
            print()
            info("Генерация отчёта...")
            report = do_health_report(send_tg_flag=True)
            clean  = re.sub(r'<[^>]+>', '', report)
            print()
            print(clean)
            input(f"{BLUE}Нажмите Enter...{NC}")

        elif ch == "3":
            lp = Path("/var/log/xray-health-report.log")
            if lp.exists():
                lines = lp.read_text().splitlines()[-30:]
                print()
                print('\n'.join(lines))
            else:
                warn("Лог не найден")
            input(f"{BLUE}Нажмите Enter...{NC}")

        elif ch in ("q", ""):
            break
        else:
            warn("Неверный выбор")
            time.sleep(1)


# =============================================================================
#  МОДУЛЬ 5: ПОЛНАЯ МИГРАЦИЯ (ЗАШИФРОВАННЫЙ АРХИВ)
# =============================================================================
def do_full_migration_export() -> None:
    """
    Полная миграция: config.json, сертификаты, ключи REALITY,
    users.json, state.json — упаковка в зашифрованный архив (AES-256).
    """
    import getpass, tarfile as _tarfile

    print()
    print()
    _box_top(f"Полный экспорт для миграции")

    ts = datetime.now().strftime('%Y%m%d_%H%M%S')
    archive_path = Path(f"/root/xray-migration-{ts}.tar.gz.enc")

    domain = ""
    try:
        if STATE_FILE.exists():
            domain = json.loads(STATE_FILE.read_text()).get("domain", "")
    except Exception:
        pass

    include_paths = [
        (CONFIG_DIR / "config.json",              "etc/xray/config.json"),
        (Path("/usr/local/etc/xray/config.json"), "usr_local/etc/xray/config.json"),
        (STATE_FILE,                              "state.json"),
        (USERS_FILE,                              "users.json"),
        (TRAFFIC_LIMITS_FILE,                     "traffic_limits.json"),
        (TG_CONFIG_FILE,                          "telegram.json"),
        (SPLIT_TUNNEL_CUSTOM_FILE,                "split_tunnel_custom.json"),
        (XRAY_SERVICE,                            "etc/systemd/system/xray.service"),
    ]
    # AWG 2.0 конфиги (если активен)
    try:
        if STATE_FILE.exists():
            _st = json.loads(STATE_FILE.read_text())
            if _st.get("awg_exit_enabled") and _st.get("install_mode") == "B":
                _awg_conf_dir = Path("/etc/amnezia/amneziawg")
                for _awg_f in _awg_conf_dir.glob("*.conf") if _awg_conf_dir.exists() else []:
                    include_paths.append((_awg_f, f"amnezia/amneziawg/{_awg_f.name}"))
                _awg_svc = Path(f"/etc/systemd/system/amneziawg-awg0.service")
                if _awg_svc.exists():
                    include_paths.append((_awg_svc, "etc/systemd/system/amneziawg-awg0.service"))
    except Exception:
        pass
    # SSL-сертификаты
    if domain:
        le_dir = Path(f"/etc/letsencrypt/live/{domain}")
        for fname in ("fullchain.pem", "privkey.pem", "chain.pem"):
            p = le_dir / fname
            if p.exists():
                include_paths.append((p, f"letsencrypt/{domain}/{fname}"))
        arc_dir = Path(f"/etc/letsencrypt/archive/{domain}")
        if arc_dir.exists():
            for f in arc_dir.iterdir():
                if f.is_file():
                    include_paths.append((f, f"letsencrypt/archive/{domain}/{f.name}"))

    _box_row(f"  {YELLOW}Архив будет зашифрован паролем (AES-256-CBC){NC}")
    _box_bottom()
    while True:
        pw1 = getpass.getpass("  Пароль шифрования: ")
        if len(pw1) < 8:
            warn("  Пароль должен быть не менее 8 символов")
            continue
        pw2 = getpass.getpass("  Повторите пароль:   ")
        if pw1 == pw2:
            break
        warn("  Пароли не совпадают")

    with tempfile.TemporaryDirectory(prefix="xray_migration_") as tmpdir:
        tmp = Path(tmpdir)
        copied = []
        for src, dest_rel in include_paths:
            if not src.exists():
                continue
            dest = tmp / dest_rel
            dest.parent.mkdir(parents=True, exist_ok=True)
            shutil.copy2(src, dest)
            copied.append(dest_rel)
            dim(f"  + {dest_rel}")

        if not copied:
            warn("Нечего экспортировать")
            return

        (tmp / "README.txt").write_text(textwrap.dedent(f"""\
            VLESS Ultimate Installer — Полный архив миграции
            Создан: {datetime.now().strftime('%Y-%m-%d %H:%M:%S')}
            Домен:  {domain or '—'}
            Файлов: {len(copied)}

            Для восстановления:
              1. Установите Xray на новом сервере
              2. Запустите install_pinned_nodes.py
              3. X → [3] Полный импорт (зашифрованный)
        """))

        tmp_tar = tmp / f"migration_{ts}.tar.gz"
        with _tarfile.open(tmp_tar, "w:gz") as tar:
            for item in tmp.iterdir():
                if item != tmp_tar:
                    tar.add(item, arcname=item.name)

        r = _run([
            "openssl", "enc", "-aes-256-cbc", "-pbkdf2", "-iter", "100000",
            "-in", str(tmp_tar), "-out", str(archive_path),
            "-pass", f"pass:{pw1}",
        ], capture=True, check=False)

        if r.returncode != 0:
            warn(f"Ошибка шифрования: {r.stderr[:200]}")
            return

    archive_path.chmod(0o600)
    size_kb = archive_path.stat().st_size // 1024
    success(f"Архив создан: {archive_path} ({size_kb} КБ, {len(copied)} файлов)")
    info(f"Скопируйте: scp root@{domain or 'SERVER'}:{archive_path} ./")
    log_to_file("INFO", f"Full migration export: {archive_path} ({len(copied)} files)")


def do_full_migration_import() -> None:
    """Импорт полного зашифрованного архива миграции."""
    import getpass, tarfile as _tarfile

    print()
    archive_raw  = input(f"  Путь к архиву (.tar.gz.enc): ").strip()
    archive_path = Path(archive_raw)
    if not archive_path.exists():
        warn(f"Файл не найден: {archive_path}")
        return

    pw = getpass.getpass("  Пароль шифрования: ")
    print()
    warn("ВНИМАНИЕ: импорт перезапишет текущие конфиги, сертификаты и ключи!")
    ans = input(f"{YELLOW}Продолжить? [y/N]:{NC} ").strip().lower()
    if ans != "y":
        info("Отменено")
        return

    with tempfile.TemporaryDirectory(prefix="xray_migimp_") as tmpdir:
        tmp_tar = Path(tmpdir) / "migration.tar.gz"
        r = _run([
            "openssl", "enc", "-d", "-aes-256-cbc", "-pbkdf2", "-iter", "100000",
            "-in", str(archive_path), "-out", str(tmp_tar),
            "-pass", f"pass:{pw}",
        ], capture=True, check=False)
        if r.returncode != 0:
            warn("Ошибка дешифрования — неверный пароль или повреждённый файл")
            return

        if not _tarfile.is_tarfile(tmp_tar):
            warn("Файл не является tar-архивом после дешифрования")
            return

        with _tarfile.open(tmp_tar, "r:gz") as tar:
            tar.extractall(tmpdir)

        tmp = Path(tmpdir)
        restore_map = [
            ("etc/xray/config.json",           CONFIG_DIR / "config.json"),
            ("usr_local/etc/xray/config.json", Path("/usr/local/etc/xray/config.json")),
            ("state.json",                     STATE_FILE),
            ("users.json",                     USERS_FILE),
            ("traffic_limits.json",            TRAFFIC_LIMITS_FILE),
            ("telegram.json",                  TG_CONFIG_FILE),
            ("split_tunnel_custom.json",       SPLIT_TUNNEL_CUSTOM_FILE),
            ("etc/systemd/system/xray.service",XRAY_SERVICE),
        ]
        restored = []

        # Сертификаты
        le_src = tmp / "letsencrypt"
        if le_src.exists():
            for src in le_src.rglob("*"):
                if src.is_file():
                    rel = src.relative_to(le_src)
                    dst = Path("/etc/letsencrypt/live") / rel
                    dst.parent.mkdir(parents=True, exist_ok=True)
                    shutil.copy2(src, dst)
                    try:
                        dst.chmod(0o600 if "privkey" in src.name else 0o644)
                    except Exception:
                        pass
                    restored.append(f"letsencrypt/{rel}")
                    dim(f"  + letsencrypt/{rel}")

        for rel, dst in restore_map:
            # Ищем в извлечённой структуре
            candidates = list(tmp.rglob(Path(rel).name))
            src = next((c for c in candidates if rel.split("/")[-1] in c.name), None)
            if src is None:
                src_direct = tmp / rel
                if src_direct.exists():
                    src = src_direct
            if src is None:
                dim(f"  - {rel} (не найден в архиве)")
                continue
            dst.parent.mkdir(parents=True, exist_ok=True)
            shutil.copy2(src, dst)
            try:
                dst.chmod(0o640)
            except Exception:
                pass
            restored.append(rel)
            dim(f"  + {rel} → {dst}")

    if not restored:
        warn("Ни один файл не был восстановлен")
        return

    success(f"Восстановлено файлов: {len(restored)}")
    _run(["systemctl", "daemon-reload"], check=False, quiet=True)

    # ── ПАТЧ СОКЕТА ─────────────────────────────────────────────────────────
    # При миграции на новый сервер socket-путь может отличаться.
    # Если в бэкапе /dev/shm/OLDNAME.socket, а текущий state.json
    # содержит другой путь — патчим config.json автоматически.
    print()
    info("Проверка socket-пути в импортированном конфиге...")
    socket_patched = False
    for _cp in (CONFIG_DIR / "config.json",
                Path("/usr/local/etc/xray/config.json")):
        if _patch_imported_config_socket(_cp):
            socket_patched = True
    if not socket_patched:
        dim("  socket-путь совпадает или патч не требуется")

    val = _run([str(XRAY_BIN), "run", "-test", "-config",
                str(CONFIG_DIR / "config.json")],
               capture=True, check=False, quiet=True)
    if val.returncode == 0:
        _run(["systemctl", "restart", "xray"], check=False, quiet=True)
        time.sleep(2)
        r = _run(["systemctl", "is-active", "xray"], capture=True, check=False)
        if r.stdout.strip() == "active":
            success("Xray запущен с восстановленным конфигом")
        else:
            warn("Xray не запустился — journalctl -u xray -n 20")
            r_jnl = _run(["journalctl", "-u", "xray", "-n", "10", "--no-pager"],
                         capture=True, check=False, quiet=True)
            if r_jnl.stdout.strip():
                print(f"{DIM}{r_jnl.stdout.strip()}{NC}")
    else:
        warn("Конфиг невалиден после восстановления — Xray не перезапускался")
        warn((val.stdout + val.stderr)[:300])
    log_to_file("INFO", f"Full migration import: {len(restored)} files restored, socket_patched={socket_patched}")


# =============================================================================
#  МОДУЛЬ 6: ИСТОРИЯ ТРАФИКА ПО ДНЯМ (ASCII-ГИСТОГРАММА)
# =============================================================================
TRAFFIC_HISTORY_FILE = Path("/var/lib/xray-installer/traffic_history.json")


def _traffic_snapshot_save() -> None:
    """Сохраняет текущий снимок максимального трафика пользователей за день."""
    users = _users_load()
    if not users:
        return
    now_date = datetime.now().strftime("%Y-%m-%d")
    try:
        history = json.loads(TRAFFIC_HISTORY_FILE.read_text()) if TRAFFIC_HISTORY_FILE.exists() else {}
    except Exception:
        history = {}
    day_data = history.setdefault(now_date, {})
    for u in users:
        email = u.get("email", "")
        if not email:
            continue
        used_bytes = _query_user_traffic_bytes(email)
        # Сохраняем максимум — счётчики Stats API накопительные с момента запуска
        key = f"{email}_max"
        day_data[key] = max(day_data.get(key, 0), used_bytes)
    # Удаляем данные старше 90 дней
    cutoff = time.time() - 90 * 86400
    history = {
        date: data for date, data in history.items()
        if datetime.strptime(date, "%Y-%m-%d").timestamp() >= cutoff
    }
    TRAFFIC_HISTORY_FILE.parent.mkdir(parents=True, exist_ok=True)
    TRAFFIC_HISTORY_FILE.write_text(json.dumps(history, indent=2, ensure_ascii=False))
    TRAFFIC_HISTORY_FILE.chmod(0o600)


def _install_traffic_snapshot_cron() -> None:
    sh = Path("/usr/local/bin/xray-traffic-snapshot.sh")
    sh.write_text(textwrap.dedent(f"""\
        #!/bin/bash
        python3 -c "
import json, re, subprocess, sys, time
from pathlib import Path
from datetime import datetime
XRAY_BIN = Path('/usr/local/bin/xray')
XRAY_STATS_API_PORT = 10085
USERS_FILE = Path('/etc/xray/users.json')
TRAFFIC_HISTORY_FILE = Path('/var/lib/xray-installer/traffic_history.json')

def _run(args):
    return subprocess.run(args, capture_output=True, text=True)

def _users_load():
    try: return json.loads(USERS_FILE.read_text()) if USERS_FILE.exists() else []
    except: return []

def qbytes(email):
    total = 0
    for d in ('uplink','downlink'):
        r = _run([str(XRAY_BIN),'api','statsquery',
            f'--server=127.0.0.1:{{XRAY_STATS_API_PORT}}',
            f'--pattern=user>>>{{email}}>>>{{d}}'])
        for line in r.stdout.splitlines():
            m = re.search(r'\"value\"\\s*:\\s*\"?(\\d+)\"?', line)
            if m: total += int(m.group(1))
    return total

users = _users_load()
if not users: sys.exit(0)
now_date = datetime.now().strftime('%Y-%m-%d')
try:
    history = json.loads(TRAFFIC_HISTORY_FILE.read_text()) if TRAFFIC_HISTORY_FILE.exists() else {{}}
except: history = {{}}
day_data = history.setdefault(now_date, {{}})
for u in users:
    email = u.get('email','')
    if not email: continue
    used = qbytes(email)
    key = f'{{email}}_max'
    day_data[key] = max(day_data.get(key, 0), used)
cutoff = time.time() - 90 * 86400
history = {{d: v for d, v in history.items()
    if datetime.strptime(d,'%Y-%m-%d').timestamp() >= cutoff}}
TRAFFIC_HISTORY_FILE.parent.mkdir(parents=True, exist_ok=True)
TRAFFIC_HISTORY_FILE.write_text(json.dumps(history, indent=2))
" 2>>/var/log/xray-traffic-snapshot.log
    """))
    sh.chmod(0o750)
    cron_p = Path("/etc/cron.d/xray-traffic-snapshot")
    cron_p.write_text(f"*/15 * * * * root {sh} >> /var/log/xray-traffic-snapshot.log 2>&1\n")
    cron_p.chmod(0o644)
    success("Cron снимков трафика установлен (каждые 15 мин)")


def do_traffic_history() -> None:
    """Показывает ASCII-гистограмму трафика по дням (последние 14 дней)."""
    while True:
        os.system("clear")
        print()
        _box_top(f"История трафика по дням")

        cron_active = Path("/etc/cron.d/xray-traffic-snapshot").exists()
        _box_row(f"  Сбор снимков: {''+GREEN+'ВКЛЮЧЁН (15 мин)'+NC if cron_active else ''+YELLOW+'ОТКЛЮЧЁН'+NC}")

        if not TRAFFIC_HISTORY_FILE.exists():
            _box_row(f"  {DIM}Данных пока нет. Включите сбор снимков [1] и подождите.{NC}")
        else:
            try:
                history = json.loads(TRAFFIC_HISTORY_FILE.read_text())
                users   = _users_load()
                all_emails = list(dict.fromkeys(
                    u.get("email", "") for u in users if u.get("email")
                ))

                if not all_emails:
                    _box_row(f"  {DIM}Пользователей нет{NC}")
                else:
                    sorted_dates = sorted(history.keys())[-14:]
                    max_bytes = max(
                        (history.get(d, {}).get(f"{email}_max", 0)
                         for d in sorted_dates for email in all_emails),
                        default=1
                    )
                    bar_width = 28
                    scale = max_bytes / bar_width if max_bytes else 1

                    def fmt_bytes(b: int) -> str:
                        if b >= 1024**3: return f"{b/1024**3:.2f} ГБ"
                        if b >= 1024**2: return f"{b/1024**2:.1f} МБ"
                        if b >= 1024:    return f"{b/1024:.0f} КБ"
                        return f"{b} Б"

                    colours = [CYAN, GREEN, MAGENTA, YELLOW, BLUE]
                    _box_row(f"  {BOLD}{'Дата':<12} {'Трафик':<{bar_width+2}} {'Итого'}{NC}")
                    _box_row(f"  {'─'*12} {'─'*bar_width} {'─'*12}")
                    for date in sorted_dates:
                        day_total = 0
                        bar_parts = []
                        for idx, email in enumerate(all_emails[:5]):
                            val   = history.get(date, {}).get(f"{email}_max", 0)
                            day_total += val
                            filled = int(val / scale) if scale else 0
                            col = colours[idx % len(colours)]
                            bar_parts.append(f"{col}{'▓' * filled}{NC}")
                        bar_str   = "".join(bar_parts)
                        total_str = fmt_bytes(day_total)
                        _box_row(f"  {date:<12} {bar_str:<{bar_width+30}} {DIM}{total_str}{NC}")

                    for idx, email in enumerate(all_emails[:5]):
                        col = colours[idx % len(colours)]
                        _box_row(f"  {col}#{NC} {email}")

            except Exception as e:
                _box_warn(f"Ошибка чтения истории: {e}")

        _box_row()
        _box_item("1", f"{'Отключить' if cron_active else 'Включить'} сбор снимков (cron 15 мин)")
        _box_item("2", f"Сохранить снимок прямо сейчас")
        _box_item("Q", f"Назад")
        _box_bottom()
        ch = input(f"{CYAN}Выбор:{NC} ").strip().lower()

        if ch == "1":
            if cron_active:
                Path("/etc/cron.d/xray-traffic-snapshot").unlink(missing_ok=True)
                Path("/usr/local/bin/xray-traffic-snapshot.sh").unlink(missing_ok=True)
                success("Сбор снимков отключён")
            else:
                _install_traffic_snapshot_cron()
            input(f"{BLUE}Нажмите Enter...{NC}")

        elif ch == "2":
            info("Сохранение снимка...")
            _traffic_snapshot_save()
            success("Снимок сохранён")
            input(f"{BLUE}Нажмите Enter...{NC}")

        elif ch in ("q", ""):
            break
        else:
            warn("Неверный выбор")
            time.sleep(1)


