def do_manage_geoip_block() -> None:
    """Добавляет routing-правила в Xray для GeoIP-блокировки."""
    # Авто-определение ASN хостера при первом открытии (патч: задача #3)
    _as_suggest_server_asn()
    while True:
        os.system("clear")
        print()
        _box_top(f"Блокировка по GeoIP")

        current_rules = _geoip_block_get_rules()
        if current_rules:
            _box_row(f"  {BOLD}Текущие правила блокировки:{NC}")
            for r in current_rules:
                ip_str  = ", ".join(r.get("ip",    [])[:3])
                geo_str = ", ".join(r.get("geoip", [])[:3])
                targets = " | ".join(filter(None, [ip_str, geo_str]))
                _box_row(f"    {RED}✗{NC} [{r.get('outboundTag','block')}] {targets or '(прочие)'}")
        else:
            _box_row(f"  {DIM}Нет правил блокировки{NC}")

        # Статус РФ подсетей в шапке меню
        _ru_active_geo = _xray_count_ru_subnet_rules()
        _ru_file_geo   = Path("/etc/xray/ru_subnets_ripe.txt")
        if _ru_active_geo:
            _ru_geo_str = f"{GREEN}✓ {_ru_active_geo} правил в Xray{NC}"
        elif _ru_file_geo.exists():
            _ru_geo_str = f"{YELLOW}файл есть, не применены{NC}"
        else:
            _ru_geo_str = f"{DIM}не настроены{NC}"
        _box_row(f"  {DIM}РФ подсети RIPE: {_ru_geo_str}{NC}")
        _box_item("1", f"Allowlist — принимать только из выбранных стран")
        _box_item("2", f"Blocklist — заблокировать конкретные страны")
        _box_item("3", f"Заблокировать диапазоны сканеров (Shodan, Censys и др.)")
        _box_item("4", f"{RED}Удалить все правила GeoIP-блокировки{NC}")
        _box_item("5", f"{GREEN}РФ подсети (RIPE NCC) → direct{NC}  [защита от цензора]")
        # Показываем активные AS прямо в шапке пункта [6]
        _geo_as_entries = _as_direct_list_load()
        if _geo_as_entries:
            _geo_as_parts = []
            for _e in _geo_as_entries:
                _geo_as_parts.append(f"{BOLD}{_e['asn']}{NC}[{_as_action_label(_e['action'])}]")
            _geo_as_hint = "  активны: " + "  ".join(_geo_as_parts)
            _box_item("6", f"{GREEN}AS-маршрутизация{NC}  [по ASN хостера/провайдера]")
            _box_row(f"       {DIM}{_geo_as_hint}{NC}")
        else:
            _box_item("6", f"{GREEN}AS-маршрутизация{NC}  [по ASN хостера/провайдера]")
        _box_item("7", f"Управление AS-маршрутами  [изменить/удалить/обновить]")
        _box_item("Q", f"Назад")
        _box_bottom()
        ch = input(f"{CYAN}Выбор:{NC} ").strip().lower()

        if ch == "1":
            print()
            raw = input("  Коды стран через запятую (напр.: RU,BY,KZ): ").strip().upper()
            if not raw:
                warn("Пусто — отмена")
                input(f"{BLUE}Нажмите Enter...{NC}")
                continue
            codes = [c.strip() for c in raw.split(",") if c.strip()]
            _geoip_set_allowlist(codes)
            input(f"{BLUE}Нажмите Enter...{NC}")

        elif ch == "2":
            print()
            raw = input("  Коды стран для блокировки (напр.: CN,US): ").strip().upper()
            if not raw:
                warn("Пусто — отмена")
                input(f"{BLUE}Нажмите Enter...{NC}")
                continue
            codes = [c.strip() for c in raw.split(",") if c.strip()]
            _geoip_add_country_block(codes)
            input(f"{BLUE}Нажмите Enter...{NC}")

        elif ch == "3":
            _geoip_add_scanner_block()
            input(f"{BLUE}Нажмите Enter...{NC}")

        elif ch == "4":
            ans = input(f"  {YELLOW}Удалить все GeoIP-правила? [y/N]:{NC} ").strip().lower()
            if ans == "y":
                _geoip_remove_all()
            input(f"{BLUE}Нажмите Enter...{NC}")

        elif ch == "5":
            do_manage_ru_subnet_direct()

        elif ch == "6":
            # ── Добавление AS прямо в меню GeoIP (батч + поиск по IP/домену) ─
            print()
            info(f"Введите ASN(ы) через пробел/запятую — или IP/домен для авто-определения")
            info(f"Примеры: {BOLD}AS8359{NC}  {BOLD}8359 1234{NC}  {BOLD}google.com{NC}  {BOLD}8.8.8.8{NC}")
            raw = input(f"  Введите: ").strip()
            if not raw:
                continue

            # Авто-определение ASN по IP/домену
            import re as _re_geo
            tokens = [t for t in _re_geo.split(r'[\s,;]+', raw) if t]
            resolved_tokens = []
            for tok in tokens:
                # Если это явно не ASN-формат — пробуем определить через API
                if not _re_geo.match(r'^(?:AS)?\d+$', tok, _re_geo.IGNORECASE):
                    info(f"  Определяю ASN для {tok}...")
                    r_asn, r_org = _resolve_asn_from_input(tok)
                    if r_asn:
                        success(f"  {tok} → {r_asn}  ({r_org})")
                        resolved_tokens.append(r_asn)
                    else:
                        warn(f"  Не удалось определить ASN для {tok!r} — пропуск")
                else:
                    resolved_tokens.append(tok)

            if not resolved_tokens:
                input(f"{BLUE}Нажмите Enter...{NC}")
                continue

            # Нормализуем и валидируем все токены
            valid_asns = []
            for tok in resolved_tokens:
                asn = _as_normalize(tok)
                _asn_ok, _asn_err = _as_validate(asn)
                if not _asn_ok:
                    warn(f"Неверный ASN {tok!r}: {_asn_err}")
                else:
                    valid_asns.append(asn)

            if not valid_asns:
                input(f"{BLUE}Нажмите Enter...{NC}")
                continue

            # Для батча из нескольких — спрашиваем действие один раз
            _cur_entries = _as_direct_list_load()
            _cur_map     = {e["asn"]: e for e in _cur_entries}

            # Фильтруем уже добавленные
            new_asns = []
            for asn in valid_asns:
                if asn in _cur_map:
                    info(f"{asn} уже добавлен [{_as_action_label(_cur_map[asn]['action'])}] — пропуск")
                else:
                    new_asns.append(asn)

            if not new_asns:
                input(f"{BLUE}Нажмите Enter...{NC}")
                continue

            # Показываем имена организаций для новых ASN (задача #10)
            if len(new_asns) == 1:
                action = _as_ask_action(new_asns[0])
            else:
                print()
                info(f"Будет добавлено {len(new_asns)} AS: {', '.join(new_asns)}")
                action = _as_ask_action()
            if not action:
                info("Отмена")
                input(f"{BLUE}Нажмите Enter...{NC}")
                continue

            # Добавляем каждый ASN
            for asn in new_asns:
                print()
                info(f"Загрузка префиксов для {asn} из RIPE Stat API...")
                cidrs = _fetch_prefixes_for_asn(asn)
                if not cidrs:
                    warn(f"Не удалось получить префиксы для {asn} — пропуск")
                    continue
                success(f"Получено {len(cidrs)} префиксов для {asn}")
                _as_direct_save(asn, cidrs)
                ok = _as_direct_apply_to_xray(asn, cidrs, action)
                if ok:
                    _cur_entries.append({"asn": asn, "action": action})
                    _as_direct_list_save(_cur_entries)
                    _cur_map[asn] = {"asn": asn, "action": action}
                    _log_change("as_routing", f"{asn} добавлен → {action}")
                    success(f"{asn} добавлен → {_as_action_label(action)}")
            input(f"{BLUE}Нажмите Enter...{NC}")

        elif ch == "7":
            do_manage_as_direct()

        elif ch in ("q", ""):
            break
        else:
            warn("Неверный выбор")
            time.sleep(1)


def _geoip_block_get_rules() -> list:
    for cfg_path in (CONFIG_DIR / "config.json",
                     Path("/usr/local/etc/xray/config.json")):
        if not cfg_path.exists():
            continue
        try:
            cfg   = json.loads(cfg_path.read_text())
            rules = cfg.get("routing", {}).get("rules", [])
            return [r for r in rules if r.get("outboundTag") == "block"]
        except Exception:
            pass
    return []


def _geoip_apply_routing(extra_rules: list) -> None:
    """Применяет routing-правила к Xray конфигу. Добавляет blackhole outbound."""
    written: set = set()
    for cfg_path in (CONFIG_DIR / "config.json",
                     Path("/usr/local/etc/xray/config.json")):
        if not cfg_path.exists():
            continue
        try:
            real = str(cfg_path.resolve())
        except Exception:
            real = str(cfg_path)
        if real in written:
            continue
        written.add(real)
        try:
            cfg = json.loads(cfg_path.read_text())
            routing = cfg.setdefault("routing", {})
            rules   = [r for r in routing.setdefault("rules", [])
                       if r.get("outboundTag") != "block"]
            routing["rules"] = extra_rules + rules
            outbounds = cfg.setdefault("outbounds", [])
            if not any(ob.get("tag") == "block" for ob in outbounds):
                outbounds.append({
                    "protocol": "blackhole",
                    "tag": "block",
                    "settings": {"response": {"type": "none"}},
                })
            cfg_path.write_text(json.dumps(cfg, indent=2, ensure_ascii=False))
            _set_config_owner(cfg_path)
        except Exception as e:
            warn(f"Ошибка патча {cfg_path}: {e}")

    _run(["systemctl", "restart", "xray"], check=False, quiet=True)
    _nginx_restart_if_reality()
    time.sleep(1)
    r = _run(["systemctl", "is-active", "xray"], capture=True, check=False)
    if r.stdout.strip() == "active":
        success("Правила применены, Xray перезагружен")
    else:
        warn("Xray не запустился — откатываем GeoIP-правила")
        _geoip_remove_all()


def _geoip_set_allowlist(codes: list) -> None:
    """Принимаем только из указанных стран, остальное — block."""
    info(f"Настройка allowlist: {', '.join(codes)}")
    # Разрешить из allowlist → direct, всё остальное → block
    rules = [
        {"type": "field", "geoip": [c.lower() for c in codes], "outboundTag": "direct"},
        {"type": "field", "ip":    ["0.0.0.0/0", "::/0"],      "outboundTag": "block"},
    ]
    _geoip_apply_routing(rules)
    success(f"Allowlist: {', '.join(codes)}")
    warn("Убедитесь что ваш IP входит в разрешённые страны — иначе потеряете SSH!")


def _geoip_add_country_block(codes: list) -> None:
    info(f"Блокировка стран: {', '.join(codes)}")
    rule = {"type": "field", "geoip": [c.lower() for c in codes], "outboundTag": "block"}
    _geoip_apply_routing([rule])
    success(f"Заблокированы: {', '.join(codes)}")


def _geoip_add_scanner_block() -> None:
    """Блокирует известные диапазоны IP крупнейших интернет-сканеров."""
    scanner_ips = [
        # Shodan
        "198.20.69.74/31", "198.20.69.96/27", "198.20.99.130/31",
        "198.20.99.132/30", "104.131.0.69",
        # Censys
        "162.142.125.0/24", "167.248.133.0/24",
        # GreyNoise
        "45.83.66.0/24", "45.83.67.0/24",
        # Rapid7 / Sonar
        "71.6.135.131", "71.6.167.142", "71.6.199.23",
        # BinaryEdge
        "45.129.14.0/24", "45.129.15.0/24",
        # LeakIX
        "176.119.7.0/24",
        # Internet Archive scanners
        "207.241.224.0/20",
    ]
    info("Блокировка диапазонов интернет-сканеров...")
    rule = {"type": "field", "ip": scanner_ips, "outboundTag": "block"}
    _geoip_apply_routing([rule])
    success(f"Заблокированы {len(scanner_ips)} диапазонов сканеров")


# =============================================================================
#  МОДУЛЬ: РФ ПОДСЕТИ (RIPE NCC) → DIRECT  [защита от цензора]
# =============================================================================
RU_SUBNETS_FILE    = Path("/etc/xray/ru_subnets_ripe.txt")
RU_SUBNETS_TIMER   = Path("/etc/systemd/system/xray-ru-subnets.timer")
RU_SUBNETS_SERVICE = Path("/etc/systemd/system/xray-ru-subnets.service")
RIPE_DELEGATED_URL        = "https://ftp.ripe.net/ripe/stats/delegated-ripencc-latest"
RIPE_DELEGATED_URL_MIRROR = "https://ftp.ripe.net/pub/stats/ripencc/delegated-ripencc-latest"
_RU_SUBNET_RULE_COMMENT   = "ru_subnets_ripe"

# =============================================================================
#  ЛОКАЛЬНЫЙ SQLITE-КЭШ ПРЕФИКСОВ ASN
#
#  Кэш хранит:
#    • prefixes_asn  — префиксы конкретного ASN (RIPE Stat API)
#    • prefixes_ru   — делегированные подсети РФ (delegated-ripencc-latest)
#
#  Логика использования:
#    1. При успешной загрузке из RIPE → обновляем кэш.
#    2. При недоступности RIPE → берём данные из кэша (если есть).
#    3. Кэш считается «свежим» если возраст < ASN_CACHE_MAX_AGE_DAYS суток.
#       Устаревший кэш всё равно используется как запасной вариант, но
#       пользователь получает предупреждение с датой последнего обновления.
# =============================================================================
ASN_CACHE_DB      = Path("/var/lib/xray-installer/asn_prefix_cache.sqlite3")
ASN_CACHE_MAX_AGE_DAYS = 30   # предупреждать если кэш старше N дней


def _asn_cache_connect():
    """Открывает (и при необходимости инициализирует) БД кэша. Возвращает sqlite3.Connection."""
    import sqlite3
    ASN_CACHE_DB.parent.mkdir(parents=True, exist_ok=True)
    conn = sqlite3.connect(str(ASN_CACHE_DB), timeout=10)
    conn.execute("PRAGMA journal_mode=WAL")
    conn.execute("""
        CREATE TABLE IF NOT EXISTS prefix_cache (
            key        TEXT PRIMARY KEY,   -- 'asn:AS12345' или 'ru_delegated'
            updated_at INTEGER NOT NULL,   -- unix timestamp последнего обновления
            cidrs_json TEXT NOT NULL       -- JSON-массив строк CIDR
        )
    """)
    conn.commit()
    return conn


def _asn_cache_save(key: str, cidrs: list) -> None:
    """Сохраняет список CIDR в кэш под указанным ключом."""
    try:
        import sqlite3
        conn = _asn_cache_connect()
        conn.execute(
            "INSERT OR REPLACE INTO prefix_cache (key, updated_at, cidrs_json) VALUES (?, ?, ?)",
            (key, int(time.time()), json.dumps(cidrs, ensure_ascii=False))
        )
        conn.commit()
        conn.close()
    except Exception as e:
        warn(f"  [кэш ASN] Не удалось сохранить '{key}': {e}")


def _asn_cache_load(key: str) -> tuple:
    """
    Загружает список CIDR из кэша.
    Возвращает (cidrs: list, age_days: float) или ([], None) если записи нет.
    """
    try:
        import sqlite3
        if not ASN_CACHE_DB.exists():
            return [], None
        conn = _asn_cache_connect()
        row = conn.execute(
            "SELECT updated_at, cidrs_json FROM prefix_cache WHERE key = ?", (key,)
        ).fetchone()
        conn.close()
        if row is None:
            return [], None
        updated_at, cidrs_json = row
        age_days = (time.time() - updated_at) / 86400
        cidrs = json.loads(cidrs_json)
        return cidrs, age_days
    except Exception as e:
        warn(f"  [кэш ASN] Не удалось прочитать '{key}': {e}")
        return [], None


def _asn_cache_delete(key: str) -> None:
    """Удаляет запись из кэша (например, при явном сбросе)."""
    try:
        if not ASN_CACHE_DB.exists():
            return
        conn = _asn_cache_connect()
        conn.execute("DELETE FROM prefix_cache WHERE key = ?", (key,))
        conn.commit()
        conn.close()
    except Exception as e:
        warn(f"  [кэш ASN] Не удалось удалить '{key}': {e}")


def _asn_cache_info() -> list:
    """
    Возвращает список dict с информацией о записях кэша:
    [{"key": ..., "count": ..., "age_days": ..., "updated_str": ...}, ...]
    """
    result = []
    try:
        if not ASN_CACHE_DB.exists():
            return result
        import sqlite3, json as _json
        conn = _asn_cache_connect()
        rows = conn.execute(
            "SELECT key, updated_at, cidrs_json FROM prefix_cache ORDER BY key"
        ).fetchall()
        conn.close()
        for key, updated_at, cidrs_json in rows:
            try:
                count = len(_json.loads(cidrs_json))
            except Exception:
                count = 0
            age_days = (time.time() - updated_at) / 86400
            updated_str = datetime.fromtimestamp(updated_at).strftime("%Y-%m-%d %H:%M")
            result.append({
                "key":         key,
                "count":       count,
                "age_days":    age_days,
                "updated_str": updated_str,
            })
    except Exception as e:
        warn(f"  [кэш ASN] Ошибка при чтении списка записей: {e}")
    return result


def _fetch_ru_subnets_from_ripe() -> list:
    """
    Скачивает delegated-ripencc-latest и извлекает IPv4/IPv6 блоки РФ.

    При успехе — обновляет SQLite-кэш ('ru_delegated').
    При недоступности RIPE — возвращает данные из кэша (с предупреждением).
    """
    import urllib.request
    import math

    _CACHE_KEY = "ru_delegated"

    def _download(url):
        req = urllib.request.Request(url, headers={"User-Agent": "xray-installer/3.5"})
        with urllib.request.urlopen(req, timeout=60) as resp:
            return resp.read().decode("utf-8", errors="replace")

    raw = ""
    for url in (RIPE_DELEGATED_URL, RIPE_DELEGATED_URL_MIRROR):
        try:
            info(f"Загрузка из RIPE NCC: {url}")
            raw = _download(url)
            if raw:
                break
        except Exception as e:
            warn(f"Ошибка загрузки {url}: {e}")

    if not raw:
        # --- Попытка восстановить данные из SQLite-кэша ---
        cached_cidrs, age_days = _asn_cache_load(_CACHE_KEY)
        if cached_cidrs:
            age_str = f"{age_days:.1f}" if age_days is not None else "?"
            if age_days is not None and age_days > ASN_CACHE_MAX_AGE_DAYS:
                warn(
                    f"RIPE NCC недоступен. Используется УСТАРЕВШИЙ кэш "
                    f"(возраст: {age_str} дней, лимит: {ASN_CACHE_MAX_AGE_DAYS}). "
                    f"Данные могут быть неактуальны."
                )
            else:
                warn(
                    f"RIPE NCC недоступен. Используется локальный кэш "
                    f"(возраст: {age_str} дней, {len(cached_cidrs)} префиксов)."
                )
            return cached_cidrs
        warn("RIPE NCC недоступен и локальный кэш пуст — список РФ подсетей не получен.")
        return []

    cidrs = []
    for line in raw.splitlines():
        line = line.strip()
        if not line or line.startswith("#"):
            continue
        parts = line.split("|")
        if len(parts) < 6:
            continue
        _, cc, typ, start, value = parts[0], parts[1], parts[2], parts[3], parts[4]
        if cc.upper() != "RU":
            continue
        if typ == "ipv4":
            try:
                prefix = 32 - int(math.log2(int(value)))
                cidrs.append(f"{start}/{prefix}")
            except Exception:
                pass
        elif typ == "ipv6":
            try:
                cidrs.append(f"{start}/{int(value)}")
            except Exception:
                pass

    # --- Обновляем кэш при успешной загрузке ---
    if cidrs:
        _asn_cache_save(_CACHE_KEY, cidrs)
        info(f"  [кэш ASN] Обновлён кэш '{_CACHE_KEY}': {len(cidrs)} префиксов → {ASN_CACHE_DB}")

    return cidrs


def _ru_subnets_save(cidrs: list) -> None:
    RU_SUBNETS_FILE.parent.mkdir(parents=True, exist_ok=True)
    with RU_SUBNETS_FILE.open("w") as f:
        f.write(f"# РФ подсети из RIPE NCC delegated-ripencc-latest\n")
        f.write(f"# Обновлено: {datetime.now().strftime('%Y-%m-%d %H:%M:%S')}\n")
        f.write(f"# Всего блоков: {len(cidrs)}\n")
        for cidr in sorted(cidrs):
            f.write(cidr + "\n")
    info(f"Сохранено {len(cidrs)} подсетей → {RU_SUBNETS_FILE}")


def _ru_subnets_load_from_file() -> list:
    if not RU_SUBNETS_FILE.exists():
        return []
    return [l.strip() for l in RU_SUBNETS_FILE.read_text().splitlines()
            if l.strip() and not l.startswith("#")]


def _ru_subnets_restore_if_needed(silent: bool = False) -> bool:
    """
    Если файл с РФ-подсетями существует — молча восстанавливает правила в конфиге Xray.
    Вызывается после каждого пересоздания конфига (generate_xray_config*,
    _apply_split_tunnel_config_from_state, редактирование ноды и т.д.),
    чтобы правила ru_subnets_ripe не терялись.

    Возвращает True если правила были восстановлены, False если файла нет или он пуст.
    """
    cidrs = _ru_subnets_load_from_file()
    if not cidrs:
        return False
    # Применяем без перезапуска Xray — перезапуск сделает вызывающий код
    written: set = set()
    ok = False
    for cfg_path in (CONFIG_DIR / "config.json",
                     Path("/usr/local/etc/xray/config.json")):
        if not cfg_path.exists():
            continue
        try:
            real = str(cfg_path.resolve())
        except Exception:
            real = str(cfg_path)
        if real in written:
            continue
        written.add(real)
        try:
            cfg     = json.loads(cfg_path.read_text())
            routing = cfg.setdefault("routing", {})
            # Убираем старые RIPE-правила (если есть), вставляем новые в начало
            rules = [r for r in routing.setdefault("rules", [])
                     if r.get("comment") != _RU_SUBNET_RULE_COMMENT]
            new_rules = []
            for i in range(0, len(cidrs), 500):
                new_rules.append({
                    "type":        "field",
                    "ip":          cidrs[i:i + 500],
                    "outboundTag": "direct",
                    "comment":     _RU_SUBNET_RULE_COMMENT,
                })
            # BUGFIX: убеждаемся что catch-all существует перед вставкой RIPE-правил.
            # Актуально для конфигов, созданных до патча (нет правила tcp,udp→direct).
            _has_balancer = bool(routing.get("balancers"))
            _has_catchall = any(
                r.get("network") in ("tcp,udp", "tcp", "udp")
                and not r.get("ip") and not r.get("domain")
                and not r.get("protocol") and not r.get("port")
                for r in rules
            )
            if not _has_catchall and not _has_balancer:
                _service_tags = {"direct", "BLOCK", "block", "xray-stats-api"}
                _catchall_tag = "direct"
                outbounds = cfg.get("outbounds", [])
                for _ob in outbounds:
                    _t = _ob.get("tag", "")
                    if _t and _t not in _service_tags:
                        _catchall_tag = _t
                        break
                rules.append({
                    "type":        "field",
                    "network":     "tcp,udp",
                    "outboundTag": _catchall_tag,
                })
                if not silent:
                    info(f"catch-all правило добавлено в конфиг → {_catchall_tag}")
            routing["rules"] = new_rules + rules
            cfg_path.write_text(json.dumps(cfg, indent=2, ensure_ascii=False))
            _set_config_owner(cfg_path)
            ok = True
        except Exception as e:
            if not silent:
                warn(f"Ошибка восстановления RIPE-правил в {cfg_path}: {e}")
    if ok and not silent:
        info(f"РФ подсети RIPE восстановлены в конфиге ({len(cidrs)} CIDR, "
             f"{(len(cidrs) + 499) // 500} правил)")
    return ok


def _ru_subnets_apply_to_xray(cidrs: list) -> bool:
    if not cidrs:
        warn("Список подсетей пуст")
        return False
    written: set = set()
    ok = False
    for cfg_path in (CONFIG_DIR / "config.json",
                     Path("/usr/local/etc/xray/config.json")):
        if not cfg_path.exists():
            continue
        try:
            real = str(cfg_path.resolve())
        except Exception:
            real = str(cfg_path)
        if real in written:
            continue
        written.add(real)
        try:
            cfg      = json.loads(cfg_path.read_text())
            routing  = cfg.setdefault("routing", {})
            rules    = [r for r in routing.setdefault("rules", [])
                        if r.get("comment") != _RU_SUBNET_RULE_COMMENT]
            outbounds = cfg.setdefault("outbounds", [])
            if not any(ob.get("tag") == "direct" for ob in outbounds):
                outbounds.append({"protocol": "freedom", "tag": "direct"})
            new_rules = []
            for i in range(0, len(cidrs), 500):
                new_rules.append({
                    "type":        "field",
                    "ip":          cidrs[i:i + 500],
                    "outboundTag": "direct",
                    "comment":     _RU_SUBNET_RULE_COMMENT,
                })
            # BUGFIX: убеждаемся что catch-all существует перед вставкой RIPE-правил.
            # Без него весь не-РФ трафик не имеет маршрута → клиенты получают EOF.
            # Не добавляем если есть балансировщик (Режим B) — там catch-all через balancerTag.
            _has_balancer = bool(routing.get("balancers"))
            _has_catchall = any(
                r.get("network") in ("tcp,udp", "tcp", "udp")
                and not r.get("ip") and not r.get("domain")
                and not r.get("protocol") and not r.get("port")
                for r in rules
            )
            if not _has_catchall and not _has_balancer:
                _service_tags = {"direct", "BLOCK", "block", "xray-stats-api"}
                _catchall_tag = "direct"
                for _ob in outbounds:
                    _t = _ob.get("tag", "")
                    if _t and _t not in _service_tags:
                        _catchall_tag = _t
                        break
                rules.append({
                    "type":        "field",
                    "network":     "tcp,udp",
                    "outboundTag": _catchall_tag,
                })
                info(f"catch-all правило добавлено в конфиг → {_catchall_tag}")
            routing["rules"] = new_rules + rules
            cfg_path.write_text(json.dumps(cfg, indent=2, ensure_ascii=False))
            _set_config_owner(cfg_path)
            info(f"Конфиг: {cfg_path} ({len(new_rules)} правил, {len(cidrs)} CIDR)")
            ok = True
        except Exception as e:
            warn(f"Ошибка патча {cfg_path}: {e}")
    if not ok:
        warn("Конфиг Xray не найден")
        return False
    # BUGFIX: на уже установленных системах xray.service может содержать
    # ExecStartPre: rm -f PARAM_SOCKET_PATH — это удаляет unix-сокет которым
    # владеет nginx (nginx bind-ится на него), вызывая EOF у клиентов.
    # Патчим unit на лету перед restart чтобы исправить существующие установки.
    if PROTOCOL_MODE == "reality" and PARAM_SOCKET_PATH and not AWG_EXIT_ENABLED:
        try:
            svc_text = XRAY_SERVICE.read_text()
            if f"rm -f {PARAM_SOCKET_PATH}" in svc_text:
                patched_lines = [l for l in svc_text.splitlines()
                                 if not ("rm -f" in l and PARAM_SOCKET_PATH in l)]
                XRAY_SERVICE.write_text("\n".join(patched_lines) + "\n")
                _run(["systemctl", "daemon-reload"], check=False, quiet=True)
                info("xray.service: убран ExecStartPre rm -f socket (BUGFIX)")
        except Exception:
            pass  # не критично — _nginx_restart_if_reality восстановит сокет
    _run(["systemctl", "restart", "xray"], check=False, quiet=True)
    # Ждём xray активно (до 15 сек). sleep(2) недостаточно при большом конфиге
    # с тысячами RIPE/AS правил — xray может подниматься дольше.
    # Если xray не active в момент проверки — nginx не перезапустится
    # и останется с proxy_pass к старому сокету → постоянный EOF клиентов.
    # Ждём xray до 90 сек: конфиг с 13 000+ RIPE-правил поднимается 30–60 сек,
    # range(15) было недостаточно и приводило к тому что _nginx_restart_if_reality
    # не вызывалась вовсе. Теперь nginx перезапускается в любом случае.
    for _wi in range(90):
        r = _run(["systemctl", "is-active", "xray"], capture=True, check=False)
        if r.stdout.strip() == "active":
            break
        time.sleep(1)
    if r.stdout.strip() != "active":
        warn("Xray не запустился за 90 сек — проверьте: journalctl -u xray -n 30")
        _nginx_restart_if_reality()   # nginx перезапускаем в любом случае
        return False
    success(f"Xray перезапущен — {len(cidrs)} РФ подсетей → direct")
    _nginx_restart_if_reality()
    smoke_test_xray()
    return True


def _ru_subnets_remove_from_xray() -> None:
    written: set = set()
    for cfg_path in (CONFIG_DIR / "config.json",
                     Path("/usr/local/etc/xray/config.json")):
        if not cfg_path.exists():
            continue
        try:
            real = str(cfg_path.resolve())
        except Exception:
            real = str(cfg_path)
        if real in written:
            continue
        written.add(real)
        try:
            cfg = json.loads(cfg_path.read_text())
            routing = cfg.get("routing", {})
            routing["rules"] = [r for r in routing.get("rules", [])
                                 if r.get("comment") != _RU_SUBNET_RULE_COMMENT]
            cfg_path.write_text(json.dumps(cfg, indent=2, ensure_ascii=False))
            _set_config_owner(cfg_path)
        except Exception as e:
            warn(f"Ошибка {cfg_path}: {e}")
    _run(["systemctl", "restart", "xray"], check=False, quiet=True)
    _nginx_restart_if_reality()
    success("Правила РФ подсетей удалены из Xray")


def _ru_subnets_install_timer(hour: int = 4, minute: int = 0) -> None:
    script_path = Path(sys.argv[0]).resolve()
    RU_SUBNETS_SERVICE.write_text(f"""[Unit]
Description=Обновление РФ подсетей RIPE NCC → Xray direct
After=network-online.target
Wants=network-online.target

[Service]
Type=oneshot
ExecStart={sys.executable} {script_path} --update-ru-subnets
StandardOutput=journal
StandardError=journal
""")
    RU_SUBNETS_TIMER.write_text(f"""[Unit]
Description=Ежесуточное обновление РФ подсетей RIPE NCC

[Timer]
OnCalendar=*-*-* {hour:02d}:{minute:02d}:00
RandomizedDelaySec=600
Persistent=true

[Install]
WantedBy=timers.target
""")
    _run(["systemctl", "daemon-reload"], check=False, quiet=True)
    _run(["systemctl", "enable", "--now", "xray-ru-subnets.timer"], check=False, quiet=True)
    success(f"Timer установлен: обновление каждый день в {hour:02d}:{minute:02d}")


def _ru_subnets_remove_timer() -> None:
    _run(["systemctl", "disable", "--now", "xray-ru-subnets.timer"], check=False, quiet=True)
    for f in (RU_SUBNETS_TIMER, RU_SUBNETS_SERVICE):
        try:
            f.unlink(missing_ok=True)
        except Exception:
            pass
    _run(["systemctl", "daemon-reload"], check=False, quiet=True)
    success("Timer xray-ru-subnets удалён")


def _ru_subnets_timer_status() -> str:
    r = _run(["systemctl", "is-enabled", "xray-ru-subnets.timer"], capture=True, check=False)
    enabled = r.stdout.strip() in ("enabled", "static")
    r2 = _run(["systemctl", "is-active", "xray-ru-subnets.timer"], capture=True, check=False)
    active = r2.stdout.strip() == "active"
    if enabled and active:   return f"{GREEN}активен{NC}"
    elif enabled:            return f"{YELLOW}включён, не запущен{NC}"
    else:                    return f"{RED}отключён{NC}"


def do_manage_ru_subnet_direct() -> None:
    """Меню управления модулем «РФ подсети RIPE → direct»."""
    while True:
        os.system("clear")
        print()
        _box_top(f"РФ подсети RIPE NCC → direct (защита от цензора)")
        if RU_SUBNETS_FILE.exists():
            _lines = [l for l in RU_SUBNETS_FILE.read_text().splitlines()
                      if l and not l.startswith("#")]
            _mtime = datetime.fromtimestamp(RU_SUBNETS_FILE.stat().st_mtime)
            file_status = (f"{GREEN}{len(_lines)} подсетей{NC}  "
                           f"(обновлён {_mtime.strftime('%Y-%m-%d %H:%M')})")
        else:
            file_status = f"{YELLOW}файл не создан{NC}"
        _ru_active = _xray_count_ru_subnet_rules()
        xray_status = (f"{GREEN}{_ru_active} правил в Xray{NC}"
                       if _ru_active else f"{RED}не применены{NC}")
        timer_st = _ru_subnets_timer_status()
        _box_row(f"  Файл подсетей  : {file_status}")
        _box_row(f"  Правила в Xray : {xray_status}")
        _box_row(f"  Авто-обновление: {timer_st}")
        _box_item("1", f"Скачать/обновить подсети из RIPE NCC и применить в Xray")
        _box_item("2", f"Применить из сохранённого файла (без загрузки)")
        _box_item("3", f"Настроить время авто-обновления (systemd timer)")
        _box_item("4", f"Отключить авто-обновление (удалить timer)")
        _box_item("5", f"{RED}Удалить правила РФ подсетей из Xray{NC}")
        _box_item("6", f"Показать первые 20 подсетей из файла")
        _box_item("7", f"{CYAN}Просмотр всех routing-правил Xray{NC}")
        _box_item("Q", f"Назад")
        _box_bottom()
        ch = input(f"{CYAN}Выбор:{NC} ").strip().lower()

        if ch == "1":
            print()
            info("Начинаем загрузку из RIPE NCC (30-60 сек)...")
            cidrs = _fetch_ru_subnets_from_ripe()
            if not cidrs:
                warn("Не удалось получить подсети — проверьте интернет")
                input(f"{BLUE}Нажмите Enter...{NC}")
                continue
            success(f"Получено {len(cidrs)} подсетей РФ")
            _ru_subnets_save(cidrs)
            _ru_subnets_apply_to_xray(cidrs)
            input(f"{BLUE}Нажмите Enter...{NC}")

        elif ch == "2":
            cidrs = _ru_subnets_load_from_file()
            if not cidrs:
                warn(f"Файл не найден или пуст: {RU_SUBNETS_FILE}")
                input(f"{BLUE}Нажмите Enter...{NC}")
                continue
            _ru_subnets_apply_to_xray(cidrs)
            input(f"{BLUE}Нажмите Enter...{NC}")

        elif ch == "3":
            print()
            try:
                h_raw  = input("  Час запуска (0-23) [4]: ").strip()
                m_raw  = input("  Минута (0-59)  [0]: ").strip()
                hour   = int(h_raw) if h_raw else 4
                minute = int(m_raw) if m_raw else 0
                if not (0 <= hour <= 23 and 0 <= minute <= 59):
                    raise ValueError
            except ValueError:
                warn("Неверный формат — используем 04:00")
                hour, minute = 4, 0
            _ru_subnets_install_timer(hour, minute)
            warn("ВАЖНО: timer запускает: " + str(Path(sys.argv[0]).resolve()) + " --update-ru-subnets")
            input(f"{BLUE}Нажмите Enter...{NC}")

        elif ch == "4":
            ans = input(f"  {YELLOW}Отключить авто-обновление? [y/N]:{NC} ").strip().lower()
            if ans == "y":
                _ru_subnets_remove_timer()
            input(f"{BLUE}Нажмите Enter...{NC}")

        elif ch == "5":
            ans = input(f"  {YELLOW}Удалить правила РФ подсетей из Xray? [y/N]:{NC} ").strip().lower()
            if ans == "y":
                _ru_subnets_remove_from_xray()
            input(f"{BLUE}Нажмите Enter...{NC}")

        elif ch == "6":
            cidrs = _ru_subnets_load_from_file()
            print()
            if cidrs:
                for c in cidrs[:20]:
                    print(f"    {c}")
                if len(cidrs) > 20:
                    print(f"    {DIM}... и ещё {len(cidrs) - 20} подсетей{NC}")
            else:
                warn("Файл пуст или не существует")
            print()
            input(f"{BLUE}Нажмите Enter...{NC}")

        elif ch == "7":
            _show_xray_routing_rules()
            input(f"{BLUE}Нажмите Enter...{NC}")

        elif ch in ("q", ""):
            break
        else:
            warn("Неверный выбор")
            time.sleep(1)


def _ru_subnets_cli_update() -> None:
    """Вызывается systemd timer: --update-ru-subnets."""
    log_to_file("INFO", "=== Авто-обновление РФ подсетей RIPE NCC ===")
    cidrs = _fetch_ru_subnets_from_ripe()
    if not cidrs:
        log_to_file("ERROR", "Не удалось получить подсети из RIPE NCC")
        sys.exit(1)
    _ru_subnets_save(cidrs)
    ok = _ru_subnets_apply_to_xray(cidrs)
    log_to_file("INFO", f"Обновление: {len(cidrs)} подсетей, xray={'OK' if ok else 'FAIL'}")
    sys.exit(0 if ok else 1)


# =============================================================================
#  AS-ROUTING MODULE — маршрутизация трафика провайдера/хостера по ASN
#
#  Принцип:  пользователь вводит номер AS (например AS8359 или 8359).
#            Скрипт запрашивает все анонсируемые префиксы этого AS через
#            RIPE Stat API и вставляет их в Xray routing с выбранным действием:
#              direct — напрямую, минуя VPN
#              proxy  — через VPN (основной outbound)
#              block  — заблокировать (blackhole)
#
#  Файлы:    /etc/xray/as_direct_<ASN>.txt  — кеш префиксов для каждого AS
#            /etc/xray/as_direct_list.json  — список активных ASN
#            Формат: [{"asn": "AS8359", "action": "direct"}, ...]
#  Комментарий правила Xray: "as_direct_<ASN>"  (например "as_direct_AS8359")
#  systemd:  xray-as-direct.timer / .service (обновляет все активные AS)
#  CLI-флаг: --update-as-direct
# =============================================================================

AS_DIRECT_DIR       = Path("/etc/xray")
AS_DIRECT_LIST_FILE = Path("/etc/xray/as_direct_list.json")
AS_DIRECT_TIMER     = Path("/etc/systemd/system/xray-as-direct.timer")
AS_DIRECT_SERVICE   = Path("/etc/systemd/system/xray-as-direct.service")

RIPE_STAT_PREFIXES_URL = "https://stat.ripe.net/data/announced-prefixes/data.json?resource={asn}&starttime=last"


def _as_normalize(raw: str) -> str:
    """Приводит ввод к виду 'AS12345'. Принимает '12345', 'as12345', 'AS12345'."""
    raw = raw.strip().upper()
    if raw.startswith("AS"):
        return raw
    if raw.isdigit():
        return f"AS{raw}"
    return raw


def _resolve_asn_from_input(raw: str) -> tuple:
    """
    Определяет ASN по IP-адресу или доменному имени.
    Возвращает (asn, org_label) или ("", "") при ошибке.
    Пример: "8.8.8.8" → ("AS15169", "Google LLC")
             "google.com" → ("AS15169", "Google LLC")
    """
    import re as _re
    import socket as _socket

    target = raw.strip()
    # Если это домен — резолвим в IP
    if not _re.match(r'^\d{1,3}(\.\d{1,3}){3}$', target):
        try:
            target = _socket.gethostbyname(target)
        except Exception:
            return ("", "")
    # Запрашиваем ASN через ip-api.com
    try:
        import urllib.request as _ur
        url = f"http://ip-api.com/json/{target}?fields=as,org,isp,status"
        req = _ur.Request(url, headers={"User-Agent": "xray-installer/3.99"})
        with _ur.urlopen(req, timeout=5) as resp:
            data = json.loads(resp.read().decode())
        if data.get("status") == "success":
            as_raw = data.get("as", "")          # "AS12345 FullName"
            asn_num = as_raw.split()[0] if as_raw else ""
            org_label = data.get("isp") or data.get("org", "")
            return (asn_num, org_label)
    except Exception:
        pass
    return ("", "")


def _as_validate(asn: str) -> tuple:
    """
    Проверяет корректность ASN.
    Возвращает (True, "") при успехе или (False, "сообщение об ошибке").
    Правила:
      - формат AS<число>
      - номер в диапазоне 1..4294967295 (RFC 4893)
      - AS0 зарезервирован и не используется
      - AS23456 (AS_TRANS) — служебный, предупреждение
    """
    asn = asn.strip().upper()
    if not asn.startswith("AS"):
        return False, f"Неверный формат: {asn!r} — ожидается 'AS<число>' или просто число"
    num_str = asn[2:]
    if not num_str.isdigit():
        return False, f"Неверный формат: {asn!r} — после 'AS' должны идти только цифры"
    num = int(num_str)
    if num == 0:
        return False, "AS0 зарезервирован и не может использоваться"
    if num > 4294967295:
        return False, f"Номер AS {num} превышает максимально допустимый (4294967295)"
    if num == 23456:
        # AS_TRANS — технический AS для совместимости 2-байтных/4-байтных AS
        warn(f"  {asn} — это AS_TRANS (служебный). Возможно, вы имели в виду другой AS?")
    return True, ""


def _as_direct_file(asn: str) -> Path:
    """Путь к файлу кеша для данного ASN."""
    return AS_DIRECT_DIR / f"as_direct_{asn}.txt"


def _as_direct_comment(asn: str) -> str:
    return f"as_direct_{asn}"


def _as_direct_list_load() -> list:
    """
    Возвращает список активных ASN из as_direct_list.json.
    Поддерживает два формата:
      - старый: ["AS8359", ...]  -> конвертируется в новый с action="direct"
      - новый:  [{"asn": "AS8359", "action": "direct"}, ...]
    Всегда возвращает список dict с ключами "asn" и "action".
    """
    try:
        if AS_DIRECT_LIST_FILE.exists():
            data = json.loads(AS_DIRECT_LIST_FILE.read_text())
            if not isinstance(data, list):
                return []
            result = []
            for item in data:
                if isinstance(item, str):
                    result.append({"asn": item, "action": "direct"})
                elif isinstance(item, dict) and "asn" in item:
                    result.append({
                        "asn":    item["asn"],
                        "action": item.get("action", "direct"),
                    })
            return result
    except Exception:
        pass
    return []


def _as_direct_list_save(entries: list) -> None:
    """
    Сохраняет список в новом формате: [{"asn": "AS8359", "action": "direct"}, ...]
    entries -- список dict {"asn": ..., "action": ...}
    """
    AS_DIRECT_DIR.mkdir(parents=True, exist_ok=True)
    seen = {}
    for e in entries:
        seen[e["asn"]] = e
    ordered = sorted(seen.values(), key=lambda x: x["asn"])
    AS_DIRECT_LIST_FILE.write_text(json.dumps(ordered, indent=2, ensure_ascii=False))


def _as_direct_list_get_action(asn: str) -> str:
    """Возвращает действие для ASN или 'direct' если не найден."""
    for e in _as_direct_list_load():
        if e["asn"] == asn:
            return e["action"]
    return "direct"


def _fetch_prefixes_for_asn(asn: str) -> list:
    """
    Скачивает все IPv4/IPv6 префиксы для ASN через RIPE Stat API.
    Возвращает список строк CIDR: сначала IPv4, затем IPv6.

    Особенности:
    - Retry × 3 с экспоненциальной задержкой (1 с → 2 с → 4 с)
    - Два URL: с параметром starttime и без (резервный)
    - Валидация каждого префикса через ipaddress.ip_network()
    - Раздельный подсчёт и логирование IPv4/IPv6
    - Проверка на пустой ответ API
    - При недоступности RIPE Stat — возврат данных из SQLite-кэша
    """
    import urllib.request
    import ipaddress

    _CACHE_KEY = f"asn:{asn}"

    # Два варианта URL: с фильтром по времени и без (резервный)
    urls = [
        RIPE_STAT_PREFIXES_URL.format(asn=asn),
        f"https://stat.ripe.net/data/announced-prefixes/data.json?resource={asn}",
    ]

    raw = ""
    for url in urls:
        info(f"  Запрос к RIPE Stat API: {url}")
        for attempt in range(1, 4):   # до 3 попыток на каждый URL
            try:
                req = urllib.request.Request(url, headers={
                    "User-Agent": "xray-installer/4.11.4",
                    "Accept":     "application/json",
                })
                with urllib.request.urlopen(req, timeout=30) as resp:
                    raw = resp.read().decode("utf-8", errors="replace")
                if raw:
                    break
            except Exception as e:
                delay = 2 ** (attempt - 1)
                if attempt < 3:
                    warn(f"  Попытка {attempt}/3 не удалась ({asn}): {e} — повтор через {delay} с")
                    time.sleep(delay)
                else:
                    warn(f"  Попытка {attempt}/3 не удалась ({asn}): {e}")
        if raw:
            break

    if not raw:
        warn(f"  Не удалось получить данные для {asn} из всех источников")
        # --- Попытка восстановить данные из SQLite-кэша ---
        cached_cidrs, age_days = _asn_cache_load(_CACHE_KEY)
        if cached_cidrs:
            age_str = f"{age_days:.1f}" if age_days is not None else "?"
            if age_days is not None and age_days > ASN_CACHE_MAX_AGE_DAYS:
                warn(
                    f"  RIPE Stat недоступен. Используется УСТАРЕВШИЙ кэш для {asn} "
                    f"(возраст: {age_str} дней, лимит: {ASN_CACHE_MAX_AGE_DAYS}). "
                    f"Данные могут быть неактуальны."
                )
            else:
                warn(
                    f"  RIPE Stat недоступен. Используется локальный кэш для {asn} "
                    f"(возраст: {age_str} дней, {len(cached_cidrs)} префиксов)."
                )
            return cached_cidrs
        warn(f"  RIPE Stat недоступен и кэш для {asn} пуст — префиксы не получены.")
        return []

    # --- Разбор JSON ---
    try:
        data = json.loads(raw)
    except Exception as e:
        warn(f"  Ошибка разбора JSON ({asn}): {e}")
        return []

    # --- Проверка статуса API ---
    status = data.get("status", "")
    if status not in ("ok", "maintenance"):
        warn(f"  RIPE Stat вернул статус: {status!r} для {asn}")
        if not data.get("data"):
            return []

    # --- Извлечение префиксов ---
    api_data     = data.get("data") or {}
    prefixes_raw = api_data.get("prefixes") or []
    # Резервный ключ на случай нестандартного ответа API
    if not prefixes_raw:
        prefixes_raw = (api_data.get("announced_space") or {}).get("prefixes") or []

    if not prefixes_raw:
        warn(f"  {asn}: API вернул пустой список префиксов")
        return []

    # --- Валидация и разделение IPv4 / IPv6 ---
    cidrs_v4, cidrs_v6 = [], []
    skipped = 0
    for entry in prefixes_raw:
        prefix = (entry.get("prefix") or "").strip()
        if not prefix:
            continue
        try:
            net = ipaddress.ip_network(prefix, strict=False)
            if isinstance(net, ipaddress.IPv4Network):
                cidrs_v4.append(str(net))   # нормализуем (убираем хост-биты)
            else:
                cidrs_v6.append(str(net))
        except ValueError:
            skipped += 1

    total = len(cidrs_v4) + len(cidrs_v6)
    info(f"  {asn}: {total} префиксов "
         f"(IPv4: {len(cidrs_v4)}, IPv6: {len(cidrs_v6)}"
         + (f", пропущено некорректных: {skipped}" if skipped else "") + ")")

    if total == 0:
        warn(f"  {asn}: после валидации не осталось ни одного корректного префикса")

    # IPv4 первыми (более частый случай), потом IPv6
    result = cidrs_v4 + cidrs_v6

    # --- Обновляем кэш при успешной загрузке ---
    if result:
        _asn_cache_save(_CACHE_KEY, result)
        info(f"  [кэш ASN] Обновлён кэш '{_CACHE_KEY}': {total} префиксов → {ASN_CACHE_DB}")

    return result


def _as_direct_save(asn: str, cidrs: list) -> None:
    """Сохраняет список CIDR в файл кеша."""
    fpath = _as_direct_file(asn)
    fpath.parent.mkdir(parents=True, exist_ok=True)
    with fpath.open("w") as f:
        f.write(f"# Префиксы {asn} из RIPE Stat API\n")
        f.write(f"# Обновлено: {datetime.now().strftime('%Y-%m-%d %H:%M:%S')}\n")
        f.write(f"# Всего: {len(cidrs)}\n")
        for c in sorted(cidrs):
            f.write(c + "\n")
    info(f"  Сохранено {len(cidrs)} префиксов → {fpath}")


def _as_direct_load_from_file(asn: str) -> list:
    fpath = _as_direct_file(asn)
    if not fpath.exists():
        return []
    return [l.strip() for l in fpath.read_text().splitlines()
            if l.strip() and not l.startswith("#")]


def _as_get_proxy_outbound_tag(cfg: dict) -> str:
    """
    Определяет тег основного proxy-outbound из конфига Xray.
    Приоритет: chain-exit-1 > chain-exit > vless-out > первый non-direct/non-block outbound.
    """
    outbounds = cfg.get("outbounds", [])
    # Предпочтительные теги в порядке приоритета
    for preferred in ("chain-exit-1", "chain-exit", "vless-out"):
        for ob in outbounds:
            if ob.get("tag") == preferred:
                return preferred
    # Fallback: первый outbound который не является служебным
    service_tags = {"direct", "block", "BLOCK", "xray-stats-api", "freedom"}
    for ob in outbounds:
        tag = ob.get("tag", "")
        proto = ob.get("protocol", "")
        if tag and tag not in service_tags and proto != "freedom" and proto != "blackhole":
            return tag
    return "direct"


def _as_direct_apply_to_xray(asn: str, cidrs: list, action: str = "direct") -> bool:
    """
    Применяет правила маршрутизации для ASN в Xray routing.

    action:
      "direct" -- трафик идёт напрямую (freedom)
      "proxy"  -- трафик идёт через основной VPN-outbound
      "block"  -- трафик блокируется (blackhole)

    Особенности:
    - Перед вставкой удаляет ВСЕ старые правила с тем же comment (идемпотентность)
    - IPv4 и IPv6 разделяются в отдельные батчи правил
    - Батчи по 500 CIDR (ограничение Xray на размер массива "ip")
    - Новые правила вставляются после других as_direct_*/ru_subnets блоков
    """
    import ipaddress

    action = action.lower()
    if action not in ("direct", "proxy", "block"):
        warn(f"  Неизвестное действие '{action}' — используется 'direct'")
        action = "direct"

    if not cidrs:
        warn(f"  Список префиксов для {asn} пуст")
        return False

    cidrs_v4, cidrs_v6 = [], []
    for c in cidrs:
        try:
            net = ipaddress.ip_network(c, strict=False)
            if isinstance(net, ipaddress.IPv4Network):
                cidrs_v4.append(c)
            else:
                cidrs_v6.append(c)
        except ValueError:
            pass

    comment = _as_direct_comment(asn)
    written: set = set()
    ok = False
    for cfg_path in (CONFIG_DIR / "config.json",
                     Path("/usr/local/etc/xray/config.json")):
        if not cfg_path.exists():
            continue
        try:
            real = str(cfg_path.resolve())
        except Exception:
            real = str(cfg_path)
        if real in written:
            continue
        written.add(real)
        try:
            cfg      = json.loads(cfg_path.read_text())
            routing  = cfg.setdefault("routing", {})
            outbounds = cfg.setdefault("outbounds", [])

            # Шаг 1: удаляем старые правила этого ASN (идемпотентность)
            rules = [r for r in routing.setdefault("rules", [])
                     if r.get("comment") != comment]

            # Шаг 2: убеждаемся что нужный outbound существует
            if action == "direct":
                outbound_tag = "direct"
                if not any(ob.get("tag") == "direct" for ob in outbounds):
                    outbounds.append({"protocol": "freedom", "tag": "direct"})

            elif action == "proxy":
                outbound_tag = _as_get_proxy_outbound_tag(cfg)
                info(f"  Используем proxy outbound: {outbound_tag}")

            else:  # block
                outbound_tag = "block"
                if not any(ob.get("tag") == "block" for ob in outbounds):
                    outbounds.append({"protocol": "blackhole", "tag": "block"})

            # Шаг 3: формируем батчи по 500 CIDR, раздельно для IPv4 и IPv6
            new_rules = []
            for chunk_list in (cidrs_v4, cidrs_v6):
                for i in range(0, len(chunk_list), 500):
                    new_rules.append({
                        "type":        "field",
                        "ip":          chunk_list[i:i + 500],
                        "outboundTag": outbound_tag,
                        "comment":     comment,
                    })

            # Шаг 4: вставляем после блоков ru_subnets/as_direct, перед остальными
            _priority_comments = {_as_direct_comment(e["asn"]) for e in _as_direct_list_load()}
            _priority_comments.add(_RU_SUBNET_RULE_COMMENT)
            insert_pos = 0
            for idx, r in enumerate(rules):
                if r.get("comment", "") in _priority_comments:
                    insert_pos = idx + 1
            rules = rules[:insert_pos] + new_rules + rules[insert_pos:]
            routing["rules"] = rules

            cfg_path.write_text(json.dumps(cfg, indent=2, ensure_ascii=False))
            _set_config_owner(cfg_path)
            action_label = {"direct": "direct (напрямую)", "proxy": f"proxy ({outbound_tag})", "block": "block (заблокирован)"}[action]
            info(f"  Конфиг обновлён: {cfg_path} "
                 f"({len(new_rules)} правил: {len(cidrs_v4)} IPv4 + {len(cidrs_v6)} IPv6 -> {action_label})")
            ok = True
        except Exception as e:
            warn(f"  Ошибка патча {cfg_path}: {e}")

    if not ok:
        warn("  Конфиг Xray не найден")
        return False

    # ── Dry-run проверка конфига перед рестартом (патч: задача #9) ──────────
    _test_cfg = CONFIG_DIR / "config.json"
    if not _test_cfg.exists():
        _test_cfg = Path("/usr/local/etc/xray/config.json")
    if _test_cfg.exists():
        _dry = _run([str(XRAY_BIN), "run", "-test", "-config", str(_test_cfg)],
                    capture=True, check=False, quiet=True)
        if _dry.returncode != 0:
            warn("  Конфиг Xray не прошёл проверку — рестарт отменён")
            warn((_dry.stdout + _dry.stderr)[:300])
            return False

    _run(["systemctl", "restart", "xray"], check=False, quiet=True)
    # Ждём xray до 90 сек (тот же RIPE-конфиг, те же 30–60 сек на валидацию)
    for _wi in range(90):
        r = _run(["systemctl", "is-active", "xray"], capture=True, check=False)
        if r.stdout.strip() == "active":
            break
        time.sleep(1)
    if r.stdout.strip() == "active":
        action_label = {"direct": "direct", "proxy": "proxy (VPN)", "block": "BLOCK"}[action]
        success(f"Xray перезапущен -- {asn}: {len(cidrs_v4)} IPv4 + {len(cidrs_v6)} IPv6 -> {action_label}")
        _nginx_restart_if_reality()
        smoke_test_xray()
        return True
    else:
        warn("  Xray не запустился за 90 сек — проверьте: journalctl -u xray -n 30")
        _nginx_restart_if_reality()   # nginx перезапускаем в любом случае
        return False


def _as_direct_remove_from_xray(asn: str) -> None:
    """Удаляет правила для ASN из Xray routing."""
    comment = _as_direct_comment(asn)
    written: set = set()
    for cfg_path in (CONFIG_DIR / "config.json",
                     Path("/usr/local/etc/xray/config.json")):
        if not cfg_path.exists():
            continue
        try:
            real = str(cfg_path.resolve())
        except Exception:
            real = str(cfg_path)
        if real in written:
            continue
        written.add(real)
        try:
            cfg = json.loads(cfg_path.read_text())
            routing = cfg.get("routing", {})
            routing["rules"] = [r for r in routing.get("rules", [])
                                 if r.get("comment") != comment]
            cfg_path.write_text(json.dumps(cfg, indent=2, ensure_ascii=False))
            _set_config_owner(cfg_path)
        except Exception as e:
            warn(f"  Ошибка {cfg_path}: {e}")
    _run(["systemctl", "restart", "xray"], check=False, quiet=True)
    _nginx_restart_if_reality()
    success(f"Правила {asn} удалены из Xray")


def _as_direct_restore_if_needed(silent: bool = False) -> bool:
    """
    Восстанавливает правила для всех активных AS после пересоздания конфига Xray.
    Вызывается из rebuild_and_restart_xray() и migration.
    Аналог _ru_subnets_restore_if_needed для AS-модуля.
    Поддерживает все три режима: direct / proxy / block.
    """
    entries = _as_direct_list_load()
    if not entries:
        return False
    restored = 0
    for entry in entries:
        asn    = entry["asn"]
        action = entry.get("action", "direct")
        cidrs  = _as_direct_load_from_file(asn)
        if not cidrs:
            if not silent:
                warn(f"AS-routing: файл для {asn} не найден, пропуск")
            continue
        ok = _as_direct_apply_to_xray(asn, cidrs, action)
        if ok:
            restored += 1
        elif not silent:
            warn(f"AS-routing восстановление {asn} ({action}): не удалось применить")
    if restored and not silent:
        info(f"AS-routing правила восстановлены ({len(entries)} AS)")
    return restored > 0


def _as_suggest_server_asn() -> None:
    """
    Определяет ASN хостера по IP сервера и предлагает добавить его в direct.
    Задача #3: авто-определение ASN сервера при установке.
    Не вызывается повторно если этот ASN уже в списке или был пропущен.
    """
    # Флаг — не предлагать повторно в рамках сессии
    if getattr(_as_suggest_server_asn, "_done", False):
        return
    _as_suggest_server_asn._done = True  # type: ignore

    server_ip = get_server_ip("4")
    if not server_ip:
        return
    try:
        info(f"Определяю ASN хостера для {server_ip}...")
        asn, org = _resolve_asn_from_input(server_ip)
        if not asn:
            return
        # Уже добавлен?
        cur_map = {e["asn"]: e for e in _as_direct_list_load()}
        if asn in cur_map:
            return
        print()
        _box_top(f"Совет: трафик внутри хостера")
        _box_row(f"  IP сервера {server_ip} принадлежит:")
        _box_row(f"  {BOLD}{asn}{NC}  {DIM}{org}{NC}")
        _box_row(f"  Рекомендуется добавить этот AS в {GREEN}direct{NC},")
        _box_row(f"  чтобы трафик внутри сети хостера не шёл через VPN.")
        _box_bottom()
        ans = input(f"  Добавить {BOLD}{asn}{NC} в direct? [y/N]: ").strip().lower()
        if ans != "y":
            return
        info(f"Загрузка префиксов для {asn}...")
        cidrs = _fetch_prefixes_for_asn(asn)
        if not cidrs:
            warn(f"Не удалось получить префиксы для {asn}")
            return
        _as_direct_save(asn, cidrs)
        ok = _as_direct_apply_to_xray(asn, cidrs, "direct")
        if ok:
            entries = _as_direct_list_load()
            entries.append({"asn": asn, "action": "direct"})
            _as_direct_list_save(entries)
            _log_change("as_routing", f"{asn} добавлен → direct (авто: хостер сервера)")
            success(f"{asn} добавлен → direct")
    except Exception:
        pass


def _as_direct_count_rules(asn: str) -> int:
    """Считает количество правил для ASN в конфиге Xray."""
    comment = _as_direct_comment(asn)
    for cfg_path in (CONFIG_DIR / "config.json",
                     Path("/usr/local/etc/xray/config.json")):
        if not cfg_path.exists():
            continue
        try:
            cfg   = json.loads(cfg_path.read_text())
            rules = cfg.get("routing", {}).get("rules", [])
            return sum(1 for r in rules if r.get("comment") == comment)
        except Exception:
            pass
    return 0


def _as_direct_install_timer(hour: int = 5, minute: int = 0) -> None:
    script_path = Path(sys.argv[0]).resolve()
    AS_DIRECT_SERVICE.write_text(f"""[Unit]
Description=Обновление AS-префиксов (as_direct) → Xray direct
After=network-online.target
Wants=network-online.target

[Service]
Type=oneshot
ExecStart={sys.executable} {script_path} --update-as-direct
StandardOutput=journal
StandardError=journal
""")
    AS_DIRECT_TIMER.write_text(f"""[Unit]
Description=Ежесуточное обновление AS-префиксов для direct-маршрутизации

[Timer]
OnCalendar=*-*-* {hour:02d}:{minute:02d}:00
RandomizedDelaySec=600
Persistent=true

[Install]
WantedBy=timers.target
""")
    _run(["systemctl", "daemon-reload"], check=False, quiet=True)
    _run(["systemctl", "enable", "--now", "xray-as-direct.timer"], check=False, quiet=True)
    success(f"Timer установлен: обновление каждый день в {hour:02d}:{minute:02d}")


def _as_direct_remove_timer() -> None:
    _run(["systemctl", "disable", "--now", "xray-as-direct.timer"], check=False, quiet=True)
    for f in (AS_DIRECT_TIMER, AS_DIRECT_SERVICE):
        try:
            f.unlink(missing_ok=True)
        except Exception:
            pass
    _run(["systemctl", "daemon-reload"], check=False, quiet=True)
    success("Timer xray-as-direct удалён")


def _as_direct_timer_status() -> str:
    r = _run(["systemctl", "is-enabled", "xray-as-direct.timer"], capture=True, check=False)
    enabled = r.stdout.strip() in ("enabled", "static")
    r2 = _run(["systemctl", "is-active", "xray-as-direct.timer"], capture=True, check=False)
    active = r2.stdout.strip() == "active"
    if enabled and active:   return f"{GREEN}активен{NC}"
    elif enabled:            return f"{YELLOW}включён, не запущен{NC}"
    else:                    return f"{RED}отключён{NC}"


def _as_direct_cli_update() -> None:
    """Вызывается systemd timer: --update-as-direct. Обновляет все активные AS."""
    log_to_file("INFO", "=== Авто-обновление AS-routing префиксов ===")
    entries = _as_direct_list_load()
    if not entries:
        log_to_file("INFO", "AS-routing: список AS пуст — нечего обновлять")
        sys.exit(0)
    errors = 0
    for entry in entries:
        asn    = entry["asn"]
        action = entry.get("action", "direct")
        cidrs  = _fetch_prefixes_for_asn(asn)
        if not cidrs:
            log_to_file("ERROR", f"AS-routing: не удалось получить префиксы для {asn}")
            errors += 1
            continue
        _as_direct_save(asn, cidrs)
        ok = _as_direct_apply_to_xray(asn, cidrs, action)
        log_to_file("INFO", f"AS-routing {asn} ({action}): {len(cidrs)} префиксов, xray={'OK' if ok else 'FAIL'}")
        if not ok:
            errors += 1
    sys.exit(1 if errors else 0)


def _as_ask_action(asn: str = "") -> str:
    """
    Интерактивно спрашивает у пользователя, куда направлять трафик AS.
    Возвращает строку: "direct" | "proxy" | "block" | "" (отмена).
    """
    import re as _re
    _BW = 46  # внутренняя видимая ширина бокса

    def _row(raw_text: str) -> str:
        visible = _re.sub(r'\033\[[0-9;]*m', '', raw_text)
        pad = _BW - len(visible)
        return f"  {CYAN}║{NC}  {raw_text}{' ' * max(pad, 0)}  {CYAN}║{NC}"

    _title = f"Куда направлять трафик{(' ' + asn) if asn else ' этого AS'}?"
    _title_pad = _BW - len(_title)
    print()
    print(f"  {CYAN}╔{'═' * (_BW + 4)}╗{NC}")
    print(f"  {CYAN}║{NC}  {BOLD}{_title}{NC}{' ' * max(_title_pad, 0)}  {CYAN}║{NC}")
    print(f"  {CYAN}╠{'═' * (_BW + 4)}║{NC}")
    print(_row(f"{GREEN}[1] direct{NC}  — напрямую, минуя VPN"))
    print(_row(f"{YELLOW}[2] proxy{NC}   — через VPN-туннель    "))
    print(_row(f"{RED}[3] block{NC}   — заблокировать        "))
    print(_row(f"{DIM}[Q] Отмена{NC}                          "))
    print(f"  {CYAN}╚{'═' * (_BW + 4)}╝{NC}")
    print()
    ch = input(f"  {CYAN}Выбор [1/2/3/Q]:{NC} ").strip().lower()
    if ch == "1":   return "direct"
    if ch == "2":   return "proxy"
    if ch == "3":   return "block"
    return ""


def _as_action_label(action: str) -> str:
    """Возвращает цветную метку для действия."""
    return {
        "direct": f"{GREEN}direct{NC}",
        "proxy":  f"{YELLOW}proxy{NC}",
        "block":  f"{RED}block{NC}",
    }.get(action, f"{DIM}{action}{NC}")


def do_manage_as_direct() -> None:
    """Меню управления уже добавленными AS-маршрутами (изменить действие / удалить / обновить)."""
    while True:
        os.system("clear")
        print()
        entries = _as_direct_list_load()

        _box_top("Управление AS-маршрутами")
        _box_row(f"  {DIM}Здесь можно изменить действие, удалить или обновить{NC}")
        _box_row(f"  {DIM}префиксы для ранее добавленных AS.{NC}")
        _box_row(f"  {DIM}Для добавления нового AS — вернитесь в GeoIP → [6].{NC}")
        _box_sep()

        if entries:
            _box_row(f"  {CYAN}Активные AS ({len(entries)}):{NC}")
            for entry in entries:
                asn    = entry["asn"]
                action = entry.get("action", "direct")
                fpath  = _as_direct_file(asn)
                n_file = 0
                mtime  = ""
                if fpath.exists():
                    lines  = [l for l in fpath.read_text().splitlines()
                               if l.strip() and not l.startswith("#")]
                    n_file = len(lines)
                    mtime  = datetime.fromtimestamp(fpath.stat().st_mtime).strftime("%Y-%m-%d %H:%M")
                n_xray  = _as_direct_count_rules(asn)
                file_st = (f"{GREEN}{n_file} префиксов{NC} ({mtime})"
                           if n_file else f"{YELLOW}нет кеша{NC}")
                xray_st = (f"{GREEN}{n_xray} правил{NC}" if n_xray else f"{RED}не применён{NC}")
                act_st  = _as_action_label(action)
                _box_row(f"    {BOLD}{asn}{NC}  [{act_st}]  |  {file_st}  |  Xray: {xray_st}")
        else:
            _box_row(f"  {YELLOW}Нет активных AS{NC}")

        _box_sep()
        timer_st = _as_direct_timer_status()
        _box_row(f"  Авто-обновление: {timer_st}")
        _box_sep()

        _box_item("1", f"Изменить действие для AS (direct / proxy / block)")
        _box_item("2", f"Обновить префиксы всех AS (из кеша, без загрузки)")
        _box_item("3", f"Обновить префиксы всех AS (свежая загрузка из RIPE)")
        _box_item("4", f"Удалить AS (убрать из списка + из Xray routing)")
        _box_item("5", f"Настроить время авто-обновления (systemd timer)")
        _box_item("6", f"Отключить авто-обновление (удалить timer)")
        _box_item("7", f"Показать префиксы AS (первые 20)")
        _box_item("8", f"{CYAN}Просмотр всех routing-правил Xray{NC}")
        _box_item("9", f"Показать устаревшие AS (кеш старше 30 дней)")
        _box_item("C", f"🗄️  Состояние SQLite-кэша префиксов ASN")
        _box_item("Q", f"Назад")
        _box_bottom()

        ch = input(f"{CYAN}Выбор:{NC} ").strip().lower()

        # ── [1] Изменить действие ────────────────────────────────────────────
        if ch == "1":
            if not entries:
                warn("Нет активных AS")
                input(f"{BLUE}Нажмите Enter...{NC}")
                continue
            print()
            _box_row("  Активные AS:")
            for i, e in enumerate(entries, 1):
                _box_row(f"    {i}. {BOLD}{e['asn']}{NC}  [{_as_action_label(e['action'])}]")
            _box_bottom()
            raw = input(f"  Введите ASN для смены действия: ").strip()
            if not raw:
                continue
            asn = _as_normalize(raw)
            entry_match = next((e for e in entries if e["asn"] == asn), None)
            if not entry_match:
                warn(f"{asn} не найден в активном списке")
                input(f"{BLUE}Нажмите Enter...{NC}")
                continue
            info(f"Текущее действие для {asn}: {_as_action_label(entry_match['action'])}")
            action = _as_ask_action(asn)
            if not action:
                info("Отмена")
                input(f"{BLUE}Нажмите Enter...{NC}")
                continue
            if action == entry_match["action"]:
                info(f"Действие не изменилось ({action})")
                input(f"{BLUE}Нажмите Enter...{NC}")
                continue
            cidrs = _as_direct_load_from_file(asn)
            if not cidrs:
                info(f"Кеш для {asn} не найден — загружаем из RIPE...")
                cidrs = _fetch_prefixes_for_asn(asn)
                if not cidrs:
                    warn(f"Не удалось получить префиксы для {asn}")
                    input(f"{BLUE}Нажмите Enter...{NC}")
                    continue
                _as_direct_save(asn, cidrs)
            ok = _as_direct_apply_to_xray(asn, cidrs, action)
            if ok:
                old_action = entry_match["action"]
                entry_match["action"] = action
                _as_direct_list_save(entries)
                _log_change("as_routing", f"{asn}: {old_action} → {action}")
                success(f"{asn}: действие изменено на {_as_action_label(action)}")
            input(f"{BLUE}Нажмите Enter...{NC}")

        # ── [2] Обновить из кеша ─────────────────────────────────────────────
        elif ch == "2":
            if not entries:
                warn("Нет активных AS")
                input(f"{BLUE}Нажмите Enter...{NC}")
                continue
            for entry in entries:
                asn    = entry["asn"]
                action = entry.get("action", "direct")
                cidrs  = _as_direct_load_from_file(asn)
                if not cidrs:
                    warn(f"  Кеш для {asn} пуст — пропуск (используйте опцию 3)")
                    continue
                _as_direct_apply_to_xray(asn, cidrs, action)
            input(f"{BLUE}Нажмите Enter...{NC}")

        # ── [3] Обновить из RIPE ─────────────────────────────────────────────
        elif ch == "3":
            if not entries:
                warn("Нет активных AS")
                input(f"{BLUE}Нажмите Enter...{NC}")
                continue
            for entry in entries:
                asn    = entry["asn"]
                action = entry.get("action", "direct")
                info(f"Обновление {asn} ({_as_action_label(action)})...")
                cidrs = _fetch_prefixes_for_asn(asn)
                if not cidrs:
                    warn(f"  Не удалось получить префиксы для {asn}")
                    continue
                _as_direct_save(asn, cidrs)
                _as_direct_apply_to_xray(asn, cidrs, action)
            input(f"{BLUE}Нажмите Enter...{NC}")

        # ── [4] Удалить AS ───────────────────────────────────────────────────
        elif ch == "4":
            if not entries:
                warn("Нет активных AS")
                input(f"{BLUE}Нажмите Enter...{NC}")
                continue
            print()
            _box_row("  Активные AS:")
            for i, e in enumerate(entries, 1):
                _box_row(f"    {i}. {BOLD}{e['asn']}{NC}  [{_as_action_label(e['action'])}]")
            _box_bottom()
            raw = input(f"  Введите ASN для удаления: ").strip()
            if not raw:
                continue
            asn = _as_normalize(raw)
            _asn_ok, _asn_err = _as_validate(asn)
            if not _asn_ok:
                warn(f"Неверный ASN {raw!r}: {_asn_err}")
                input(f"{BLUE}Нажмите Enter...{NC}")
                continue
            if not any(e["asn"] == asn for e in entries):
                warn(f"{asn} не найден в активном списке")
                input(f"{BLUE}Нажмите Enter...{NC}")
                continue
            ans = input(f"  {YELLOW}Удалить {asn} из Xray и активного списка? [y/N]:{NC} ").strip().lower()
            if ans == "y":
                _as_direct_remove_from_xray(asn)
                entries = [e for e in entries if e["asn"] != asn]
                _as_direct_list_save(entries)
                _log_change("as_routing", f"{asn} удалён")
                try:
                    _as_direct_file(asn).unlink(missing_ok=True)
                except Exception:
                    pass
                success(f"{asn} удалён")
            input(f"{BLUE}Нажмите Enter...{NC}")

        # ── [5] Настроить timer ──────────────────────────────────────────────
        elif ch == "5":
            print()
            try:
                h_raw  = input("  Час запуска (0-23) [5]: ").strip()
                m_raw  = input("  Минута (0-59)  [0]: ").strip()
                hour   = int(h_raw) if h_raw else 5
                minute = int(m_raw) if m_raw else 0
                if not (0 <= hour <= 23 and 0 <= minute <= 59):
                    raise ValueError
            except ValueError:
                warn("Неверный формат — используем 05:00")
                hour, minute = 5, 0
            _as_direct_install_timer(hour, minute)
            warn("ВАЖНО: timer запускает: " + str(Path(sys.argv[0]).resolve()) + " --update-as-direct")
            input(f"{BLUE}Нажмите Enter...{NC}")

        # ── [6] Удалить timer ────────────────────────────────────────────────
        elif ch == "6":
            ans = input(f"  {YELLOW}Отключить авто-обновление AS-routing? [y/N]:{NC} ").strip().lower()
            if ans == "y":
                _as_direct_remove_timer()
            input(f"{BLUE}Нажмите Enter...{NC}")

        # ── [7] Показать префиксы ────────────────────────────────────────────
        elif ch == "7":
            if not entries:
                warn("Нет активных AS")
                input(f"{BLUE}Нажмите Enter...{NC}")
                continue
            print()
            default_asn = entries[0]["asn"]
            raw = input(f"  ASN для просмотра [{default_asn}]: ").strip()
            asn = _as_normalize(raw) if raw else default_asn
            cidrs = _as_direct_load_from_file(asn)
            print()
            if cidrs:
                action = _as_direct_list_get_action(asn)
                print(f"  {CYAN}{asn}{NC} [{_as_action_label(action)}]: {len(cidrs)} префиксов")
                for c in cidrs[:20]:
                    print(f"    {c}")
                if len(cidrs) > 20:
                    print(f"    {DIM}... и ещё {len(cidrs) - 20} префиксов{NC}")
            else:
                warn(f"Кеш для {asn} пуст или не существует")
            print()
            input(f"{BLUE}Нажмите Enter...{NC}")

        # ── [8] Просмотр routing-правил ──────────────────────────────────────
        elif ch == "8":
            _show_xray_routing_rules()
            input(f"{BLUE}Нажмите Enter...{NC}")

        # ── [9] Устаревшие AS (патч: задача #7) ──────────────────────────────
        elif ch == "9":
            if not entries:
                warn("Нет активных AS")
                input(f"{BLUE}Нажмите Enter...{NC}")
                continue
            _stale_days = 30
            _now = time.time()
            print()
            _box_top(f"Устаревшие AS (кеш старше {_stale_days} дней)")
            _found_stale = False
            for entry in entries:
                asn   = entry["asn"]
                fpath = _as_direct_file(asn)
                if not fpath.exists():
                    _box_row(f"  {RED}{asn}{NC}  — {RED}нет файла кеша{NC}")
                    _found_stale = True
                else:
                    age_days = (_now - fpath.stat().st_mtime) / 86400
                    if age_days >= _stale_days:
                        _box_row(f"  {YELLOW}{asn}{NC}  — кеш {YELLOW}{age_days:.0f} дн.{NC} назад")
                        _found_stale = True
            if not _found_stale:
                _box_row(f"  {GREEN}Все AS актуальны (кеш свежее {_stale_days} дней){NC}")
            _box_bottom()
            input(f"{BLUE}Нажмите Enter...{NC}")

        # ── [C] Состояние SQLite-кэша ────────────────────────────────────────
        elif ch == "c":
            print()
            _box_top("🗄️  SQLite-кэш префиксов ASN")
            records = _asn_cache_info()
            if not records:
                _box_row(f"  {YELLOW}Кэш пуст — данных нет{NC}")
                _box_row(f"  {DIM}Кэш заполняется автоматически при загрузке из RIPE.{NC}")
            else:
                # Размер файла БД
                try:
                    db_size_kb = ASN_CACHE_DB.stat().st_size // 1024
                    db_size_str = f"{db_size_kb} КБ"
                except Exception:
                    db_size_str = "?"
                _box_row(f"  БД: {CYAN}{ASN_CACHE_DB}{NC}  ({db_size_str})")
                _box_sep()
                _box_row(f"  {'Ключ':<22} {'Префиксов':>10}  {'Обновлён':<17}  {'Возраст':>10}")
                _box_row(f"  {'─'*22} {'─'*10}  {'─'*17}  {'─'*10}")
                for rec in records:
                    age = rec["age_days"]
                    age_str = f"{age:.1f} дн."
                    if age > ASN_CACHE_MAX_AGE_DAYS:
                        age_col = f"{YELLOW}{age_str}{NC}"
                        key_col = f"{YELLOW}{rec['key']:<22}{NC}"
                    else:
                        age_col = f"{GREEN}{age_str}{NC}"
                        key_col = f"{rec['key']:<22}"
                    _box_row(f"  {key_col} {rec['count']:>10}  {rec['updated_str']:<17}  {age_col}")
                _box_sep()
                _box_row(f"  {DIM}Жёлтым выделены записи старше {ASN_CACHE_MAX_AGE_DAYS} дней.{NC}")
                _box_row(f"  {DIM}Сброс отдельной записи: python3 {sys.argv[0]} --clear-asn-cache <ASN|all>{NC}")
            _box_bottom()
            input(f"{BLUE}Нажмите Enter...{NC}")

        elif ch in ("q", ""):
            break
        else:
            warn("Неверный выбор")
            time.sleep(1)


def _geoip_remove_all() -> None:
    written: set = set()
    for cfg_path in (CONFIG_DIR / "config.json",
                     Path("/usr/local/etc/xray/config.json")):
        if not cfg_path.exists():
            continue
        try:
            real = str(cfg_path.resolve())
        except Exception:
            real = str(cfg_path)
        if real in written:
            continue
        written.add(real)
        try:
            cfg = json.loads(cfg_path.read_text())
            routing = cfg.get("routing", {})
            routing["rules"] = [r for r in routing.get("rules", [])
                                 if r.get("outboundTag") != "block"]
            cfg["outbounds"] = [ob for ob in cfg.get("outbounds", [])
                                 if ob.get("tag") != "block"]
            cfg_path.write_text(json.dumps(cfg, indent=2, ensure_ascii=False))
            _set_config_owner(cfg_path)
        except Exception as e:
            warn(f"Ошибка {cfg_path}: {e}")
    _run(["systemctl", "restart", "xray"], check=False, quiet=True)
    _nginx_restart_if_reality()
    success("Все GeoIP-правила удалены")


