            for svc in svcs:
                rs = _run(["systemctl", "is-active", svc], capture=True, check=False)
                if rs.stdout.strip() == "active":
                    success(f"{svc}: ● активен")
                else:
                    warn(f"{svc}: ○ неактивен")
            r2 = _run(["systemctl", "is-active", "dnscrypt-proxy"],
                      capture=True, check=False)
